   * @param {string} message - The message
   * @param {{ cause?: unknown }} options? - The options?
   */
  constructor(message: string, options?: { cause?: unknown }) {
    super(message);
    if (options?.cause) {
      (this as unknown as Record<string, unknown>).cause = options.cause;
    }
    this.name = 'ScanError';
  }
