    }

    try {
      logger.info({ cacheFile: this.cacheFile }, 'Loading fallback secrets from cache');

      const cacheContent = await fs.readFile(this.cacheFile, 'utf-8');
      this.cachedSecrets = JSON.parse(cacheContent);
