  scheduleScan(scanType: string, repositories: RepositoryConfig[], groupName: string | null = null): Job {
    const jobId = this.createScanJobId(scanType);
    const jobData = {
      scanType,
      repositories,
      groupName,
      type: 'duplicate-detection'
    };

    return this.createJob(jobId, jobData);
