export interface ScanResultWithCache extends Record<string, unknown> {
  scan_type?: string;
  metrics?: {
    total_duplicate_groups?: number;
    total_suggestions?: number;
    [key: string]: unknown;
  };
  cache_metadata?: CacheMetadataAttachment;
