      if (!metadataStr) {
        return null;
      }

      const metadata = JSON.parse(metadataStr) as CacheMetadata;

      logger.debug({ cacheKey, repoPath }, 'Retrieved cache metadata');

      return metadata;
    } catch (error) {
      logError(logger, error, 'Failed to get cache metadata', { cacheKey, repoPath });
      return null;
    }
  }

    /**
   * Clear all.
   *
