   *
   * @returns {Promise<string[]>} The resulting string
   * @async
   */
  async listFiles(repoPath: string, filter: FileFilter = {}): Promise<string[]> {
    const files: string[] = [];

    const ignoredDirs = new Set(['node_modules', '.git', 'dist', 'build', '.next']);
    const langMap: Record<string, string> = {
      '.js': 'javascript',
      '.ts': 'typescript',
      '.jsx': 'javascript',
      '.tsx': 'typescript',
      '.py': 'python'
    };

        /**
     * Walk.
     *
     * @param {string} dir - The dir
     *
     * @returns {Promise<void>} The Promise<void>
     * @async
     */
    async function walk(dir: string): Promise<void> {
      const entries = await fs.readdir(dir, { withFileTypes: true });

      for (const entry of entries) {
        const fullPath = path.join(dir, entry.name);

        // Skip common ignored directories
        if (entry.isDirectory()) {
          if (ignoredDirs.has(entry.name)) {
            continue;
          }
          await walk(fullPath);
        } else {
          // Apply language filter if provided
          if (filter.languages) {
            const ext = path.extname(entry.name).toLowerCase();
            if (filter.languages.includes(langMap[ext])) {
              files.push(fullPath);
            }
          } else {
            files.push(fullPath);
          }
        }
      }
    }

    await walk(repoPath);
    return files;
  }

    /**
   * Detect languages.
   *
   * @param {string[]} files - The files
   *
   * @returns {string[]} The resulting string
   */
  detectLanguages(files: string[]): string[] {
    const langMap: Record<string, string> = {
      '.js': 'javascript',
      '.ts': 'typescript',
      '.jsx': 'javascript',
      '.tsx': 'typescript',
      '.py': 'python',
      '.go': 'go',
      '.rs': 'rust',
      '.java': 'java',
      '.rb': 'ruby',
      '.php': 'php'
    };

    const languages = new Set<string>();
    for (const file of files) {
      const ext = path.extname(file).toLowerCase();
      if (langMap[ext]) {
        languages.add(langMap[ext]);
      }
    }

    return Array.from(languages);
  }
