  async findLoadingWithoutFinally(repoPath: string): Promise<TimeoutFinding[]> {
    const pattern = 'setLoading(true)';
    const matches = await this.searchPattern(repoPath, pattern, {
      language: 'typescript',
      extensions: ['.ts', '.tsx', '.js', '.jsx']
