   * @async
   */
  async readFile(filePath: string): Promise<string> {
    try {
      return await fs.readFile(filePath, 'utf-8');
    } catch {
      return '';
    }
  }

    /**
   * Group by file.
   *
   * @param {PatternMatch[]} matches - The matches
   *
   * @returns {Record<string, PatternMatch[]>} The resulting string
