  let listenerSnapshot: Map<string, ((...args: unknown[]) => void)[]>;

  // Helper to create and track servers for cleanup
  /**
   * createTestServer.
   */
  const createTestServer = () => {
    const server = createServer();
    servers.push(server);
    return server;
