   * runJobHandler.
   */
  async runJobHandler(job) {
    // Simulate job execution
    if (job.data.shouldFail) {
      throw new Error('Simulated job failure');
    }
    return { success: true, data: job.data };
  }
}

describe('SidequestServer', () => {
  const servers = [];
  /**
   * createServer.
   */
  const createServer = (opts = {}) => {
