async function initGitRepo(repoPath) {
  await runGitCommand(repoPath, ['init']);
  await runGitCommand(repoPath, ['config', 'user.name', 'Test User']);
  await runGitCommand(repoPath, ['config', 'user.email', 'test@example.com']);

