    sentryDsn: config.sentryDsn,
  });

  setupWorkerEventListeners(worker);

  console.log('Creating job...\n');
  const job = worker.createRepomixJob(absolutePath, relativePath);

  await waitForJobCompletion(worker, job.id);
}

