  /**
   * Handle key press.
   *
   * @param {React.KeyboardEvent} e - The e
   */
  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      handleToggle();
    }
  };

  /**
   * Handle view click.
   *
   * @param {React.MouseEvent} e - The e
