  const handleViewClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (onView) {
      onView(pipeline.id);
    }
  };

  /**
   * Handle retry click.
   *
   * @param {React.MouseEvent} e - The e
   */
  const handleRetryClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (onRetry) {
      onRetry(pipeline.id);
