#!/usr/bin/env -S node --strip-types
/**
 * Permission Validator
 *
 * Ensures critical service files have correct permissions before PM2 startup.
 * Prevents 'fork/exec permission denied' errors from Doppler.
 *
 * Background:
 * - PM2 invokes files via: doppler run -- node <script>
 * - Files should NOT be executable (644 permissions)
 * - If files have execute bit (755), Doppler may try to exec directly
 * - This causes 'permission denied' errors
 *
 * Solution:
 * - Validate files are NOT executable
 * - Auto-fix if needed
 * - Log to Sentry for monitoring
 *
 * Usage:
 *   node --strip-types scripts/validate-permissions.ts
 *   node --strip-types scripts/validate-permissions.ts --fix
 *   node --strip-types scripts/validate-permissions.ts --check-only
 */

import fs from 'fs/promises';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const ROOT = path.resolve(__dirname, '..');

// Files that must NOT be executable (invoked with 'node', not './')
const CRITICAL_FILES = [
  'api/server.ts',
  'sidequest/pipeline-runners/duplicate-detection-pipeline.ts',
  'sidequest/pipeline-runners/claude-health-pipeline.ts',
  'sidequest/pipeline-runners/git-activity-pipeline.ts',
  'sidequest/pipeline-runners/plugin-management-pipeline.ts',
  'sidequest/pipeline-runners/gitignore-pipeline.ts',
  'sidequest/pipeline-runners/repo-cleanup-pipeline.ts',
  'sidequest/pipeline-runners/schema-enhancement-pipeline.ts',
  'sidequest/pipeline-runners/bugfix-audit-pipeline.ts',
  'sidequest/pipeline-runners/dashboard-populate-pipeline.ts'
];

// Parse CLI arguments
const args = process.argv.slice(2);
const FIX_MODE = args.includes('--fix');
const CHECK_ONLY = args.includes('--check-only');

/**
 * checkFilePermissions.
 */
async function checkFilePermissions(filePath) {
  const fullPath = path.join(ROOT, filePath);

  try {
    const stats = await fs.stat(fullPath);
    const mode = stats.mode;

    // Check if file has execute permission (user, group, or other)
    const isExecutable = (mode & 0o111) !== 0;

    // Expected: 0o100644 (regular file, rw-r--r--)
    // Problem:  0o100755 (regular file, rwxr-xr-x)

    return {
      path: filePath,
      fullPath,
      mode: mode.toString(8),
      isExecutable,
      isValid: !isExecutable
    };
  } catch (error) {
    return {
      path: filePath,
      fullPath,
      error: error.message,
      isValid: false
    };
  }
}

/**
 * fixFilePermissions.
 */
async function fixFilePermissions(filePath) {
  const fullPath = path.join(ROOT, filePath);

  try {
    // Set to 644 (rw-r--r--)
    await fs.chmod(fullPath, 0o644);
    return { success: true, path: filePath };
  } catch (error) {
    return { success: false, path: filePath, error: error.message };
  }
}

/**
 * reportInvalidFiles.
 */
function reportInvalidFiles(invalid: Awaited<ReturnType<typeof checkFilePermissions>>[]) {
  for (const result of invalid) {
    if (result.error) {
    } else if (result.isExecutable) {
    }
  }
}

/**
 * applyPermissionFixes.
 */
async function applyPermissionFixes(executable: Awaited<ReturnType<typeof checkFilePermissions>>[]) {

  const fixes = await Promise.all(executable.map(r => fixFilePermissions(r.path)));
  const successful = fixes.filter(f => f.success);
  const failed = fixes.filter(f => !f.success);

  if (successful.length > 0) {
    successful.forEach(f => console.log(`   - ${f.path}`));
  }

  if (failed.length > 0) {
    failed.forEach(f => console.log(`   - ${f.path}: ${f.error}`));
    process.exit(1);
  }

  process.exit(0);
}

/**
 * main.
 */
async function main() {

  const results = await Promise.all(CRITICAL_FILES.map(checkFilePermissions));
  const invalid = results.filter(r => !r.isValid);
  const executable = results.filter(r => r.isExecutable);

  if (invalid.length === 0) {
    process.exit(0);
  }

  reportInvalidFiles(invalid);

  if (CHECK_ONLY) {
    process.exit(1);
  }

  if (FIX_MODE || executable.length > 0) {
    await applyPermissionFixes(executable);
    return;
  }

  process.exit(1);
}

main().catch(error => {
  process.exit(1);
});

