#!/usr/bin/env -S node --strip-types

/**
 * Error Log Cleanup Script
 *
 * Automatically archives and removes old error log files from the logs directory.
 * Designed to run as a weekly cron job to prevent log file accumulation.
 *
 * Features:
 * - Archives error logs older than retention period
 * - Compresses archived logs
 * - Deletes archived files after extended retention
 * - Generates cleanup summary reports
 * - Dry-run mode for testing
 *
 * Usage:
 *   node --strip-types scripts/cleanup-error-logs.ts                    # Normal cleanup
 *   node --strip-types scripts/cleanup-error-logs.ts --dry-run          # Preview without changes
 *   node --strip-types scripts/cleanup-error-logs.ts --retention 14    # Custom retention days
 *   node --strip-types scripts/cleanup-error-logs.ts --help             # Show help
 *
 * Cron setup (weekly, Sunday 3 AM):
 *   0 3 * * 0 cd /path/to/jobs && node --strip-types scripts/cleanup-error-logs.ts
 */

import fs from 'fs/promises';
import path from 'path';
import { createGzip } from 'zlib';
import { pipeline } from 'stream/promises';
import { createReadStream, createWriteStream } from 'fs';
import { BYTES_PER_KB, TIMEOUTS } from '../sidequest/core/constants.ts';
import { createComponentLogger, logError } from '../sidequest/utils/logger.ts';

const logger = createComponentLogger('ErrorLogCleanup');

interface ErrorLogEntry {
  path: string;
  name: string;
  ageDays: number;
  sizeBytes: number;
  directory: string;
}

interface ArchivedLogEntry {
  path: string;
  name: string;
  ageDays: number;
  sizeBytes: number;
}

interface CleanupOptions {
  retentionDays: number;
  dryRun: boolean;
  verbose: boolean;
  help: boolean;
}

// Configuration
const DEFAULT_RETENTION_DAYS = 7;      // Keep error logs for 7 days
const ARCHIVE_RETENTION_DAYS = 30;     // Keep archives for 30 days
const LOGS_BASE_DIR = path.join(process.cwd(), 'logs');
const DECIMAL_RADIX = 10;

/**
 * Parse command line arguments
 */
function parseArgs(): CleanupOptions {
  const args = {
    dryRun: false,
    retentionDays: DEFAULT_RETENTION_DAYS,
    help: false,
    verbose: false
  };

  for (let i = 2; i < process.argv.length; i++) {
    const arg = process.argv[i];

    if (arg === '--dry-run' || arg === '-d') {
      args.dryRun = true;
    } else if (arg === '--retention' || arg === '-r') {
      args.retentionDays = parseInt(process.argv[++i], DECIMAL_RADIX);
    } else if (arg === '--verbose' || arg === '-v') {
      args.verbose = true;
    } else if (arg === '--help' || arg === '-h') {
      args.help = true;
    }
  }

  return args;
}

/**
 * Show help message
 */
function showHelp() {
  console.log(`
Error Log Cleanup Script

Automatically archives and removes old error log files.

Usage:
  node --strip-types scripts/cleanup-error-logs.ts [options]

Options:
  --dry-run, -d         Preview changes without modifying files
  --retention N, -r N   Set retention period in days (default: ${DEFAULT_RETENTION_DAYS})
  --verbose, -v         Show detailed output
  --help, -h            Show this help message

Examples:
  node --strip-types scripts/cleanup-error-logs.ts
  node --strip-types scripts/cleanup-error-logs.ts --dry-run
  node --strip-types scripts/cleanup-error-logs.ts --retention 14
  node --strip-types scripts/cleanup-error-logs.ts -d -v

Cron Setup (weekly, Sunday 3 AM):
  0 3 * * 0 cd /path/to/jobs && node --strip-types scripts/cleanup-error-logs.ts
`);
}

/**
 * Get file age in days
 */
async function getFileAgeDays(filePath: string): Promise<number> {
  const stats = await fs.stat(filePath);
  const ageMs = Date.now() - stats.mtimeMs;
  return ageMs / TIMEOUTS.ONE_DAY_MS;
}

/**
 * Compress a file using gzip
 */
async function compressFile(inputPath: string, outputPath: string): Promise<void> {
  const gzip = createGzip();
  const source = createReadStream(inputPath);
  const destination = createWriteStream(outputPath);

  await pipeline(source, gzip, destination);
}

/**
 * Scan directory for error log files
 */
async function scanErrorLogs(baseDir: string): Promise<ErrorLogEntry[]> {
  const errorLogs: ErrorLogEntry[] = [];

  /**
   * scanDir.
   */
  async function scanDir(dir: string): Promise<void> {
    const entries = await fs.readdir(dir, { withFileTypes: true });

    for (const entry of entries) {
      const fullPath = path.join(dir, entry.name);

      if (entry.isDirectory()) {
        await scanDir(fullPath);
      } else if (entry.name.endsWith('.error.json')) {
        const age = await getFileAgeDays(fullPath);
        const size = (await fs.stat(fullPath)).size;

        errorLogs.push({
          path: fullPath,
          name: entry.name,
          ageDays: age,
          sizeBytes: size,
          directory: path.relative(baseDir, dir)
        });
      }
    }
  }

  await scanDir(baseDir);
  return errorLogs;
}

/**
 * Scan for archived logs
 */
async function scanArchivedLogs(archiveDir: string): Promise<ArchivedLogEntry[]> {
  try {
    await fs.access(archiveDir);
  } catch {
    return [];
  }

  const archivedLogs: ArchivedLogEntry[] = [];
  const entries = await fs.readdir(archiveDir, { withFileTypes: true });

  for (const entry of entries) {
    if (entry.name.endsWith('.gz')) {
      const fullPath = path.join(archiveDir, entry.name);
      const age = await getFileAgeDays(fullPath);
      const size = (await fs.stat(fullPath)).size;

      archivedLogs.push({
        path: fullPath,
        name: entry.name,
        ageDays: age,
        sizeBytes: size
      });
    }
  }

  return archivedLogs;
}

/**
 * Format bytes to human-readable size
 */
function formatBytes(bytes: number): string {
  if (bytes === 0) return '0 B';
  const k = BYTES_PER_KB;
  const sizes = ['B', 'KB', 'MB', 'GB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
}

/**
 * Archive old error logs
 */
async function archiveOldLogs(errorLogs: ErrorLogEntry[], retentionDays: number, dryRun: boolean, verbose: boolean): Promise<{ archived: number; totalSize: number }> {
  const archiveDir = path.join(LOGS_BASE_DIR, 'archive');
  const toArchive = errorLogs.filter(log => log.ageDays > retentionDays);

  if (toArchive.length === 0) {
    return { archived: 0, totalSize: 0 };
  }

  if (!dryRun) {
    await fs.mkdir(archiveDir, { recursive: true });
  }

  let archivedCount = 0;
  let totalSize = 0;

  for (const log of toArchive) {
    const timestamp = new Date().toISOString().replace(/:/g, '-').split('.')[0];
    const archiveName = `${path.basename(log.name, '.json')}-${timestamp}.json.gz`;
    const archivePath = path.join(archiveDir, archiveName);

    if (dryRun) {
      if (verbose) {
      }
    } else {
      try {
        await compressFile(log.path, archivePath);
        await fs.unlink(log.path);

        if (verbose) {
        }

        archivedCount++;
        totalSize += log.sizeBytes;
      } catch (error) {
        logError(logger, error, 'Failed to archive error log', { file: log.name });
      }
    }
  }

  const action = dryRun ? '[DRY RUN] Would archive' : 'Archived';

  return { archived: archivedCount, totalSize };
}

/**
 * Delete very old archives
 */
async function deleteOldArchives(archivedLogs: ArchivedLogEntry[], retentionDays: number, dryRun: boolean, verbose: boolean): Promise<{ deleted: number; totalSize: number }> {
  const toDelete = archivedLogs.filter(log => log.ageDays > retentionDays);

  if (toDelete.length === 0) {
    return { deleted: 0, totalSize: 0 };
  }

  let deletedCount = 0;
  let totalSize = 0;

  for (const log of toDelete) {
    if (dryRun) {
      if (verbose) {
      }
    } else {
      try {
        await fs.unlink(log.path);

        if (verbose) {
        }

        deletedCount++;
        totalSize += log.sizeBytes;
      } catch (error) {
        logError(logger, error, 'Failed to delete archived log', { file: log.name });
      }
    }
  }

  const action = dryRun ? '[DRY RUN] Would delete' : 'Deleted';

  return { deleted: deletedCount, totalSize };
}

/**
 * printCleanupSummary.
 */
function printCleanupSummary(archiveResult: { archived: number; totalSize: number }, deleteResult: { deleted: number; totalSize: number }, dryRun: boolean) {
  if (dryRun) console.log('\n⚠️  This was a dry run - no files were modified');
}

/**
 * Main cleanup function
 */
async function cleanup(options: CleanupOptions): Promise<void> {

  const errorLogs = await scanErrorLogs(LOGS_BASE_DIR);

  if (options.verbose && errorLogs.length > 0) {
    const recent = errorLogs.filter(log => log.ageDays <= options.retentionDays).length;
  }

  const archiveResult = await archiveOldLogs(errorLogs, options.retentionDays, options.dryRun, options.verbose);

  const archiveDir = path.join(LOGS_BASE_DIR, 'archive');
  const archivedLogs = await scanArchivedLogs(archiveDir);

  if (archivedLogs.length > 0) {
    const deleteResult = await deleteOldArchives(archivedLogs, ARCHIVE_RETENTION_DAYS, options.dryRun, options.verbose);
    printCleanupSummary(archiveResult, deleteResult, options.dryRun);
  } else {
  }

}

/**
 * Main entry point
 */
async function main() {
  const options = parseArgs();

  if (options.help) {
    showHelp();
    process.exit(0);
  }

  try {
    await cleanup(options);
    process.exit(0);
  } catch (error) {
    logError(logger, error, 'Cleanup failed');
    process.exit(1);
  }
}

// Run if executed directly
if (import.meta.url === `file://${process.argv[1]}`) {
  main();
}

