/**
 * Emergency shutdown handler for startup failures
 * Cleans up partially initialized resources to prevent resource leaks
 * @private
 */
async function emergencyShutdown() {
  logStart(logger, 'emergency shutdown');

  try {
    // Stop Doppler health monitoring if started
    dopplerMonitor.stopMonitoring();
  } catch (err) {
    logger.error({ error: (err as Error).message }, 'Failed to stop Doppler monitor during emergency shutdown');
  }

  try {
    // Shutdown all workers if registry initialized
    await workerRegistry.shutdown();
  } catch (err) {
    logger.error({ error: (err as Error).message }, 'Failed to shutdown worker registry during emergency shutdown');
  }

  try {
    // Close WebSocket server if created
    if (wss?.clients) {
      await new Promise<void>((resolve) => {
        wss.close(() => {
          logger.info('WebSocket server closed during emergency shutdown');
          resolve();
        });
      });
    }
  } catch (err) {
    logger.error({ error: (err as Error).message }, 'Failed to close WebSocket server during emergency shutdown');
  }

  try {
    // Close job repository if initialized
    jobRepository.close();
  } catch (err) {
    logger.error({ error: (err as Error).message }, 'Failed to close job repository during emergency shutdown');
  }

  logger.info('Emergency shutdown complete');
}

// Start server with port fallback
const PREFERRED_PORT = config.apiPort; // Now using JOBS_API_PORT from Doppler (default: 8080)

(async () => {
  try {
    // Initialize job repository (sql.js requires async init)
    await jobRepository.initialize();
    logger.info('Job repository initialized');

    // Cancel stale queued jobs for all disabled pipelines so the dashboard
    // doesn't show permanently-stuck entries from previous sessions.
    // Root cause: the in-memory SidequestServer queue is not re-hydrated from DB
    // on restart, so queued jobs from a prior session never transition to running.
    for (const pipelineId of workerRegistry.getDisabledPipelines()) {
      const cancelled = jobRepository.cancelPipelineJobs(pipelineId);
      if (cancelled > 0) {
        logger.info({ pipelineId, count: cancelled }, 'Cancelled stale queued jobs for disabled pipeline');
      }
    }

    // Setup server with automatic port fallback
    const actualPort = await setupServerWithPortFallback(httpServer, {
      preferredPort: PREFERRED_PORT,
      maxPort: PREFERRED_PORT + PORT.FALLBACK_RANGE,
      host: '0.0.0.0',
      killExisting: false // Set to true in development if needed
    });

    logger.info({ port: actualPort }, 'API server started');
    logger.info({ port: actualPort }, 'AlephAuto API Server & Dashboard running');
    if (actualPort !== PREFERRED_PORT) {
      logger.warn({
        actualPort,
        preferredPort: PREFERRED_PORT
      }, 'Using fallback API port because preferred port was in use');
    }
    logger.info({
      dashboardUrl: `http://localhost:${actualPort}/`,
      healthUrl: `http://localhost:${actualPort}/health`,
      dopplerHealthUrl: `http://localhost:${actualPort}/api/health/doppler`,
      websocketUrl: `ws://localhost:${actualPort}/ws`,
      apiBaseUrl: `http://localhost:${actualPort}/api/`
    }, 'Service endpoints');

    // Start Doppler health monitoring (check every 15 minutes)
    await dopplerMonitor.startMonitoring(TIMEOUTS.DOPPLER_MONITOR_INTERVAL_MIN);

    // Setup graceful shutdown handlers
    setupGracefulShutdown(httpServer, {
      timeout: PORT.DEFAULT_SHUTDOWN_TIMEOUT_MS,
      onShutdown: async (signal) => {
        logger.info({ signal }, 'Running custom shutdown handlers');

        // Stop Doppler health monitoring
        dopplerMonitor.stopMonitoring();

        // Shutdown all workers
        await workerRegistry.shutdown();

        // Close WebSocket server
        await new Promise<void>((resolve) => {
          wss.close(() => {
            logger.info('WebSocket server closed');
            resolve();
          });
        });

        // Close job repository
        jobRepository.close();
      }
    });
  } catch (error) {
    logger.error({ error: (error as Error).message, stack: (error as Error).stack }, 'Failed to start server');
    Sentry.captureException(error, {
      tags: { component: 'APIServer', phase: 'startup' }
    });

    // Emergency shutdown: cleanup partially initialized resources
    await emergencyShutdown();

    process.exit(1);
  }
})();

