/**
 * Constructor options for SidequestServer
 */
export interface SidequestServerOptions {
  maxConcurrent?: number;
  maxRetries?: number;
  retryDelayMs?: number;
  logDir?: string;
  autoStart?: boolean;
  gitWorkflowEnabled?: boolean;
  gitBranchPrefix?: string;
  gitBaseBranch?: string;
  gitDryRun?: boolean;
  jobType?: string;
  jobRetentionDays?: number;
  sentryDsn?: string;
}

interface JobActionResult {
  success: boolean;
  message: string;
  job?: Job;
}

/**
 * Base job-queue server with retry, persistence, and optional git workflow support.
 */
export class SidequestServer extends EventEmitter {
  jobs: Map<string, Job>;
  jobHistory: Job[];
  maxConcurrent: number;
  activeJobs: number;
  queue: string[];
  logDir: string;
  isRunning: boolean;
  maxRetries: number;
  retryDelayMs: number;
  gitWorkflowEnabled: boolean;
  gitBranchPrefix: string;
  gitBaseBranch: string;
  gitDryRun: boolean;
  jobType: string;
  jobRetentionDays: number;
  branchManager: BranchManager | undefined;
  private _dbReady: Promise<void>;
  private _queueDraining = false;

  /**
   * Creates a Sidequest worker instance.
   *
   * @param options Runtime configuration for queueing, retries, logging, and git integration.
   */
  constructor(options: SidequestServerOptions = {}) {
    super();
    this.jobs = new Map();
    this.jobHistory = [];
    this.maxConcurrent = options.maxConcurrent ?? CONCURRENCY.DEFAULT_MAX_JOBS;
    this.activeJobs = 0;
    this.queue = [];
    this.logDir = options.logDir || './logs';

    // Auto-start control: if false, jobs won't process until start() is called
    this.isRunning = options.autoStart !== false;

    // Retry configuration
    this.maxRetries = options.maxRetries ?? RETRY.MAX_ABSOLUTE_ATTEMPTS;
    this.retryDelayMs = options.retryDelayMs ?? RETRY.DEFAULT_DELAY_MS;

    // Git workflow options
    this.gitWorkflowEnabled = options.gitWorkflowEnabled ?? false;
    this.gitBranchPrefix = options.gitBranchPrefix || 'automated';
    this.gitBaseBranch = options.gitBaseBranch || 'main';
    this.gitDryRun = options.gitDryRun ?? false;
    this.jobType = options.jobType || 'job';
    const retentionByType = config.jobRetentionDaysByType as Record<string, number>;
    const retentionFromConfig = retentionByType[this.jobType] ?? config.defaultJobRetentionDays;
    const requestedRetention = options.jobRetentionDays ?? retentionFromConfig;
    const defaultRetentionDays = config.defaultJobRetentionDays as number;
    this.jobRetentionDays = Number.isFinite(requestedRetention) && requestedRetention > 0
      ? Math.floor(requestedRetention)
      : defaultRetentionDays;

    // Initialize BranchManager if git workflow is enabled
    if (this.gitWorkflowEnabled) {
      this.branchManager = new BranchManager({
        baseBranch: this.gitBaseBranch,
        branchPrefix: this.gitBranchPrefix,
        dryRun: this.gitDryRun
      });
    }

    // Initialize SQLite database for job persistence.
    // Graceful degradation: .catch() converts DB init failure to a resolved promise
    // so start() always succeeds. Jobs still run in-memory but won't persist to disk.
    this._dbReady = jobRepository.initialize()
      .then(() => {
        logger.info('Job history database initialized');
      })
      .catch((err) => {
        logError(logger, err, 'Failed to initialize database - jobs will not persist');
        Sentry.captureException(err, {
          tags: { component: 'database', event: 'init_failed' }
        });
      });

    // Initialize Sentry once per process
    if (!sentryInitialized) {
      Sentry.init({
        dsn: options.sentryDsn ?? config.sentryDsn,
        environment: config.nodeEnv,
        tracesSampleRate: config.sentryTracesSampleRate
      });
      sentryInitialized = true;
    }
  }

  /**
   * Enqueues and returns a new job.
   *
   * @param jobId Job identifier.
   * @param jobData Arbitrary job payload.
   * @returns Created in-memory job object.
   */
  createJob(jobId: string, jobData: Record<string, unknown>): Job {
    if (!VALIDATION.JOB_ID_PATTERN.test(jobId)) {
      throw new Error(`Invalid job ID: must match ${VALIDATION.JOB_ID_PATTERN}`);
    }
    const resolvedJobId = this._resolveUniqueJobId(jobId);
    const job: Job = {
      id: resolvedJobId,
      status: JOB_STATUS.QUEUED,
      data: jobData,
      createdAt: new Date(),
      startedAt: null,
      completedAt: null,
      error: null,
      result: null,
      retryCount: 0,
      git: {
        branchName: null,
        originalBranch: null,
        commitSha: null,
        prUrl: null,
        changedFiles: []
      }
    };

    this.jobs.set(resolvedJobId, job);
    this.queue.push(resolvedJobId);

    // Persist to SQLite immediately so job is visible in dashboard
    this._trySilentPersist(job, PERSIST_CONTEXT.CREATE);

    Sentry.addBreadcrumb({
      category: 'job',
      message: `Job ${resolvedJobId} created`,
      level: 'info',
      data: { jobId: resolvedJobId, jobData }
    });

    this.emit(JOB_EVENTS.CREATED, job);
    this.processQueue();

    return job;
  }

  private _resolveUniqueJobId(requestedJobId: string): string {
    if (!this.jobs.has(requestedJobId)) {
      return requestedJobId;
    }

    let suffix = 1;
    let candidateId = `${requestedJobId}-${suffix}`;
    while (this.jobs.has(candidateId)) {
      suffix += 1;
      candidateId = `${requestedJobId}-${suffix}`;
    }

    logger.warn({
      requestedJobId,
      resolvedJobId: candidateId
    }, 'Duplicate job ID detected; assigned unique ID');

    return candidateId;
  }

  /**
   * Drains queued jobs up to configured concurrency.
   */
  async processQueue(): Promise<void> {
    if (!this.isRunning || this._queueDraining) {
      return;
    }

    this._queueDraining = true;
    try {
      while (this.queue.length > 0 && this.activeJobs < this.maxConcurrent) {
        const jobId = this.queue.shift();
        if (!jobId) continue;
        const job = this.jobs.get(jobId);

        if (!job) continue;

        this.activeJobs++;
        this.executeJob(jobId).catch(error => {
          logError(logger, error, 'Error executing job', { jobId });
        });
      }
    } finally {
      this._queueDraining = false;
    }
  }

  /**
   * Executes a job lifecycle with tracing, retry handling, and persistence.
   *
   * @param jobId Job identifier.
   */
  async executeJob(jobId: string): Promise<void> {
    const job = this.jobs.get(jobId);
    if (!job) {
      return;
    }

    return await Sentry.startSpan({
      op: 'job.execute',
      name: `Execute Job: ${jobId}`
    }, async () => {
      let branchCreated = false;

      try {
        if (!this._prepareJobForExecution(job)) {
          return;
        }
        branchCreated = await this._setupGitBranchIfEnabled(job);

        const result = await this.runJobHandler(job);
        await this._finalizeJobSuccess(job, result, branchCreated);

      } catch (error) {
        await this._finalizeJobFailure(job, error, branchCreated);

      } finally {
        this.activeJobs--;
        this.processQueue();
      }
    });
  }

  private _persistJob(job: Job): void {
    if (!job?.id) {
      logger.error({ job }, 'Cannot persist job without ID');
      return;
    }

    if (!isValidJobStatus(job.status)) {
      logger.error({ jobId: job.id, status: job.status }, 'Invalid job status, skipping persistence');
      return;
    }

    try {
      jobRepository.saveJob({
        id: job.id,
        pipelineId: this.jobType,
        status: job.status,
        createdAt: toISOString(job.createdAt),
        startedAt: toISOString(job.startedAt),
        completedAt: toISOString(job.completedAt),
        data: job.data,
        result: job.result,
        error: job.error,
        git: job.git
      });
    } catch (dbErr) {
      logError(logger, dbErr, 'Failed to persist job to database', { jobId: job.id, status: job.status });
      Sentry.captureException(dbErr, {
        tags: { jobId: job.id, operation: 'persist' }
      });
      throw dbErr;
    }
  }

  private _trySilentPersist(job: Job, context: string): void {
    try {
      this._persistJob(job);
    } catch (err) {
      logError(logger, err, `Failed to persist job (${context})`, { jobId: job.id, status: job.status });
      Sentry.captureException(err, {
        tags: { jobId: job.id, operation: `persist_${context}` }
      });
    }
  }

  private _prepareJobForExecution(job: Job): boolean {
    if (job.status !== JOB_STATUS.QUEUED) {
      logger.debug({
        jobId: job.id,
        status: job.status
      }, 'Skipping execution because job is no longer queued');
      return false;
    }

    job.status = JOB_STATUS.RUNNING;
    job.startedAt = new Date();
    job.retryPending = false;
    this.emit(JOB_EVENTS.STARTED, job);
    this._trySilentPersist(job, PERSIST_CONTEXT.STARTED);

    Sentry.addBreadcrumb({
      category: 'job',
      message: `Job ${job.id} started`,
      level: 'info'
    });

    return true;
  }

  private async _setupGitBranchIfEnabled(job: Job): Promise<boolean> {
    if (!this.gitWorkflowEnabled || !this.branchManager || !job.data.repositoryPath) {
      return false;
    }

    try {
      const branchInfo = await this.branchManager.createJobBranch(
        job.data.repositoryPath as string,
        {
          jobId: job.id,
          jobType: this.jobType,
          description: (job.data.description || job.data.repository) as string | undefined
        }
      );

      if (branchInfo?.branchName) {
        job.git.branchName = branchInfo.branchName;
        job.git.originalBranch = branchInfo.originalBranch;
        return true;
      }
    } catch (gitError) {
      logWarn(logger, gitError as Error, 'Failed to create branch, continuing without git workflow', { jobId: job.id });
    }

    return false;
  }

  private async _finalizeJobSuccess(job: Job, result: unknown, branchCreated: boolean): Promise<void> {
    job.status = JOB_STATUS.COMPLETED;
    job.completedAt = new Date();
    job.result = result;

    if (branchCreated && this.gitWorkflowEnabled) {
      try {
        await this._handleGitWorkflowSuccess(job);
      } catch (gitError) {
        logError(logger, gitError, 'Git workflow failed, but job completed successfully', { jobId: job.id });
        Sentry.captureException(gitError, {
          tags: { component: 'git-workflow', jobId: job.id }
        });
      }
    }

    this.emit(JOB_EVENTS.COMPLETED, job);
    this.jobHistory.push({ ...job });
    this._pruneExpiredJobs();
    try {
      this._persistJob(job);
    } catch (dbErr) {
      logError(logger, dbErr, 'Failed to persist completed job', { jobId: job.id });
      Sentry.captureException(dbErr, {
        tags: { jobId: job.id, operation: 'persist_completed' }
      });
    }
    await this.logJobCompletion(job);

    Sentry.addBreadcrumb({
      category: 'job',
      message: `Job ${job.id} completed`,
      level: 'info'
    });
  }

  private async _finalizeJobFailure(job: Job, error: unknown, branchCreated: boolean): Promise<void> {
    const canRetry = isRetryable(error as Error) && job.retryCount < this.maxRetries;

    if (canRetry) {
      job.retryCount++;

      const classification = classifyError(error as Error);
      const retryDelay = classification?.suggestedDelay ?? this.retryDelayMs;

      logger.info({
        jobId: job.id,
        retryCount: job.retryCount,
        maxRetries: this.maxRetries,
        errorCode: (error as { code?: string })?.code,
        retryDelay
      }, 'Scheduling job retry');

      job.status = JOB_STATUS.QUEUED;
      job.startedAt = null;
      job.error = null;
      job.retryPending = true;

      this.emit(RETRY_EVENTS.CREATED, job, {
        attempt: job.retryCount,
        maxAttempts: this.maxRetries,
        reason: classification?.reason,
        delay: retryDelay
      });

      this._trySilentPersist(job, PERSIST_CONTEXT.RETRY_QUEUED);

      const jobId = job.id;
      setTimeout(() => {
        if (!this.jobs.has(jobId)) {
          logger.warn({ jobId }, 'Job deleted during retry delay, skipping retry');
          return;
        }

        const currentJob = this.jobs.get(jobId)!;

        if (!currentJob.retryPending) {
          logger.warn({ jobId }, 'Retry already processed or cancelled, skipping');
          return;
        }

        if (currentJob.status !== JOB_STATUS.QUEUED) {
          logger.warn({ jobId, status: currentJob.status }, 'Job status changed during retry delay, skipping retry');
          currentJob.retryPending = false;
          return;
        }

        currentJob.retryPending = false;
        this.queue.push(jobId);
        this.processQueue();
      }, retryDelay);

      return;
    }

    // No retry - mark as failed
    job.status = JOB_STATUS.FAILED;
    job.completedAt = new Date();
    job.error = { message: safeErrorMessage(error) };

    if (branchCreated && this.gitWorkflowEnabled && this.branchManager && job.git.branchName && job.git.originalBranch && typeof job.data.repositoryPath === 'string') {
      try {
        await this.branchManager.cleanupBranch(
          job.data.repositoryPath,
          job.git.branchName,
          job.git.originalBranch
        );
        logger.info({ jobId: job.id, branchName: job.git.branchName }, 'Cleaned up branch after job failure');
      } catch (cleanupError) {
        logWarn(logger, cleanupError as Error, 'Failed to cleanup branch', { jobId: job.id });
      }
    }

    this.emit(JOB_EVENTS.FAILED, job, error);
    this.jobHistory.push({ ...job });
    this._pruneExpiredJobs();
    this._trySilentPersist(job, PERSIST_CONTEXT.FAILED);

    Sentry.captureException(error, {
      tags: { jobId: job.id, jobType: this.jobType },
      contexts: {
        job: { id: job.id, data: job.data as Record<string, unknown>, startedAt: job.startedAt?.toISOString() ?? null }
      }
    });

    await this.logJobFailure(job, error as Error);
    logError(logger, error, 'Job failed', { jobId: job.id, jobData: job.data });
  }

  private async _handleGitWorkflowSuccess(job: Job): Promise<void> {
    if (!this.branchManager) {
      logger.warn({ jobId: job.id }, 'Branch manager not initialized, skipping git workflow');
      return;
    }
    if (!job.git.branchName || !job.git.originalBranch) {
      logger.warn({ jobId: job.id }, 'Missing branch info, skipping git workflow');
      return;
    }

    const repositoryPath = job.data.repositoryPath;
    if (typeof repositoryPath !== 'string') {
      logger.warn({ jobId: job.id }, 'Missing repository path, skipping git workflow');
      return;
    }

    const hasChanges = await this.branchManager.hasChanges(repositoryPath);
    if (!hasChanges) {
      logger.info({ jobId: job.id }, 'No changes to commit, cleaning up branch');

      await this.branchManager.cleanupBranch(
        repositoryPath,
        job.git.branchName,
        job.git.originalBranch
      );

      return;
    }

    job.git.changedFiles = await this.branchManager.getChangedFiles(repositoryPath);

    logger.info({
      jobId: job.id,
      filesChanged: job.git.changedFiles.length
    }, 'Changes detected, committing');

    const commitMessage = await this._generateCommitMessage(job);
    const commitContext = {
      message: commitMessage.title,
      description: commitMessage.body,
      jobId: job.id
    };

    job.git.commitSha = await this.branchManager.commitChanges(
      repositoryPath,
      commitContext
    );

    const pushed = await this.branchManager.pushBranch(
      repositoryPath,
      job.git.branchName
    );

    if (!pushed) {
      logger.warn({ jobId: job.id }, 'Failed to push branch, skipping PR creation');
      return;
    }

    const prContext = await this._generatePRContext(job, commitMessage);
    job.git.prUrl = await this.branchManager.createPullRequest(
      repositoryPath,
      prContext
    );

    if (job.git.prUrl) {
      logger.info({
        jobId: job.id,
        prUrl: job.git.prUrl
      }, 'Pull request created');

      Sentry.addBreadcrumb({
        category: 'git',
        message: `Created PR: ${job.git.prUrl}`,
        level: 'info'
      });
    }
  }

  /**
   * Generate commit message for job
   * Override this method to customize commit messages
   *
   * @param job Completed job context.
   * @returns Commit title/body payload.
   */
  public async _generateCommitMessage(job: Job): Promise<{ title: string; body: string }> {
    return {
      title: `${this.jobType}: automated changes from job ${job.id}`,
      body: `Automated changes generated by ${this.jobType} job.\n\nFiles changed: ${job.git.changedFiles.length}`
    };
  }

  /**
   * Generate PR context for job
   * Override this method to customize PR details
   *
   * @param job Completed job context.
   * @param commitMessage Optional pre-generated commit message.
   * @returns Pull request context payload.
   */
  public async _generatePRContext(job: Job, commitMessage?: { title: string; body: string }): Promise<{ branchName: string; title: string; body: string; labels: string[] }> {
    const msg = commitMessage ?? await this._generateCommitMessage(job);

    return {
      branchName: job.git.branchName ?? '',
      title: msg.title,
      body: [
        '## Automated Changes',
        '',
        msg.body,
        '',
        '### Job Details',
        `- **Job ID**: ${job.id}`,
        `- **Job Type**: ${this.jobType}`,
        `- **Files Changed**: ${job.git.changedFiles.length}`,
        '',
        '### Changed Files',
        ...job.git.changedFiles.map(f => `- \`${f}\``),
        '',
        '---',
        '',
        'Generated with [Claude Code](https://claude.com/claude-code)'
      ].join('\n'),
      labels: ['automated', this.jobType]
    };
  }

  /**
   * Override this method to define job execution logic
   *
   * @param _job Job to execute.
   * @returns Job result payload.
   */
  async runJobHandler(_job: Job): Promise<unknown> {
    throw new Error('runJobHandler must be implemented by subclass');
  }

  /**
   * Starts queue processing after database initialization completes.
   */
  async start(): Promise<void> {
    await this._dbReady;
    this.isRunning = true;
    this.processQueue();
  }

  /**
   * Stops queue processing for new jobs.
   */
  stop(): void {
    this.isRunning = false;
  }

  /**
   * Convenience setter to override `runJobHandler`.
   *
   * @param handler Async job execution handler.
   */
  set handleJob(handler: (job: Job) => Promise<unknown>) {
    this.runJobHandler = handler;
  }

  private async _writeJobLog(job: Job, suffix: string, extra?: Record<string, unknown>): Promise<void> {
    try {
      await fs.mkdir(this.logDir, { recursive: true });
      const sanitizedId = job.id.replace(VALIDATION.JOB_ID_SANITIZE_PATTERN, '_');
      const logPath = path.join(this.logDir, `${sanitizedId}${suffix}`);
      await fs.writeFile(logPath, JSON.stringify(extra ? { ...job, ...extra } : job, null, FORMATTING.JSON_INDENT));
    } catch (writeError) {
      logError(logger, writeError, `Failed to write ${suffix} log file`, { jobId: job.id });
    }
  }

  /**
   * Writes a success log file for a job.
   *
   * @param job Job to log.
   */
  async logJobCompletion(job: Job): Promise<void> {
    await this._writeJobLog(job, '.json');
  }

  /**
   * Writes a failure log file for a job.
   *
   * @param job Failed job.
   * @param error Failure error details.
   */
  async logJobFailure(job: Job, error: Error): Promise<void> {
    await this._writeJobLog(job, '.error.json', {
      error: { message: error.message, stack: error.stack }
    });
  }

  /**
   * Returns a job by id.
   *
   * @param jobId Job identifier.
   * @returns Job when found.
   */
  getJob(jobId: string): Job | undefined {
    return this.jobs.get(jobId);
  }

  /**
   * Returns all currently tracked jobs.
   *
   * @returns List of in-memory jobs.
   */
  getAllJobs(): Job[] {
    return Array.from(this.jobs.values());
  }

  /**
   * Returns queue and outcome statistics.
   *
   * @returns Aggregated job stats.
   */
  getStats(): JobStats {
    return {
      total: this.jobs.size,
      queued: this.queue.length,
      active: this.activeJobs,
      pendingRetries: Array.from(this.jobs.values()).filter(j => j.retryPending === true).length,
      completed: this.jobHistory.filter(j => j.status === JOB_STATUS.COMPLETED).length,
      failed: this.jobHistory.filter(j => j.status === JOB_STATUS.FAILED).length
    };
  }

  private _isExpiredTerminalJob(job: Job, cutoffMs: number): boolean {
    if (!TERMINAL_STATUSES.includes(job.status)) return false;
    const completedAtMs = job.completedAt?.getTime();
    if (typeof completedAtMs !== 'number') return false;
    return completedAtMs <= cutoffMs;
  }

  private _pruneExpiredJobs(referenceTimeMs: number = Date.now()): void {
    const cutoffMs = referenceTimeMs - (this.jobRetentionDays * TIME_MS.DAY);
    let removedFromJobs = 0;

    for (const [jobId, job] of this.jobs.entries()) {
      if (this._isExpiredTerminalJob(job, cutoffMs)) {
        this.jobs.delete(jobId);
        removedFromJobs++;
      }
    }

    const historyBefore = this.jobHistory.length;
    this.jobHistory = this.jobHistory.filter(job => !this._isExpiredTerminalJob(job, cutoffMs));
    const removedFromHistory = historyBefore - this.jobHistory.length;

    if (removedFromJobs > 0 || removedFromHistory > 0) {
      logger.debug({
        jobType: this.jobType,
        retentionDays: this.jobRetentionDays,
        removedFromJobs,
        removedFromHistory
      }, 'Pruned expired terminal jobs from memory');
    }
  }

  private _executeJobAction(jobId: string, config: {
    action: string;
    statusGuard: (status: JobStatus) => boolean;
    guardMessage: (status: JobStatus) => string;
    mutate: (job: Job) => void;
    postAction?: () => void;
    logLevel?: 'info' | 'warning';
  }): JobActionResult {
    const job = this.jobs.get(jobId);
    if (!job) {
      return { success: false, message: `Job ${jobId} not found` };
    }
    if (config.statusGuard(job.status)) {
      return { success: false, message: config.guardMessage(job.status), job };
    }

    const previousStatus = job.status;

    if (job.status === JOB_STATUS.QUEUED) {
      const idx = this.queue.indexOf(jobId);
      if (idx > -1) this.queue.splice(idx, 1);
    }

    config.mutate(job);
    if (TERMINAL_STATUSES.includes(job.status)) {
      this._pruneExpiredJobs();
    }

    this._trySilentPersist(job, config.action);

    this.emit(`job:${config.action}`, job);

    Sentry.addBreadcrumb({
      category: 'job',
      message: `Job ${jobId} ${config.action}`,
      level: config.logLevel ?? 'info',
      data: { jobId, previousStatus }
    });

    logger.info({ jobId, previousStatus }, `Job ${config.action}`);
    config.postAction?.();

    return { success: true, message: `Job ${jobId} ${config.action} successfully`, job };
  }

  /**
   * Cancels a queued or paused job.
   * Running jobs are not cancellable because handlers are not abortable.
   *
   * @param jobId Job identifier.
   * @returns Action result summary.
   */
  cancelJob(jobId: string): JobActionResult {
    return this._executeJobAction(jobId, {
      action: 'cancelled',
      statusGuard: (s) => TERMINAL_STATUSES.includes(s) || s === JOB_STATUS.RUNNING,
      guardMessage: (s) => s === JOB_STATUS.RUNNING
        ? 'Cannot cancel a running job. Cancellation is only supported for queued or paused jobs.'
        : `Cannot cancel job with status '${s}'`,
      mutate: (job) => {
        job.status = JOB_STATUS.CANCELLED;
        job.retryPending = false;
        job.completedAt = new Date();
        job.error = { message: 'Job cancelled by user', cancelled: true };
      },
      logLevel: 'warning'
    });
  }

  /**
   * Pauses a queued job before execution.
   *
   * @param jobId Job identifier.
   * @returns Action result summary.
   */
  pauseJob(jobId: string): JobActionResult {
    return this._executeJobAction(jobId, {
      action: 'paused',
      statusGuard: (s) => s !== JOB_STATUS.QUEUED,
      guardMessage: (s) => s === JOB_STATUS.RUNNING
        ? 'Cannot pause a running job. Pause is only supported for queued jobs.'
        : `Cannot pause job with status '${s}'`,
      mutate: (job) => {
        job.status = JOB_STATUS.PAUSED;
        job.retryPending = false;
        job.pausedAt = new Date();
      }
    });
  }

  /**
   * Resumes a paused job and re-enqueues it.
   *
   * @param jobId Job identifier.
   * @returns Action result summary.
   */
  resumeJob(jobId: string): JobActionResult {
    return this._executeJobAction(jobId, {
      action: 'resumed',
      statusGuard: (s) => s !== JOB_STATUS.PAUSED,
      guardMessage: (s) => `Cannot resume job with status '${s}'. Only paused jobs can be resumed.`,
      mutate: (job) => {
        job.status = JOB_STATUS.QUEUED;
        job.resumedAt = new Date();
        delete job.pausedAt;
        this.queue.push(job.id);
      },
      postAction: () => this.processQueue()
    });
  }
}

// file: sidequest/core/git-workflow-manager.ts
/**
 * Git Workflow Manager
 *
 * Encapsulates git operations for automated job workflows:
 * - Branch creation and cleanup
 * - Committing changes
 * - Pushing branches
 * - Creating pull requests
 */

import { BranchManager } from '../pipeline-core/git/branch-manager.ts';
import type { BranchManagerOptions, JobBranchContext, BranchResult, PRContext } from '../pipeline-core/git/branch-manager.ts';
import { createComponentLogger, logError, logWarn } from '../utils/logger.ts';
import * as Sentry from '@sentry/node';

const logger = createComponentLogger('GitWorkflowManager');

export interface CommitMessage {
  title: string;
  body: string;
}

export interface MessageGenerator {
  generateCommitMessage(): Promise<CommitMessage>;
  generatePRContext(): Promise<PRContext>;
}

export interface GitInfo {
  branchName: string;
  originalBranch: string;
}

export interface CommitContext {
  message: string;
  description?: string;
  jobId?: string;
}

export interface WorkflowResult {
  changedFiles: string[];
  commitSha: string | null;
  prUrl: string | null;
}

/**
 * Coordinates git automation for job execution workflows.
 */
export class GitWorkflowManager {
  readonly baseBranch: string;
  readonly branchPrefix: string;
  readonly dryRun: boolean;
  readonly branchManager: BranchManager;

  /**
   * Creates a workflow manager backed by `BranchManager`.
   *
   * @param options Branch and git execution options.
   */
  constructor(options: BranchManagerOptions = {}) {
    this.baseBranch = options.baseBranch || 'main';
    this.branchPrefix = options.branchPrefix || 'automated';
    this.dryRun = options.dryRun ?? false;

    this.branchManager = new BranchManager({
      baseBranch: this.baseBranch,
      branchPrefix: this.branchPrefix,
      dryRun: this.dryRun
    });

    logger.info({
      baseBranch: this.baseBranch,
      branchPrefix: this.branchPrefix,
      dryRun: this.dryRun
    }, 'GitWorkflowManager initialized');
  }

  /**
   * Creates an isolated branch for a job.
   *
   * @param repositoryPath Local repository path.
   * @param jobInfo Job metadata used for branch naming/context.
   * @returns Branch metadata when creation succeeds; otherwise `null`.
   */
  async createJobBranch(repositoryPath: string, jobInfo: JobBranchContext): Promise<BranchResult | null> {
    try {
      const branchInfo = await this.branchManager.createJobBranch(
        repositoryPath,
        jobInfo
      );

      if (branchInfo.branchName) {
        logger.info({
          jobId: jobInfo.jobId,
          branchName: branchInfo.branchName,
          repositoryPath
        }, 'Created job branch');

        Sentry.addBreadcrumb({
          category: 'git',
          message: `Created branch ${branchInfo.branchName}`,
          level: 'info'
        });
      }

      return branchInfo;
    } catch (error) {
      logWarn(logger, error as Error, 'Failed to create branch', { jobId: jobInfo.jobId });
      return null;
    }
  }

  /**
   * Checks whether the repository has uncommitted changes.
   *
   * @param repositoryPath Local repository path.
   * @returns `true` when changes are present.
   */
  async hasChanges(repositoryPath: string): Promise<boolean> {
    return this.branchManager.hasChanges(repositoryPath);
  }

  /**
   * Lists changed files in the repository.
   *
   * @param repositoryPath Local repository path.
   * @returns Relative file paths with changes.
   */
  async getChangedFiles(repositoryPath: string): Promise<string[]> {
    return this.branchManager.getChangedFiles(repositoryPath);
  }

  /**
   * Commits staged changes using provided context.
   *
   * @param repositoryPath Local repository path.
   * @param commitContext Commit message context.
   * @returns Commit SHA when commit succeeds; otherwise `null`.
   */
  async commitChanges(repositoryPath: string, commitContext: CommitContext): Promise<string | null> {
    try {
      const normalizedContext = {
        message: commitContext.message,
        jobId: commitContext.jobId || 'unknown',
        description: commitContext.description
      };
      const commitSha = await this.branchManager.commitChanges(
        repositoryPath,
        normalizedContext
      );

      logger.info({
        jobId: commitContext.jobId,
        commitSha
      }, 'Changes committed');

      return commitSha;
    } catch (error) {
      logError(logger, error, 'Failed to commit changes', { jobId: commitContext.jobId });
      throw error;
    }
  }

  /**
   * Pushes a branch to the remote.
   *
   * @param repositoryPath Local repository path.
   * @param branchName Branch name to push.
   * @returns `true` when push succeeds.
   */
  async pushBranch(repositoryPath: string, branchName: string): Promise<boolean> {
    try {
      const pushed = await this.branchManager.pushBranch(repositoryPath, branchName);

      if (pushed) {
        logger.info({ branchName }, 'Branch pushed to remote');
      } else {
        logWarn(logger, null, 'Failed to push branch', { branchName });
      }

      return pushed;
    } catch (error) {
      logError(logger, error, 'Error pushing branch', { branchName });
      return false;
    }
  }

  /**
   * Creates a pull request for a branch.
   *
   * @param repositoryPath Local repository path.
   * @param prContext Pull request context payload.
   * @returns Pull request URL when created; otherwise `null`.
   */
  async createPullRequest(repositoryPath: string, prContext: PRContext): Promise<string | null> {
    try {
      const prUrl = await this.branchManager.createPullRequest(repositoryPath, prContext);

      if (prUrl) {
        logger.info({ prUrl }, 'Pull request created');

        Sentry.addBreadcrumb({
          category: 'git',
          message: `Created PR: ${prUrl}`,
          level: 'info'
        });
      }

      return prUrl;
    } catch (error) {
      logError(logger, error, 'Failed to create pull request');
      return null;
    }
  }

  /**
   * Cleans up branch state after workflow completion/failure.
   *
   * @param repositoryPath Local repository path.
   * @param branchName Working branch to clean up.
   * @param originalBranch Branch to restore.
   */
  async cleanupBranch(repositoryPath: string, branchName: string, originalBranch: string): Promise<void> {
    try {
      await this.branchManager.cleanupBranch(repositoryPath, branchName, originalBranch);
      logger.info({ branchName }, 'Branch cleaned up');
    } catch (error) {
      logWarn(logger, error as Error, 'Failed to cleanup branch', { branchName });
    }
  }

  /**
   * Runs the full git workflow for a job.
   *
   * @param repositoryPath Local repository path.
   * @param gitInfo Branch context for the job.
   * @param messageGenerator Commit/PR message generator.
   * @returns Workflow result summary.
   */
  async executeWorkflow(repositoryPath: string, gitInfo: GitInfo, messageGenerator: MessageGenerator): Promise<WorkflowResult> {
    const result: WorkflowResult = {
      changedFiles: [],
      commitSha: null,
      prUrl: null
    };

    const hasChanges = await this.hasChanges(repositoryPath);

    if (!hasChanges) {
      logger.info('No changes to commit, cleaning up branch');
      await this.cleanupBranch(repositoryPath, gitInfo.branchName, gitInfo.originalBranch);
      return result;
    }

    result.changedFiles = await this.getChangedFiles(repositoryPath);

    logger.info({ filesChanged: result.changedFiles.length }, 'Changes detected, committing');

    const commitMessage = await messageGenerator.generateCommitMessage();
    const commitContext: CommitContext = {
      message: commitMessage.title,
      description: commitMessage.body
    };

    result.commitSha = await this.commitChanges(repositoryPath, commitContext);

    const pushed = await this.pushBranch(repositoryPath, gitInfo.branchName);

    if (!pushed) {
      logger.warn('Failed to push branch, skipping PR creation');
      return result;
    }

    const prContext = await messageGenerator.generatePRContext();
    result.prUrl = await this.createPullRequest(repositoryPath, prContext);

    return result;
  }
}

