import { SidequestServer, type Job, type SidequestServerOptions } from '../core/server.ts';
import { generateReport } from '../utils/report-generator.ts';
import { spawn } from 'child_process';
import { captureProcessOutput } from '@shared/process-io';
import fs from 'fs/promises';
import path from 'path';
import os from 'os';
import { fileURLToPath } from 'url';
import * as Sentry from '@sentry/node';
import { createComponentLogger } from '../utils/logger.ts';
import { TIMEOUTS, GIT_ACTIVITY, NUMBER_BASE } from '../core/constants.ts';
import { TIME_MS } from '../core/units.ts';

const logger = createComponentLogger('GitActivityWorker');

interface GitActivityWorkerOptions extends SidequestServerOptions {
  codeBaseDir?: string;
  pythonScript?: string;
  personalSiteDir?: string;
  outputDir?: string;
}

interface PythonArgs {
  reportType?: string;
  days?: number;
  sinceDate?: string;
  untilDate?: string;
  outputFormat?: string;
  generateVisualizations?: boolean;
}

interface PythonScriptResult {
  stdout: string;
  stderr: string;
  outputFiles: string[];
}

export interface GitActivityStats {
  totalCommits: number;
  totalRepositories: number;
  linesAdded: number;
  linesDeleted: number;
  filesChanged?: number;
}

interface VerifiedFile {
  path: string;
  size?: number;
  exists: boolean;
}

interface ReportJobOptions {
  jobId?: string;
  reportType?: string;
  days?: number;
  sinceDate?: string;
  untilDate?: string;
  outputFormat?: string;
  generateVisualizations?: boolean;
}

function toFiniteNumber(value: unknown): number {
  if (typeof value === 'number' && Number.isFinite(value)) {
    return value;
  }
  if (typeof value === 'string') {
    const parsed = Number(value);
    if (Number.isFinite(parsed)) {
      return parsed;
    }
  }
  return 0;
}

export function buildGitActivityStatsFromData(data: Record<string, unknown>): GitActivityStats {
  return {
    totalCommits: toFiniteNumber(data.total_commits),
    totalRepositories: Array.isArray(data.repositories)
      ? data.repositories.length
      : toFiniteNumber(data.total_repositories),
    linesAdded: toFiniteNumber(data.total_additions),
    linesDeleted: toFiniteNumber(data.total_deletions),
    filesChanged: toFiniteNumber(data.total_files)
  };
}

export async function parseGitActivityStatsFromJsonFiles(
  outputFiles: string[],
  scriptDir: string,
  readFile: (path: string, encoding: BufferEncoding) => Promise<string> = fs.readFile
): Promise<GitActivityStats | null> {
  const jsonFiles = outputFiles.filter((file) => file.toLowerCase().endsWith('.json'));

  for (const file of jsonFiles) {
    const resolvedPath = path.isAbsolute(file)
      ? file
      : path.resolve(scriptDir, file);
    try {
      const content = await readFile(resolvedPath, 'utf-8');
      const data = JSON.parse(content) as Record<string, unknown>;
      if (Object.prototype.hasOwnProperty.call(data, 'total_commits')) {
        return buildGitActivityStatsFromData(data);
      }
    } catch (error) {
      const err = error as Error;
      logger.warn({ file: resolvedPath, error: err.message }, 'Failed to parse git activity stats JSON file');
      Sentry.captureException(err, {
        tags: {
          component: 'git-activity-worker',
          operation: 'parse-stats-json'
        },
        extra: {
          file: resolvedPath
        }
      });
      // Continue to next JSON output file.
    }
  }

  return null;
}

export function parseGitActivityStatsFromText(stdout: string): GitActivityStats {
  const stats: GitActivityStats = {
    totalCommits: 0,
    totalRepositories: 0,
    linesAdded: 0,
    linesDeleted: 0
  };

  const commitsMatch = stdout.match(/Total commits:\s*(\d+)/i);
  if (commitsMatch) {
    stats.totalCommits = parseInt(commitsMatch[1], NUMBER_BASE.DECIMAL);
  }

  const additionsMatch = stdout.match(/Lines added:\s*(\d+)/i);
  if (additionsMatch) {
    stats.linesAdded = parseInt(additionsMatch[1], NUMBER_BASE.DECIMAL);
  }

  const deletionsMatch = stdout.match(/Lines deleted:\s*(\d+)/i);
  if (deletionsMatch) {
    stats.linesDeleted = parseInt(deletionsMatch[1], NUMBER_BASE.DECIMAL);
  }

  const reposMatch = stdout.match(/Active repositories:\s*(\d+)/i);
  if (reposMatch) {
    stats.totalRepositories = parseInt(reposMatch[1], NUMBER_BASE.DECIMAL);
  }

  const filesMatch = stdout.match(/File changes:\s*(\d+)/i);
  if (filesMatch) {
    stats.filesChanged = parseInt(filesMatch[1], NUMBER_BASE.DECIMAL);
  }

  return stats;
}

/**
 * GitActivityWorker - Executes git activity report jobs
 *
 * Integrates the Python git activity collector into the AlephAuto framework,
 * providing job queue management, event tracking, and Sentry error monitoring.
 */
export class GitActivityWorker extends SidequestServer {
  codeBaseDir: string;
  pythonScript: string;
  personalSiteDir: string;
  outputDir: string;

  /**
   * Initialize a git activity worker with project and output paths.
   *
   * @param options Optional worker configuration.
   */
  constructor(options: GitActivityWorkerOptions = {}) {
    super({
      ...options,
      jobType: 'git-activity'
    });
    this.codeBaseDir = options.codeBaseDir ?? path.join(os.homedir(), 'code');
    const moduleDir = path.dirname(fileURLToPath(import.meta.url));
    this.pythonScript = options.pythonScript ?? path.join(
      moduleDir,
      '..',
      'pipeline-runners',
      'collect_git_activity.py'
    );
    this.personalSiteDir = options.personalSiteDir ?? path.join(
      os.homedir(),
      'code',
      'PersonalSite'
    );
    this.outputDir = options.outputDir ?? path.join(os.homedir(), 'code', 'PersonalSite', '_reports');
  }

  /**
   * Run git activity report job
   */
  async runJobHandler(job: Job): Promise<unknown> {
    const startTime = Date.now();
    const {
      reportType,
      days,
      sinceDate,
      untilDate,
      outputFormat = 'both',
      generateVisualizations = true
    } = job.data as {
      reportType?: string;
      days?: number;
      sinceDate?: string;
      untilDate?: string;
      outputFormat?: string;
      generateVisualizations?: boolean;
    };

    logger.info({
      jobId: job.id,
      reportType,
      days,
      sinceDate,
      untilDate
    }, 'Running git activity report');

    try {
      // Build command arguments
      const args = this.#buildPythonArgs({
        reportType,
        days,
        sinceDate,
        untilDate,
        outputFormat,
        generateVisualizations
      });

      // Execute Python script
      const { stdout, stderr, outputFiles } = await this.#runPythonScript(args);

      if (stderr) {
        logger.warn({ jobId: job.id, stderr }, 'Git activity warnings');
      }

      // Parse JSON output to get statistics
      const stats = await this.#parseStats(stdout, outputFiles);

      // Verify output files exist
      const verifiedFiles = await this.#verifyOutputFiles(outputFiles);

      logger.info({
        jobId: job.id,
        stats,
        filesGenerated: verifiedFiles.length
      }, 'Git activity report completed');

      const result: Record<string, unknown> = {
        reportType,
        days: days ?? this.#calculateDays(sinceDate, untilDate),
        sinceDate,
        untilDate,
        stats,
        outputFiles: verifiedFiles,
        timestamp: new Date().toISOString()
      };

      // Generate HTML/JSON reports
      const endTime = Date.now();
      const reportPaths = await generateReport({
        jobId: job.id,
        jobType: 'git-activity',
        status: 'completed',
        result,
        startTime,
        endTime,
        parameters: job.data,
        metadata: {
          reportType,
          filesGenerated: verifiedFiles.length
        }
      });

      result.reportPaths = reportPaths;
      logger.info({ reportPaths }, 'Git activity reports generated');

      return result;
    } catch (error) {
      const err = error as Error;
      logger.error({
        jobId: job.id,
        error: err.message,
        stack: err.stack
      }, 'Git activity report failed');
      throw error;
    }
  }

  /**
   * Build Python script arguments
   */
  #buildPythonArgs({ reportType, days, sinceDate, untilDate, outputFormat, generateVisualizations }: PythonArgs): string[] {
    const args: string[] = [];

    // Add date range arguments
    if (sinceDate) {
      args.push('--start-date', sinceDate);
      if (untilDate) {
        args.push('--end-date', untilDate);
      }
    } else if (reportType === GIT_ACTIVITY.WEEKLY_REPORT_TYPE || days === GIT_ACTIVITY.WEEKLY_WINDOW_DAYS) {
      args.push('--weekly');
    } else if (reportType === GIT_ACTIVITY.MONTHLY_REPORT_TYPE || days === GIT_ACTIVITY.MONTHLY_WINDOW_DAYS) {
      args.push('--monthly');
    } else if (days) {
      args.push('--days', String(days));
    } else {
      // Default to weekly
      args.push('--weekly');
    }

    // Always pass output format explicitly so Python defaults cannot drift.
    if (outputFormat) {
      args.push('--output-format', outputFormat);
    }

    // Add visualization flag
    if (!generateVisualizations) {
      args.push('--no-visualizations');
    }

    return args;
  }

  /**
   * Execute Python script
   */
  #runPythonScript(args: string[]): Promise<PythonScriptResult> {
    return new Promise((resolve, reject) => {
      logger.debug({ args }, 'Executing Python script');

      const proc = spawn('python3', [this.pythonScript, ...args], {
        cwd: path.dirname(this.pythonScript),
        timeout: TIMEOUTS.GIT_REPORT_MS
      });

      const output = captureProcessOutput(proc);

      proc.on('close', (code) => {
        const stdout = output.getStdout();
        const stderr = output.getStderr();
        if (code === 0) {
          // Extract output files from stdout if present
          const outputFiles = this.#extractOutputFiles(stdout);
          resolve({ stdout, stderr, outputFiles });
        } else {
          const error = new Error(`Python script exited with code ${code}`) as Error & {
            code: number | null;
            stdout: string;
            stderr: string;
          };
          error.code = code;
          error.stdout = stdout;
          error.stderr = stderr;
          reject(error);
        }
      });

      proc.on('error', (error) => {
        const augmented = error as Error & { stdout: string; stderr: string };
        augmented.stdout = output.getStdout();
        augmented.stderr = output.getStderr();
        reject(augmented);
      });
    });
  }

  /**
   * Extract output file paths from script output
   */
  #extractOutputFiles(stdout: string): string[] {
    const files = new Set<string>();
    const pendingSvgBasenames: string[] = [];

    // JSON output lines emitted by the Python script.
    const jsonPatterns = [
      /JSON data saved to:\s*(.+\.json)/gi,
      /(?:Saving|Saved)\s+(?:to|data to):\s*(.+\.json)/gi
    ];
    for (const pattern of jsonPatterns) {
      for (const match of stdout.matchAll(pattern)) {
        files.add(match[1].trim());
      }
    }

    // Markdown output line emitted by the Python script.
    for (const match of stdout.matchAll(/Jekyll report saved to:\s*(.+\.md)/gi)) {
      files.add(match[1].trim());
    }

    // SVG output lines (supports 'Created:', 'Saving:', 'Generated:', etc).
    for (const match of stdout.matchAll(/(?:Generating|Generated|Saving|Created).*?:\s*(.+\.svg)/gi)) {
      const rawPath = match[1].trim();
      if (path.isAbsolute(rawPath) || rawPath.includes('/')) {
        files.add(rawPath);
      } else {
        pendingSvgBasenames.push(rawPath);
      }
    }

    // When Python logs only SVG basenames, recover full paths from summary output.
    const visualizationDirMatch = stdout.match(/Visualizations saved to:\s*(.+)/i);
    if (visualizationDirMatch) {
      const visualizationDir = visualizationDirMatch[1].trim();
      for (const svgName of pendingSvgBasenames) {
        files.add(path.join(visualizationDir, svgName));
      }
    }

    return Array.from(files);
  }

  async #parseStats(stdout: string, outputFiles: string[]): Promise<GitActivityStats> {
    const scriptDir = path.dirname(this.pythonScript);
    const jsonStats = await parseGitActivityStatsFromJsonFiles(outputFiles, scriptDir);
    if (jsonStats) {
      return jsonStats;
    }
    return parseGitActivityStatsFromText(stdout);
  }

  /**
   * Calculate days between two dates
   */
  #calculateDays(sinceDate?: string, untilDate?: string): number | null {
    if (!sinceDate || !untilDate) return null;

    const since = new Date(sinceDate);
    const until = new Date(untilDate);
    const diffTime = Math.abs(until.getTime() - since.getTime());
    const diffDays = Math.ceil(diffTime / TIME_MS.DAY);

    return diffDays;
  }

  /**
   * Verify output files exist
   */
  async #verifyOutputFiles(files: string[]): Promise<VerifiedFile[]> {
    const verified: VerifiedFile[] = [];
    const scriptDir = path.dirname(this.pythonScript);

    for (const file of files) {
      const resolvedPath = path.isAbsolute(file)
        ? file
        : path.resolve(scriptDir, file);
      try {
        await fs.access(resolvedPath);
        const stats = await fs.stat(resolvedPath);
        verified.push({
          path: resolvedPath,
          size: stats.size,
          exists: true
        });
      } catch (error) {
        const err = error as Error;
        logger.warn({ file: resolvedPath, error: err.message }, 'Output file not found');
        verified.push({
          path: resolvedPath,
          exists: false
        });
      }
    }

    return verified;
  }

  /**
   * Create a weekly report job
   */
  createWeeklyReportJob(): Job {
    const jobId = `git-activity-weekly-${Date.now()}`;

    return this.createJob(jobId, {
      reportType: GIT_ACTIVITY.WEEKLY_REPORT_TYPE,
      days: GIT_ACTIVITY.WEEKLY_WINDOW_DAYS,
      outputFormat: 'both',
      type: 'git-activity-report'
    });
  }

  /**
   * Create a monthly report job
   */
  createMonthlyReportJob(): Job {
    const jobId = `git-activity-monthly-${Date.now()}`;

    return this.createJob(jobId, {
      reportType: GIT_ACTIVITY.MONTHLY_REPORT_TYPE,
      days: GIT_ACTIVITY.MONTHLY_WINDOW_DAYS,
      outputFormat: 'both',
      type: 'git-activity-report'
    });
  }

  /**
   * Create a custom date range report job
   */
  createCustomReportJob(sinceDate: string, untilDate: string): Job {
    const jobId = `git-activity-custom-${Date.now()}`;

    return this.createJob(jobId, {
      reportType: GIT_ACTIVITY.CUSTOM_REPORT_TYPE,
      sinceDate,
      untilDate,
      type: 'git-activity-report'
    });
  }

  /**
   * Create a report job with custom parameters
   */
  createReportJob(options: ReportJobOptions = {}): Job {
    const jobId = options.jobId ?? `git-activity-${Date.now()}`;

    return this.createJob(jobId, {
      reportType: options.reportType ?? GIT_ACTIVITY.DEFAULT_REPORT_TYPE,
      days: options.days,
      sinceDate: options.sinceDate,
      untilDate: options.untilDate,
      outputFormat: options.outputFormat ?? 'both',
      generateVisualizations: options.generateVisualizations !== false,
      type: 'git-activity-report'
    });
  }
}

// file: sidequest/workers/git-activity-worker.test.ts
import test from 'node:test';
import assert from 'node:assert/strict';
import fs from 'fs/promises';
import os from 'os';
import path from 'path';
import {
  buildGitActivityStatsFromData,
  parseGitActivityStatsFromJsonFiles,
  parseGitActivityStatsFromText
} from './git-activity-worker.ts';

test('buildGitActivityStatsFromData coerces numeric values safely', () => {
  const stats = buildGitActivityStatsFromData({
    total_commits: '12',
    total_repositories: '3',
    total_additions: 44,
    total_deletions: '9',
    total_files: '18'
  });

  assert.deepEqual(stats, {
    totalCommits: 12,
    totalRepositories: 3,
    linesAdded: 44,
    linesDeleted: 9,
    filesChanged: 18
  });
});

test('parseGitActivityStatsFromJsonFiles parses valid JSON output files', async (t) => {
  const tmpDir = await fs.mkdtemp(path.join(os.tmpdir(), 'git-activity-worker-test-'));
  t.after(async () => {
    await fs.rm(tmpDir, { recursive: true, force: true });
  });

  const jsonPath = path.join(tmpDir, 'report.json');
  await fs.writeFile(jsonPath, JSON.stringify({
    total_commits: 8,
    repositories: [{ name: 'a' }, { name: 'b' }],
    total_additions: 100,
    total_deletions: 20,
    total_files: 14
  }));

  const stats = await parseGitActivityStatsFromJsonFiles(['report.json'], tmpDir);

  assert.deepEqual(stats, {
    totalCommits: 8,
    totalRepositories: 2,
    linesAdded: 100,
    linesDeleted: 20,
    filesChanged: 14
  });
});

test('parseGitActivityStatsFromJsonFiles skips invalid JSON and returns null when none parse', async (t) => {
  const tmpDir = await fs.mkdtemp(path.join(os.tmpdir(), 'git-activity-worker-test-'));
  t.after(async () => {
    await fs.rm(tmpDir, { recursive: true, force: true });
  });

  await fs.writeFile(path.join(tmpDir, 'bad.json'), '{not json');

  const stats = await parseGitActivityStatsFromJsonFiles(['bad.json'], tmpDir);

  assert.equal(stats, null);
});

test('parseGitActivityStatsFromJsonFiles skips JSON without total_commits and uses next file', async (t) => {
  const tmpDir = await fs.mkdtemp(path.join(os.tmpdir(), 'git-activity-worker-test-'));
  t.after(async () => {
    await fs.rm(tmpDir, { recursive: true, force: true });
  });

  await fs.writeFile(path.join(tmpDir, 'partial.json'), JSON.stringify({ total_files: 9 }));
  await fs.writeFile(path.join(tmpDir, 'good.json'), JSON.stringify({
    total_commits: 4,
    total_repositories: 2,
    total_additions: 11,
    total_deletions: 3,
    total_files: 9
  }));

  const stats = await parseGitActivityStatsFromJsonFiles(['partial.json', 'good.json'], tmpDir);

  assert.deepEqual(stats, {
    totalCommits: 4,
    totalRepositories: 2,
    linesAdded: 11,
    linesDeleted: 3,
    filesChanged: 9
  });
});

test('parseGitActivityStatsFromText parses text summary fallback', () => {
  const stats = parseGitActivityStatsFromText(`
Total commits: 17
Lines added: 222
Lines deleted: 101
Active repositories: 6
File changes: 45
`);

  assert.deepEqual(stats, {
    totalCommits: 17,
    totalRepositories: 6,
    linesAdded: 222,
    linesDeleted: 101,
    filesChanged: 45
  });
});

test('parseGitActivityStatsFromText defaults missing fields to zero', () => {
  const stats = parseGitActivityStatsFromText('Total commits: 3');

  assert.deepEqual(stats, {
    totalCommits: 3,
    totalRepositories: 0,
    linesAdded: 0,
    linesDeleted: 0
  });
});

// file: sidequest/workers/bugfix-audit-worker.ts
import { SidequestServer, type Job, type SidequestServerOptions } from '../core/server.ts';
import { BranchManager } from '../pipeline-core/git/branch-manager.ts';
import { execCommand } from '@shared/process-io';
import { createComponentLogger, logError, logStage } from '../utils/logger.ts';
import { FORMATTING } from '../core/constants.ts';
import { config } from '../core/config.ts';
import fs from 'fs/promises';
import path from 'path';

const logger = createComponentLogger('BugfixAuditWorker');

interface BugfixAuditWorkerOptions extends SidequestServerOptions {
  activeDocsDir?: string;
  outputBaseDir?: string;
}

interface StageResult {
  name: string;
  status: string;
  output: string;
}

interface WorkflowResults {
  markdownFile: string;
  projectName: string;
  repoPath: string;
  stages: StageResult[];
  branchName: string;
  pullRequestUrl: string | null;
  timestamp: string;
}

interface RepositoryInfo {
  projectName: string | null;
  possibleRepoPaths: string[];
}

/**
 * BugfixAuditWorker - Automated bug detection and fixing workflow
 *
 * Orchestrates multiple tools in sequence:
 * 1. bugfix-planner agent - Create comprehensive bug fix plans
 * 2. bug-detective plugin - Systematic debugging
 * 3. audit plugin - Security audit
 * 4. ceo-quality-controller-agent - Quality validation
 * 5. refractor plugin - Implement fixes
 *
 * Git workflow:
 * - Creates feature branch before changes
 * - Commits after each stage
 * - Pushes branch and creates PR when complete
 *
 * Uses BranchManager directly (not gitWorkflowEnabled) because
 * this pipeline makes multiple intermediate commits rather than the
 * base class's single commit-at-end pattern.
 */
export class BugfixAuditWorker extends SidequestServer {
  activeDocsDir: string;
  outputBaseDir: string;
  declare branchManager: BranchManager;

  /**
   * constructor.
   */
  constructor(options: BugfixAuditWorkerOptions = {}) {
    super({
      ...options,
      jobType: 'bugfix-audit',
      // Explicitly disable base-class git workflow -- we manage commits ourselves
      gitWorkflowEnabled: false
    });

    this.activeDocsDir = options.activeDocsDir ?? path.join(config.homeDir, 'dev', 'active');
    this.outputBaseDir = options.outputBaseDir ?? path.join(config.homeDir, 'code', 'jobs', 'sidequest', 'bug-fixes', 'output');

    this.branchManager = new BranchManager({
      baseBranch: options.gitBaseBranch ?? config.gitBaseBranch,
      branchPrefix: options.gitBranchPrefix ?? 'bugfix',
      dryRun: options.gitDryRun ?? config.gitDryRun
    });

    logger.info({
      activeDocsDir: this.activeDocsDir,
      outputBaseDir: this.outputBaseDir
    }, 'BugfixAuditWorker initialized');
  }

  /**
   * Find all markdown files in active docs directory
   */
  async findMarkdownFiles(): Promise<string[]> {
    logger.info({ dir: this.activeDocsDir }, 'Scanning for markdown files');

    const markdownFiles: string[] = [];

    /**
     * scanDirectory.
     */
    async function scanDirectory(dir: string): Promise<void> {
      const entries = await fs.readdir(dir, { withFileTypes: true });
      for (const entry of entries) {
        const fullPath = path.join(dir, entry.name);
        if (entry.isDirectory()) {
          await scanDirectory(fullPath);
        } else if (entry.isFile() && entry.name.endsWith('.md')) {
          markdownFiles.push(fullPath);
        }
      }
    }

    await scanDirectory(this.activeDocsDir);

    logger.info({ count: markdownFiles.length }, 'Markdown files found');
    return markdownFiles;
  }

  /**
   * Extract repository path from markdown file location
   */
  getRepositoryFromPath(markdownPath: string): RepositoryInfo {
    const parts = markdownPath.split(path.sep);
    const activeIndex = parts.indexOf('active');

    if (activeIndex !== -1 && parts.length > activeIndex + 1) {
      const projectName = parts[activeIndex + 1];
      const possibleRepoPaths = [
        path.join(config.homeDir, 'code', projectName),
        path.join(config.homeDir, 'code', 'jobs', projectName),
        path.join(config.homeDir, 'code', projectName.replace(/^bugfix-/, '').replace(/-\d{4}-\d{2}-\d{2}$/, ''))
      ];
      return { projectName, possibleRepoPaths };
    }

    return { projectName: null, possibleRepoPaths: [] };
  }

  /**
   * Run Claude Code agent via CLI
   */
  async runClaudeAgent(agentType: string, prompt: string, cwd: string): Promise<{ stdout: string; stderr: string }> {
    logger.info({ agentType, cwd }, 'Running Claude Code agent');

    const result = await execCommand('claude', ['--agent', agentType, '--prompt', prompt], {
      cwd
    });

    if (result.code !== 0) {
      throw new Error(`Agent ${agentType} failed with code ${result.code}: ${result.stderr}`);
    }

    return { stdout: result.stdout, stderr: result.stderr };
  }

  /**
   * Run Claude Code slash command
   */
  async runSlashCommand(command: string, cwd: string): Promise<{ stdout: string; stderr: string }> {
    logger.info({ command, cwd }, 'Running slash command');

    const result = await execCommand('claude', ['--command', command], {
      cwd
    });

    if (result.code !== 0) {
      throw new Error(`Command ${command} failed with code ${result.code}: ${result.stderr}`);
    }

    return { stdout: result.stdout, stderr: result.stderr };
  }

  /**
   * Main job handler - orchestrates the entire bug fix workflow
   */
  async runJobHandler(job: Job): Promise<WorkflowResults> {
    const { markdownFile, projectName, repoPath } = job.data as {
      markdownFile: string;
      projectName: string;
      repoPath: string;
    };

    logger.info({
      jobId: job.id,
      markdownFile,
      projectName,
      repoPath
    }, 'Starting bug fix audit workflow');

    // Create feature branch at job start
    const branchInfo = await this.branchManager.createJobBranch(repoPath, {
      jobId: job.id,
      jobType: 'bugfix-audit',
      description: `automated-audit-${projectName}`
    });

    const branchName = branchInfo?.branchName;
    if (!branchName) {
      throw new Error(`Failed to create git branch for ${projectName}`);
    }

    const outputDir = path.join(this.outputBaseDir, projectName, new Date().toISOString().split('T')[0]);
    await fs.mkdir(outputDir, { recursive: true });

    const results: WorkflowResults = {
      markdownFile,
      projectName,
      repoPath,
      stages: [],
      branchName,
      pullRequestUrl: null,
      timestamp: new Date().toISOString()
    };

    try {
      const markdownContent = await fs.readFile(markdownFile, 'utf-8');

      // Stage 1: bugfix-planner agent
      logStage(logger, '1/5: Running bugfix-planner agent');
      const plannerPrompt = `Analyze this markdown file and create a comprehensive bug fix plan:\n\n${markdownContent}`;
      const plannerResult = await this.runClaudeAgent('bugfix-planner', plannerPrompt, repoPath);
      results.stages.push({ name: 'bugfix-planner', status: 'completed', output: plannerResult.stdout });
      await fs.writeFile(path.join(outputDir, '01-bugfix-plan.md'), plannerResult.stdout);

      // Stage 2: bug-detective plugin
      logStage(logger, '2/5: Running bug-detective plugin');
      const detectiveResult = await this.runSlashCommand('/bug-detective:bug-detective', repoPath);
      results.stages.push({ name: 'bug-detective', status: 'completed', output: detectiveResult.stdout });
      await fs.writeFile(path.join(outputDir, '02-bug-detective-report.md'), detectiveResult.stdout);

      // Stage 3: audit plugin
      logStage(logger, '3/5: Running audit plugin');
      const auditResult = await this.runSlashCommand('/audit:audit', repoPath);
      results.stages.push({ name: 'audit', status: 'completed', output: auditResult.stdout });
      await fs.writeFile(path.join(outputDir, '03-security-audit.md'), auditResult.stdout);

      // Commit audit results
      await this.branchManager.commitChanges(repoPath, {
        message: 'chore(audit): automated bugfix plan, detective report, security audit',
        description: 'Generated with Claude Code AlephAuto',
        jobId: job.id
      });

      // Stage 4: ceo-quality-controller-agent
      logStage(logger, '4/5: Running ceo-quality-controller-agent');
      const qualityPrompt = 'Review all audit reports and validate quality standards before implementing fixes';
      const qualityResult = await this.runClaudeAgent('ceo-quality-controller-agent', qualityPrompt, repoPath);
      results.stages.push({ name: 'ceo-quality-controller', status: 'completed', output: qualityResult.stdout });
      await fs.writeFile(path.join(outputDir, '04-quality-control.md'), qualityResult.stdout);

      // Commit quality control
      await this.branchManager.commitChanges(repoPath, {
        message: 'chore(audit): quality control validation complete',
        description: 'Generated with Claude Code AlephAuto',
        jobId: job.id
      });

      // Stage 5: refractor plugin - implement fixes
      logStage(logger, '5/5: Running refractor plugin to implement fixes');
      const refractorResult = await this.runSlashCommand('/refractor:refractor', repoPath);
      results.stages.push({ name: 'refractor', status: 'completed', output: refractorResult.stdout });
      await fs.writeFile(path.join(outputDir, '05-refactor-implementation.md'), refractorResult.stdout);

      // Commit refactored code
      await this.branchManager.commitChanges(repoPath, {
        message: 'fix: automated refactoring and bug fixes implemented',
        description: 'Generated with Claude Code AlephAuto',
        jobId: job.id
      });

      // Push branch + create PR
      await this.branchManager.pushBranch(repoPath, branchName);

      const prBody = [
        '## Automated Bug Fix Workflow',
        '',
        'This PR was automatically generated by the BugfixAuditWorker (AlephAuto framework).',
        '',
        '### Workflow Stages Completed:',
        ...results.stages.map((stage, i) => `${i + 1}. **${stage.name}**: ${stage.status}`),
        '',
        '### Reports Generated:',
        '- Bug Fix Plan',
        '- Bug Detective Analysis',
        '- Security Audit',
        '- Quality Control Validation',
        '- Refactor Implementation',
        '',
        '### Testing:',
        '- [ ] All automated tests pass',
        '- [ ] Manual review of security audit findings',
        '- [ ] Code quality meets standards',
        '',
        '---',
        '',
        'Generated with [Claude Code](https://claude.com/claude-code) AlephAuto'
      ].join('\n');

      const prUrl = await this.branchManager.createPullRequest(repoPath, {
        branchName,
        title: `fix: automated bug fixes for ${projectName}`,
        body: prBody,
        labels: ['automated', 'bugfix']
      });

      results.pullRequestUrl = prUrl;
      logger.info({ prUrl }, 'Pull request created');

      // Save final results summary
      await fs.writeFile(path.join(outputDir, 'workflow-summary.json'), JSON.stringify(results, null, FORMATTING.JSON_INDENT));

      return results;
    } catch (error) {
      logError(logger, error as Error, 'Bug fix workflow failed', { jobId: job.id });

      await fs.writeFile(
        path.join(outputDir, 'workflow-error.json'),
        JSON.stringify({ ...results, error: (error as Error).message, stack: (error as Error).stack }, null, FORMATTING.JSON_INDENT)
      );

      throw error;
    }
  }

  /**
   * Create a single bugfix job for a specific markdown file
   */
  createBugfixJob(markdownFile: string, projectName: string, repoPath: string): Job {
    const jobId = `bugfix-${projectName}-${Date.now()}`;
    return this.createJob(jobId, {
      markdownFile,
      projectName,
      repoPath
    });
  }

  /**
   * Create jobs for all markdown files in the active docs directory
   */
  async createJobsForAllMarkdownFiles(): Promise<Job[]> {
    const markdownFiles = await this.findMarkdownFiles();

    logger.info({ count: markdownFiles.length }, 'Creating jobs for markdown files');

    const jobs: Job[] = [];

    for (const markdownFile of markdownFiles) {
      const { projectName, possibleRepoPaths } = this.getRepositoryFromPath(markdownFile);

      if (!projectName) {
        logger.warn({ markdownFile }, 'Could not determine project name, skipping');
        continue;
      }

      // Find the first existing repo path
      let repoPath: string | null = null;
      for (const possiblePath of possibleRepoPaths) {
        try {
          await fs.access(possiblePath);
          repoPath = possiblePath;
          break;
        } catch {
          // Path doesn't exist, try next
        }
      }

      if (!repoPath) {
        logger.warn({ markdownFile, possibleRepoPaths }, 'Could not find repository, skipping');
        continue;
      }

      // Check if it's a git repository
      try {
        await fs.access(path.join(repoPath, '.git'));
      } catch {
        logger.warn({ repoPath }, 'Not a git repository, skipping');
        continue;
      }

      const job = this.createBugfixJob(markdownFile, projectName, repoPath);
      jobs.push(job);
    }

    logger.info({ jobCount: jobs.length }, 'Jobs created');
    return jobs;
  }
}

// file: sidequest/workers/schema-enhancement-worker.ts
/**
 * SchemaEnhancementWorker - Enhances README files with Schema.org markup
 */

import { SidequestServer, type Job, type SidequestServerOptions } from '../core/server.ts';
import { SchemaMCPTools, type SchemaObject } from '../utils/schema-mcp-tools.ts';
import { generateReport } from '../utils/report-generator.ts';
import { createComponentLogger } from '../utils/logger.ts';
import { config } from '../core/config.ts';
import { FORMATTING, LIMITS, MAX_SCORE } from '../core/constants.ts';
import fs from 'fs/promises';
import path from 'path';

const logger = createComponentLogger('SchemaEnhancementWorker');

// Type definitions

interface SchemaEnhancementWorkerOptions extends SidequestServerOptions {
  outputBaseDir?: string;
  dryRun?: boolean;
  mcpServerUrl?: string;
  useRealMCP?: boolean;
}

interface EnhancementJobData {
  readmePath: string;
  relativePath: string;
  repositoryPath: string | null;
  repository: string | null;
  context: Record<string, unknown>;
  type?: string;
}

interface SchemaValidation {
  valid: boolean;
  errors: string[];
  warnings: string[];
}

interface SchemaImpact {
  impactScore: number;
  rating: string;
  seoImprovements: string[];
  richResultsEligibility: string[];
  timestamp: string;
  schemaType: string;
  metrics: Record<string, unknown>;
}

interface EnhancementResult {
  status: string;
  reason?: string;
  readmePath: string;
  relativePath: string;
  schemaType?: string;
  schema?: SchemaObject;
  impact?: SchemaImpact;
  validation?: SchemaValidation;
  timestamp?: string;
  reportPaths?: unknown;
}

interface ReadmeInfo {
  fullPath: string;
  relativePath: string;
  dirPath: string;
}

interface EnhancementStats {
  enhanced: number;
  skipped: number;
  failed: number;
  total: number;
  successRate: string | number;
}

interface EnhancementSummary {
  timestamp: string;
  enhancement: EnhancementStats;
  jobs: unknown;
  outputDirectory: string;
}

export class SchemaEnhancementWorker extends SidequestServer {
  outputBaseDir: string;
  mcpTools: SchemaMCPTools;
  dryRun: boolean;
  stats: {
    enhanced: number;
    skipped: number;
    failed: number;
  };

  /**
   * constructor.
   */
  constructor(options: SchemaEnhancementWorkerOptions = {}) {
    // Enable git workflow with schema-specific settings
    super({
      ...options,
      jobType: 'schema-enhancement',
      gitWorkflowEnabled: options.gitWorkflowEnabled ?? config.enableGitWorkflow,
      gitBranchPrefix: options.gitBranchPrefix ?? config.gitBranchPrefix ?? 'docs',
      gitBaseBranch: options.gitBaseBranch ?? config.gitBaseBranch,
      gitDryRun: options.gitDryRun ?? config.gitDryRun
    });

    this.outputBaseDir = options.outputBaseDir ?? './document-enhancement-impact-measurement';
    this.mcpTools = new SchemaMCPTools({ mcpServerUrl: options.mcpServerUrl, useRealMCP: options.useRealMCP });
    this.dryRun = options.dryRun ?? false;
    this.stats = {
      enhanced: 0,
      skipped: 0,
      failed: 0
    };
  }

  /**
   * Run enhancement for a specific README file
   */
  async runJobHandler(job: Job): Promise<EnhancementResult> {
    const startTime = Date.now();
    const { readmePath, relativePath, context } = job.data as unknown as EnhancementJobData;

    logger.info({ jobId: job.id, readmePath }, 'Enhancing README');

    try {
      // Read README content
      const originalContent = await fs.readFile(readmePath, 'utf-8');

      // Check if already has schema
      if (originalContent.includes('<script type='application/ld+json'>')) {
        logger.info({ jobId: job.id }, 'Skipped - already has schema markup');
        this.stats.skipped++;
        return {
          status: 'skipped',
          reason: 'Already has schema markup',
          readmePath,
          relativePath
        };
      }

      // Get appropriate schema type
      const schemaType = await this.mcpTools.getSchemaType(
        readmePath,
        originalContent,
        context
      ) as string;

      logger.info({ jobId: job.id, schemaType }, 'Schema type detected');

      // Generate schema markup
      const schema = await this.mcpTools.generateSchema(
        readmePath,
        originalContent,
        context,
        schemaType
      ) as SchemaObject;

      // Validate schema
      const validation = await this.mcpTools.validateSchema(schema) as SchemaValidation;
      if (!validation.valid) {
        throw new Error(`Schema validation failed: ${validation.errors.join(', ')}`);
      }

      if (validation.warnings.length > 0) {
        logger.warn({
          jobId: job.id,
          warnings: validation.warnings
        }, 'Schema validation warnings');
      }

      // Inject schema into content
      const enhancedContent = this.mcpTools.injectSchema(originalContent, schema) as string;

      // Analyze impact
      const impact = await this.mcpTools.analyzeSchemaImpact(
        originalContent,
        enhancedContent,
        schema
      ) as unknown as SchemaImpact;

      logger.info({
        jobId: job.id,
        impactScore: impact.impactScore,
        rating: impact.rating
      }, 'Impact analysis complete');

      // Save enhanced README
      if (!this.dryRun) {
        await fs.writeFile(readmePath, enhancedContent, 'utf-8');
        logger.info({ jobId: job.id }, 'Enhanced README saved');
      } else {
        logger.info({ jobId: job.id }, 'Dry run - no changes made');
      }

      // Save impact report
      await this.saveImpactReport(relativePath, schema, impact);

      // Save enhanced copy to output directory
      await this.saveEnhancedCopy(relativePath, enhancedContent);

      this.stats.enhanced++;

      const result: EnhancementResult = {
        status: 'enhanced',
        readmePath,
        relativePath,
        schemaType,
        schema,
        impact,
        validation,
        timestamp: new Date().toISOString()
      };

      // Generate HTML/JSON reports
      const endTime = Date.now();
      const reportPaths = await generateReport({
        jobId: job.id,
        jobType: 'schema-enhancement',
        status: 'completed',
        result,
        startTime,
        endTime,
        parameters: job.data,
        metadata: {
          schemaType,
          impactScore: impact.impactScore,
          rating: impact.rating
        }
      });

      result.reportPaths = reportPaths;
      logger.info({ reportPaths }, 'Schema enhancement reports generated');

      return result;

    } catch (error) {
      this.stats.failed++;
      throw error;
    }
  }

  /**
   * Save impact report to output directory
   */
  async saveImpactReport(relativePath: string, schema: SchemaObject, impact: SchemaImpact): Promise<void> {
    const reportDir = path.join(
      this.outputBaseDir,
      'impact-reports',
      path.dirname(relativePath)
    );

    await fs.mkdir(reportDir, { recursive: true });

    const reportPath = path.join(
      reportDir,
      `${path.basename(relativePath, '.md')}-impact.json`
    );

    const report = {
      relativePath,
      schema,
      impact,
      timestamp: new Date().toISOString()
    };

    await fs.writeFile(reportPath, JSON.stringify(report, null, FORMATTING.JSON_INDENT));
  }

  /**
   * Save enhanced copy to output directory
   */
  async saveEnhancedCopy(relativePath: string, enhancedContent: string): Promise<void> {
    const outputDir = path.join(
      this.outputBaseDir,
      'enhanced-readmes',
      path.dirname(relativePath)
    );

    await fs.mkdir(outputDir, { recursive: true });

    const outputPath = path.join(outputDir, path.basename(relativePath));

    await fs.writeFile(outputPath, enhancedContent, 'utf-8');
  }

  /**
   * Find git repository root from a directory path
   * Walks up the directory tree until .git is found
   */
  async findGitRoot(startPath: string): Promise<string | null> {
    let currentPath = startPath;
    const root = path.parse(currentPath).root;

    while (currentPath !== root) {
      try {
        const gitPath = path.join(currentPath, '.git');
        const stats = await fs.stat(gitPath);

        if (stats.isDirectory()) {
          return currentPath;
        }
      } catch {
        // .git not found, continue up
      }

      currentPath = path.dirname(currentPath);
    }

    // No git repository found
    return null;
  }

  /**
   * Create an enhancement job for a README
   */
  async createEnhancementJob(readme: ReadmeInfo, context: Record<string, unknown>): Promise<Job> {
    const jobId = `schema-${readme.relativePath.replace(/\//g, '-')}-${Date.now()}`;

    // Find git repository root for this README
    const repositoryPath = await this.findGitRoot(readme.dirPath);

    return this.createJob(jobId, {
      readmePath: readme.fullPath,
      relativePath: readme.relativePath,
      repositoryPath, // Add repository path for git workflow
      repository: repositoryPath ? path.basename(repositoryPath) : null,
      context,
      type: 'schema-enhancement'
    });
  }

  /**
   * Generate commit message for schema enhancement
   */
  public async _generateCommitMessage(job: Job): Promise<{ title: string; body: string }> {
    const { relativePath } = job.data as unknown as EnhancementJobData;
    const result = job.result as EnhancementResult | undefined;
    const impact = result?.impact;

    const title = `docs: add Schema.org structured data to ${path.basename(relativePath)}`;

    const bodyParts = [
      'Added Schema.org JSON-LD markup to enhance SEO and enable rich results.',
      ''
    ];

    if (result?.schemaType) {
      bodyParts.push(`- Schema type: ${result.schemaType}`);
    }

    if (impact) {
      bodyParts.push(
        `- Impact score: ${impact.impactScore}/100 (${impact.rating})`,
        `- ${impact.seoImprovements.length} SEO improvements: ${impact.seoImprovements.slice(0, LIMITS.SHORT_PREVIEW_COUNT).join(', ')}${impact.seoImprovements.length > LIMITS.SHORT_PREVIEW_COUNT ? '...' : ''}`
      );

      if (impact.richResultsEligibility.length > 0) {
        bodyParts.push(`- Eligible for ${impact.richResultsEligibility.join(', ')} rich results in search engines`);
      }
    }

    return {
      title,
      body: bodyParts.join('\n')
    };
  }

  /**
   * Generate PR context for schema enhancement
   */
  public async _generatePRContext(job: Job, commitMessage?: { title: string; body: string }): Promise<{
    branchName: string;
    title: string;
    body: string;
    labels: string[];
  }> {
    const msg = commitMessage ?? await this._generateCommitMessage(job);
    const { relativePath } = job.data as unknown as EnhancementJobData;
    const result = job.result as EnhancementResult | undefined;
    const impact = result?.impact;
    const schema = result?.schema;

    const bodyParts = [
      '## Summary',
      '',
      `This PR adds Schema.org structured data to \`${relativePath}\` to improve SEO and enable rich search results.`,
      ''
    ];

    if (impact) {
      bodyParts.push(
        '## Impact Analysis',
        '',
        `- **Impact Score**: ${impact.impactScore}/100 (${impact.rating})`,
        `- **SEO Improvements**: ${impact.seoImprovements.length}`,
        ''
      );

      if (impact.seoImprovements.length > 0) {
        bodyParts.push(
          '### SEO Enhancements',
          ...impact.seoImprovements.map(imp => `- ${imp}`),
          ''
        );
      }

      if (impact.richResultsEligibility.length > 0) {
        bodyParts.push(
          '### Rich Results Eligibility',
          ...impact.richResultsEligibility.map(r => `- ${r}`),
          ''
        );
      }
    }

    if (schema) {
      bodyParts.push(
        '## Schema Details',
        '',
        `- **Type**: \`${schema['@type']}\``,
        `- **Properties**: ${Object.keys(schema).length} properties defined`,
        ''
      );
    }

    bodyParts.push(
      '## Testing',
      '',
      '- [ ] Validate schema markup using [Google Rich Results Test](https://search.google.com/test/rich-results)',
      '- [ ] Verify structured data using [Schema.org validator](https://validator.schema.org/)',
      '',
      '---',
      '',
      'Generated with [Claude Code](https://claude.com/claude-code)'
    );

    return {
      branchName: job.git.branchName ?? '',
      title: msg.title,
      body: bodyParts.join('\n'),
      labels: ['documentation', 'seo', 'schema-org', 'automated']
    };
  }

  /**
   * Get enhancement statistics
   */
  getEnhancementStats(): EnhancementStats {
    return {
      ...this.stats,
      total: this.stats.enhanced + this.stats.skipped + this.stats.failed,
      successRate: this.stats.enhanced > 0
        ? ((this.stats.enhanced / (this.stats.enhanced + this.stats.failed)) * MAX_SCORE).toFixed(FORMATTING.DECIMAL_PLACES)
        : 0
    };
  }

  /**
   * Generate enhancement summary report
   */
  async generateSummaryReport(): Promise<EnhancementSummary> {
    const stats = this.getEnhancementStats();
    const jobStats = this.getStats();

    const summary: EnhancementSummary = {
      timestamp: new Date().toISOString(),
      enhancement: stats,
      jobs: jobStats,
      outputDirectory: this.outputBaseDir
    };

    const summaryPath = path.join(
      this.outputBaseDir,
      `enhancement-summary-${Date.now()}.json`
    );

    await fs.mkdir(this.outputBaseDir, { recursive: true });
    await fs.writeFile(summaryPath, JSON.stringify(summary, null, FORMATTING.JSON_INDENT));

    return summary;
  }
}

