import { SidequestServer } from '../core/server.ts';
import { generateReport } from '../utils/report-generator.ts';
import { createComponentLogger } from '../utils/logger.ts';
import * as Sentry from '@sentry/node';
import { execCommandOrThrow } from '@shared/process-io';
import path from 'path';
import os from 'os';
import type { Job } from '../core/server.ts';
import { LIMITS, NUMBER_BASE, TIMEOUTS } from '../core/constants.ts';

const logger = createComponentLogger('DashboardPopulateWorker');

const DASHBOARD_DIR = path.join(os.homedir(), '.claude', 'mcp-servers', 'observability-toolkit', 'dashboard');
const TOOLKIT_DIR = path.join(os.homedir(), '.claude', 'mcp-servers', 'observability-toolkit');

interface PopulateOptions {
  seed?: boolean;
  dryRun?: boolean;
  skipJudge?: boolean;
  skipSync?: boolean;
  limit?: number;
}

export interface PopulateWorkerOptions {
  maxConcurrent?: number;
  dashboardDir?: string;
  toolkitDir?: string;
  [key: string]: unknown;
}

interface StepTiming {
  name: string;
  ms: number;
}

interface PopulateOutput {
  seed: boolean;
  dryRun: boolean;
  skipJudge: boolean;
  skipSync: boolean;
  limit: number | undefined;
  steps: StepTiming[];
  durationMs: number;
  stdout: string;
  stderr: string;
  timestamp: string;
  reportPaths?: object;
}

/**
 * DashboardPopulateWorker - Runs the quality-metrics-dashboard populate pipeline
 */
export class DashboardPopulateWorker extends SidequestServer {
  dashboardDir: string;
  toolkitDir: string;

  /**
   * constructor.
   */
  constructor(options: PopulateWorkerOptions = {}) {
    super({
      ...options,
      jobType: 'dashboard-populate'
    });
    this.dashboardDir = options.dashboardDir ?? DASHBOARD_DIR;
    this.toolkitDir = options.toolkitDir ?? TOOLKIT_DIR;
  }

  /**
   * Create a populate job
   */
  createPopulateJob(options: PopulateOptions = {}): Job {
    const jobId = `dashboard-populate-${Date.now()}`;
    return this.createJob(jobId, {
      type: 'populate',
      seed: options.seed ?? true,
      dryRun: options.dryRun ?? false,
      skipJudge: options.skipJudge ?? false,
      skipSync: options.skipSync ?? false,
      limit: options.limit
    });
  }

  /**
   * Run the populate pipeline
   */
  async runJobHandler(job: Job): Promise<PopulateOutput> {
    const startTime = Date.now();
    const seed = job.data.seed as boolean;
    const dryRun = job.data.dryRun as boolean;
    const skipJudge = job.data.skipJudge as boolean;
    const skipSync = job.data.skipSync as boolean;
    const limit = job.data.limit as number | undefined;

    logger.info({
      jobId: job.id,
      seed,
      dryRun,
      skipJudge,
      skipSync,
      limit
    }, 'Running dashboard populate job');

    try {
      // Build parent toolkit first (sync-to-kv imports from dist/)
      if (!skipSync) {
        logger.info({ jobId: job.id }, 'Building parent observability-toolkit');
        await execCommandOrThrow('npm', ['run', 'build'], {
          cwd: this.toolkitDir
        });
      }

      // Build populate args
      const populateArgs = ['run', 'populate', '--'];
      if (seed) populateArgs.push('--seed');
      if (dryRun) populateArgs.push('--dry-run');
      if (skipJudge) populateArgs.push('--skip-judge');
      if (skipSync) populateArgs.push('--skip-sync');
      if (limit) populateArgs.push('--limit', String(limit));

      logger.info({
        jobId: job.id,
        command: `npm ${populateArgs.join(' ')}`,
        cwd: this.dashboardDir
      }, 'Executing populate pipeline');

      const { stdout, stderr } = await execCommandOrThrow('npm', populateArgs, {
        cwd: this.dashboardDir,
        timeout: TIMEOUTS.FIVE_MINUTES_MS,
        env: { ...process.env, FORCE_COLOR: '0' }
      });

      const stepTimings = this.#parseTimings(stdout);

      const endTime = Date.now();
      const output: PopulateOutput = {
        seed,
        dryRun,
        skipJudge,
        skipSync,
        limit,
        steps: stepTimings,
        durationMs: endTime - startTime,
        stdout: stdout.slice(-(2 * LIMITS.MAX_OUTPUT_CHARS)),
        stderr: stderr.slice(-LIMITS.MAX_OUTPUT_CHARS),
        timestamp: new Date().toISOString()
      };

      logger.info({
        jobId: job.id,
        durationMs: output.durationMs,
        steps: stepTimings.length
      }, 'Dashboard populate job completed');

      const reportPaths = await generateReport({
        jobId: job.id,
        jobType: 'dashboard-populate',
        status: 'completed',
        result: output,
        startTime,
        endTime,
        parameters: job.data,
        metadata: { steps: stepTimings }
      });

      output.reportPaths = reportPaths;
      return output;
    } catch (error) {
      logger.error({
        jobId: job.id,
        error: (error as Error).message,
        stderr: (error as { stderr?: string }).stderr?.slice(-LIMITS.MAX_OUTPUT_CHARS)
      }, 'Dashboard populate job failed');

      Sentry.captureException(error, {
        tags: {
          component: 'dashboard-populate-worker',
          job_id: job.id
        },
        extra: { seed, dryRun, skipJudge, skipSync }
      });

      throw error;
    }
  }

  /**
   * Parse step timings from populate-dashboard.ts stdout
   */
  #parseTimings(stdout: string): StepTiming[] {
    const timings: StepTiming[] = [];
    const lines = stdout.split('\n');
    for (const line of lines) {
      const match = line.match(/^\s{2}(\S+)\s+(\d+)ms$/);
      if (match && match[1] !== 'total') {
        timings.push({ name: match[1], ms: parseInt(match[2], NUMBER_BASE.DECIMAL) });
      }
    }
    return timings;
  }
}

// file: sidequest/workers/repo-cleanup-worker.ts
/**
 * RepoCleanupWorker - Executes repository cleanup jobs
 *
 * Integrates universal-repo-cleanup.sh into the AlephAuto framework,
 * providing job queue management, event tracking, and Sentry error monitoring.
 *
 * Cleanup targets:
 * - Python virtual environments (venv, .venv, etc.)
 * - Temporary/cache files (.DS_Store, __pycache__, .swp)
 * - Build artifacts (.jekyll-cache, dist, build, node_modules/.cache)
 * - Output files (repomix-output.xml, *.log)
 * - Redundant directories (drafts, temp, tmp, backup)
 */

import { SidequestServer, type Job, type SidequestServerOptions } from '../core/server.ts';
import { generateReport } from '../utils/report-generator.ts';
import { createComponentLogger } from '../utils/logger.ts';
import * as Sentry from '@sentry/node';
import { execFile, spawn } from 'child_process';
import { promisify } from 'util';
import path from 'path';
import os from 'os';
import fs from 'fs/promises';
import { fileURLToPath } from 'url';
import { BYTES_PER_KB, LIMITS, NUMBER_BASE } from '../core/constants.ts';

const execFileAsync = promisify(execFile);
const logger = createComponentLogger('RepoCleanupWorker');

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

// Type definitions

interface RepoCleanupWorkerOptions extends SidequestServerOptions {
  baseDir?: string;
}

interface CleanupJobData {
  targetDir?: string;
  dryRun?: boolean;
  type?: string;
}

interface ScanCategories {
  venvs: string[];
  tempFiles: string[];
  outputFiles: string[];
  buildArtifacts: string[];
  redundantDirs: string[];
}

interface CleanupSummary {
  venvs: number;
  tempFiles: number;
  outputFiles: number;
  buildArtifacts: number;
  redundantDirs: number;
}

interface ScanResult {
  categories: ScanCategories;
  totalItems: number;
  summary: CleanupSummary;
}

interface CleanupResult {
  totalItems: number;
  summary: CleanupSummary;
  rawOutput: string;
}

interface CleanupOutput {
  targetDir: string;
  dryRun: boolean;
  initialSize: string;
  finalSize: string;
  savedSpace: string;
  totalItems: number;
  summary: CleanupSummary;
  categories?: ScanCategories;
  rawOutput?: string;
  timestamp: string;
  reportPaths?: unknown;
}

interface CleanupJobOptions {
  dryRun?: boolean;
}

export class RepoCleanupWorker extends SidequestServer {
  baseDir: string;
  scriptPath: string;

  /**
   * constructor.
   */
  constructor(options: RepoCleanupWorkerOptions = {}) {
    super({
      ...options,
      jobType: 'repo-cleanup'
    });
    this.baseDir = options.baseDir ?? path.join(os.homedir(), 'code');
    this.scriptPath = path.join(__dirname, '../pipeline-runners/universal-repo-cleanup.sh');
  }

  /**
   * Run repository cleanup job
   */
  async runJobHandler(job: Job): Promise<CleanupOutput> {
    const startTime = Date.now();
    const {
      targetDir = this.baseDir,
      dryRun = false
    } = job.data as unknown as CleanupJobData;

    logger.info({
      jobId: job.id,
      targetDir,
      dryRun
    }, 'Running repository cleanup job');

    try {
      // Check script exists
      await fs.access(this.scriptPath);

      // Get initial size
      const initialSize = await this.getDirectorySize(targetDir);

      let result: ScanResult | CleanupResult;
      if (dryRun) {
        // Scan only, don't clean
        result = await this.scanRepository(targetDir);
      } else {
        // Run actual cleanup
        result = await this.runCleanup(targetDir);
      }

      // Get final size
      const finalSize = await this.getDirectorySize(targetDir);

      const output: CleanupOutput = {
        targetDir,
        dryRun,
        initialSize,
        finalSize,
        savedSpace: dryRun ? 'N/A (dry run)' : this.formatSizeDiff(initialSize, finalSize),
        ...result,
        timestamp: new Date().toISOString()
      };

      logger.info({
        jobId: job.id,
        targetDir,
        initialSize,
        finalSize,
        itemsFound: result.totalItems
      }, 'Repository cleanup job completed');

      // Generate HTML/JSON reports
      const endTime = Date.now();
      const reportPaths = await generateReport({
        jobId: job.id,
        jobType: 'repo-cleanup',
        status: 'completed',
        result: output,
        startTime,
        endTime,
        parameters: job.data,
        metadata: {
          targetDir,
          dryRun,
          totalItems: result.totalItems
        }
      });

      output.reportPaths = reportPaths;
      logger.info({ reportPaths }, 'Repository cleanup reports generated');

      return output;
    } catch (error) {
      logger.error({
        jobId: job.id,
        error: (error as Error).message,
        stack: (error as Error).stack
      }, 'Repository cleanup job failed');

      Sentry.captureException(error, {
        tags: {
          component: 'repo-cleanup-worker',
          job_id: job.id
        },
        extra: {
          targetDir,
          dryRun
        }
      });

      throw error;
    }
  }

  /**
   * Scan repository without cleaning
   */
  private async scanRepository(targetDir: string): Promise<ScanResult> {
    const categories: ScanCategories = {
      venvs: [],
      tempFiles: [],
      outputFiles: [],
      buildArtifacts: [],
      redundantDirs: []
    };

    // Python venvs
    const venvPatterns = ['venv', '.venv', 'env', 'virtualenv'];
    for (const pattern of venvPatterns) {
      try {
        const { stdout } = await execFileAsync('find', [
          targetDir, '-maxdepth', '3', '-type', 'd', '-name', pattern
        ], { maxBuffer: LIMITS.MAX_BUFFER_MB * BYTES_PER_KB * BYTES_PER_KB });
        const dirs = stdout.trim().split('\n').filter(Boolean);
        categories.venvs.push(...dirs);
      } catch {
        // Pattern not found
      }
    }

    // Temp files
    const tempPatterns = ['.DS_Store', '__pycache__', '*.pyc', '*.swp'];
    for (const pattern of tempPatterns) {
      try {
        const { stdout } = await execFileAsync('find', [
          targetDir, '-name', pattern
        ], { maxBuffer: LIMITS.MAX_BUFFER_MB * BYTES_PER_KB * BYTES_PER_KB });
        const files = stdout.trim().split('\n').filter(Boolean);
        categories.tempFiles.push(...files);
      } catch {
        // Pattern not found
      }
    }

    // Build artifacts
    const buildArtifacts = ['.jekyll-cache', 'dist', 'build', '.next', 'node_modules/.cache'];
    for (const artifact of buildArtifacts) {
      const artifactPath = path.join(targetDir, artifact);
      try {
        await fs.access(artifactPath);
        categories.buildArtifacts.push(artifactPath);
      } catch {
        // Not found
      }
    }

    // Redundant dirs
    const redundantDirs = ['drafts', 'temp', 'tmp', 'backup', 'backups'];
    for (const dir of redundantDirs) {
      const dirPath = path.join(targetDir, dir);
      try {
        await fs.access(dirPath);
        categories.redundantDirs.push(dirPath);
      } catch {
        // Not found
      }
    }

    const totalItems = Object.values(categories).reduce((sum, arr) => sum + arr.length, 0);

    return {
      categories,
      totalItems,
      summary: {
        venvs: categories.venvs.length,
        tempFiles: categories.tempFiles.length,
        outputFiles: categories.outputFiles.length,
        buildArtifacts: categories.buildArtifacts.length,
        redundantDirs: categories.redundantDirs.length
      }
    };
  }

  /**
   * Run actual cleanup using bash script
   */
  private async runCleanup(targetDir: string): Promise<CleanupResult> {
    return await new Promise<CleanupResult>((resolve, reject) => {
      const proc = spawn(this.scriptPath, [targetDir], {
        stdio: ['pipe', 'pipe', 'pipe'],
        env: process.env
      });

      let stdout = '';
      let stderr = '';

      proc.stdout.on('data', (chunk) => {
        stdout += String(chunk);
      });
      proc.stderr.on('data', (chunk) => {
        stderr += String(chunk);
      });

      proc.on('error', (error) => {
        reject(error);
      });

      proc.on('close', (code) => {
        if (stderr) {
          logger.warn({ stderr }, 'Cleanup script stderr');
        }
        if (code !== 0) {
          const error = new Error(`Cleanup script exited with code ${code}`) as Error & {
            code: number | null;
            stdout: string;
            stderr: string;
          };
          error.code = code;
          error.stdout = stdout;
          error.stderr = stderr;
          reject(error);
          return;
        }

        resolve(this.parseCleanupOutput(stdout));
      });

      proc.stdin.write('yes\n');
      proc.stdin.end();
    });
  }

  /**
   * Parse cleanup script output
   */
  private parseCleanupOutput(output: string): CleanupResult {
    const summary: CleanupSummary = {
      venvs: 0,
      tempFiles: 0,
      outputFiles: 0,
      buildArtifacts: 0,
      redundantDirs: 0
    };

    // Extract counts from output
    const venvMatch = output.match(/Removed (\d+) virtual environment/);
    if (venvMatch) summary.venvs = parseInt(venvMatch[1], NUMBER_BASE.DECIMAL);

    const tempMatch = output.match(/Removed (\d+) temporary file/);
    if (tempMatch) summary.tempFiles = parseInt(tempMatch[1], NUMBER_BASE.DECIMAL);

    const outputMatch = output.match(/Removed (\d+) output file/);
    if (outputMatch) summary.outputFiles = parseInt(outputMatch[1], NUMBER_BASE.DECIMAL);

    const buildMatch = output.match(/Removed (\d+) build artifact/);
    if (buildMatch) summary.buildArtifacts = parseInt(buildMatch[1], NUMBER_BASE.DECIMAL);

    const dirMatch = output.match(/Removed (\d+) redundant director/);
    if (dirMatch) summary.redundantDirs = parseInt(dirMatch[1], NUMBER_BASE.DECIMAL);

    const totalItems = Object.values(summary).reduce((sum, val) => sum + val, 0);

    return {
      totalItems,
      summary,
      rawOutput: output
    };
  }

  /**
   * Get directory size
   */
  private async getDirectorySize(dirPath: string): Promise<string> {
    try {
      const { stdout } = await execFileAsync('du', ['-sh', dirPath]);
      return stdout.trim().split('\t')[0] ?? 'N/A';
    } catch {
      return 'N/A';
    }
  }

  /**
   * Format size difference
   */
  private formatSizeDiff(initial: string, final: string): string {
    // Simple string comparison for now
    return `${initial} -> ${final}`;
  }

  /**
   * Create a job to clean a specific repository
   */
  createCleanupJob(targetDir?: string, options: CleanupJobOptions = {}): Job {
    const jobId = `repo-cleanup-${Date.now()}`;

    return this.createJob(jobId, {
      type: 'repo-cleanup',
      targetDir: targetDir ?? this.baseDir,
      dryRun: options.dryRun ?? false
    });
  }

  /**
   * Create a dry-run job to preview cleanup
   */
  createDryRunJob(targetDir?: string, _options: CleanupJobOptions = {}): Job {
    const jobId = `repo-cleanup-dryrun-${Date.now()}`;

    return this.createJob(jobId, {
      type: 'repo-cleanup',
      targetDir: targetDir ?? this.baseDir,
      dryRun: true
    });
  }
}

