import test from 'node:test';
import assert from 'node:assert/strict';
import fs from 'fs/promises';
import os from 'os';
import path from 'path';
import { RepoCleanupWorker } from './repo-cleanup-worker.ts';

test('runCleanup treats targetDir as a literal path (no shell interpolation)', async (t) => {
  const tmpRoot = await fs.mkdtemp(path.join(os.tmpdir(), 'repo-cleanup-worker-'));
  const markerFile = `repo-cleanup-injection-marker-${Date.now()}`;
  const markerPath = path.join(process.cwd(), markerFile);
  const injectedDir = path.join(tmpRoot, `repo-$(touch ${markerFile})`);

  await fs.rm(markerPath, { force: true });
  await fs.mkdir(injectedDir, { recursive: true });

  t.after(async () => {
    await fs.rm(markerPath, { force: true });
    await fs.rm(tmpRoot, { recursive: true, force: true });
  });

  const worker = new RepoCleanupWorker({ autoStart: false, baseDir: tmpRoot });
  worker.stop();

  const result = await (
    worker as unknown as { runCleanup: (targetDir: string) => Promise<{ totalItems: number }> }
  ).runCleanup(injectedDir);

  assert.equal(result.totalItems, 0);
  await assert.rejects(
    fs.access(markerPath),
    /ENOENT/
  );
});

test('runCleanup succeeds when only temp files are detected', async (t) => {
  const tmpRoot = await fs.mkdtemp(path.join(os.tmpdir(), 'repo-cleanup-temp-only-'));
  const targetDir = path.join(tmpRoot, 'repo');
  const tempFile = path.join(targetDir, '__pycache__', 'a.pyc');

  await fs.mkdir(path.dirname(tempFile), { recursive: true });
  await fs.writeFile(tempFile, 'x');

  t.after(async () => {
    await fs.rm(tmpRoot, { recursive: true, force: true });
  });

  const worker = new RepoCleanupWorker({ autoStart: false, baseDir: tmpRoot });
  worker.stop();

  const result = await (
    worker as unknown as {
      runCleanup: (targetDir: string) => Promise<{ totalItems: number; summary: { tempFiles: number } }>;
    }
  ).runCleanup(targetDir);

  assert.ok(result.totalItems >= 1);
  assert.ok(result.summary.tempFiles >= 1);
  await assert.rejects(
    fs.access(tempFile),
    /ENOENT/
  );
});

// file: sidequest/workers/gitignore-worker.ts
/**
 * GitignoreWorker - Executes gitignore update jobs
 *
 * Integrates GitignoreRepomixUpdater into the AlephAuto framework,
 * providing job queue management, event tracking, and Sentry error monitoring.
 */

import { SidequestServer, type Job, type SidequestServerOptions } from '../core/server.ts';
import { GitignoreRepomixUpdater } from '../utils/gitignore-repomix-updater.ts';
import { generateReport } from '../utils/report-generator.ts';
import { createComponentLogger } from '../utils/logger.ts';
import { LIMITS } from '../core/constants.ts';
import * as Sentry from '@sentry/node';
import path from 'path';
import os from 'os';

const logger = createComponentLogger('GitignoreWorker');

// Type definitions

interface GitignoreWorkerOptions extends SidequestServerOptions {
  baseDir?: string;
  excludeDirs?: string[];
  maxDepth?: number;
  gitignoreEntry?: string;
}

interface GitignoreJobData {
  baseDir?: string;
  excludeDirs?: string[];
  maxDepth?: number;
  gitignoreEntry?: string;
  dryRun?: boolean;
  repositories?: string[] | null;
  type?: string;
}

interface RepositoryResult {
  repository: string;
  action: string;
  reason?: string;
  [key: string]: unknown;
}

interface ProcessSummary {
  added: number;
  skipped: number;
  would_add: number;
  error: number;
  [key: string]: unknown;
}

interface ProcessResults {
  totalRepositories: number;
  results: RepositoryResult[];
  summary: ProcessSummary;
}

interface GitignoreUpdateResult extends ProcessResults {
  timestamp: string;
  dryRun: boolean;
  gitignoreEntry: string;
  reportPaths?: unknown;
}

interface UpdateJobOptions {
  baseDir?: string;
  dryRun?: boolean;
  gitignoreEntry?: string;
  excludeDirs?: string[];
  maxDepth?: number;
  repositories?: string[];
}

export class GitignoreWorker extends SidequestServer {
  baseDir: string;
  excludeDirs: string[];
  maxDepth: number;
  gitignoreEntry: string;

  /**
   * constructor.
   */
  constructor(options: GitignoreWorkerOptions = {}) {
    super({
      ...options,
      jobType: 'gitignore-manager'
    });
    this.baseDir = options.baseDir ?? path.join(os.homedir(), 'code');
    this.excludeDirs = options.excludeDirs ?? [
      'node_modules',
      '.git',
      'dist',
      'build',
      'coverage',
      '.next',
      '.nuxt',
      'vendor',
      '__pycache__',
      '.venv',
      'venv'
    ];
    this.maxDepth = options.maxDepth ?? LIMITS.DEFAULT_MAX_DEPTH;
    this.gitignoreEntry = options.gitignoreEntry ?? 'repomix-output.xml';
  }

  /**
   * Run gitignore update job
   */
  async runJobHandler(job: Job): Promise<GitignoreUpdateResult> {
    const startTime = Date.now();
    const {
      baseDir = this.baseDir,
      excludeDirs = this.excludeDirs,
      maxDepth = this.maxDepth,
      gitignoreEntry = this.gitignoreEntry,
      dryRun = false,
      repositories = null, // Optional: specific repositories to process
    } = job.data as unknown as GitignoreJobData;

    logger.info({
      jobId: job.id,
      baseDir,
      dryRun,
      specificRepos: repositories ? repositories.length : 'all'
    }, 'Running gitignore update job');

    try {
      // Create updater instance
      const updater = new GitignoreRepomixUpdater({
        baseDir,
        excludeDirs,
        maxDepth,
        dryRun
      });

      // Override gitignore entry if specified
      if (gitignoreEntry) {
        updater.gitignoreEntry = gitignoreEntry;
      }

      let results: ProcessResults;
      if (repositories && repositories.length > 0) {
        // Process specific repositories
        results = await this.processSpecificRepositories(updater, repositories);
      } else {
        // Process all repositories
        results = await updater.processRepositories() as unknown as ProcessResults;
      }

      logger.info({
        jobId: job.id,
        totalRepositories: results.totalRepositories,
        added: results.summary.added,
        skipped: results.summary.skipped,
        wouldAdd: results.summary.would_add,
        errors: results.summary.error
      }, 'Gitignore update job completed');

      const result: GitignoreUpdateResult = {
        ...results,
        timestamp: new Date().toISOString(),
        dryRun,
        gitignoreEntry
      };

      // Generate HTML/JSON reports
      const endTime = Date.now();
      const reportPaths = await generateReport({
        jobId: job.id,
        jobType: 'gitignore-update',
        status: 'completed',
        result,
        startTime,
        endTime,
        parameters: job.data,
        metadata: {
          totalRepositories: results.totalRepositories,
          dryRun
        }
      });

      result.reportPaths = reportPaths;
      logger.info({ reportPaths }, 'Gitignore update reports generated');

      return result;
    } catch (error) {
      logger.error({
        jobId: job.id,
        error: (error as Error).message,
        stack: (error as Error).stack
      }, 'Gitignore update job failed');

      Sentry.captureException(error, {
        tags: {
          component: 'gitignore-worker',
          job_id: job.id
        },
        extra: {
          baseDir,
          dryRun,
          gitignoreEntry
        }
      });

      throw error;
    }
  }

  /**
   * Process specific repositories
   */
  private async processSpecificRepositories(updater: GitignoreRepomixUpdater, repositories: string[]): Promise<ProcessResults> {
    const results: RepositoryResult[] = [];

    logger.info({
      count: repositories.length
    }, 'Processing specific repositories');

    for (const repoPath of repositories) {
      logger.info({ repository: repoPath }, 'Processing repository');
      const result = await updater.addToGitignore(repoPath) as unknown as { action: string; reason?: string; [key: string]: unknown };
      results.push({
        repository: repoPath,
        ...result
      });
      logger.info({
        repository: repoPath,
        action: result.action,
        reason: result.reason
      }, 'Repository processed');
    }

    return {
      totalRepositories: repositories.length,
      results,
      summary: updater.generateSummary(results as unknown as Parameters<typeof updater.generateSummary>[0]) as unknown as ProcessSummary
    };
  }

  /**
   * Create a job to update all repositories
   */
  createUpdateAllJob(options: UpdateJobOptions = {}): Job {
    const jobId = `gitignore-update-all-${Date.now()}`;

    return this.createJob(jobId, {
      type: 'gitignore-update',
      baseDir: options.baseDir ?? this.baseDir,
      dryRun: options.dryRun ?? false,
      gitignoreEntry: options.gitignoreEntry ?? this.gitignoreEntry,
      excludeDirs: options.excludeDirs ?? this.excludeDirs,
      maxDepth: options.maxDepth ?? this.maxDepth
    });
  }

  /**
   * Create a job to update specific repositories
   */
  createUpdateRepositoriesJob(repositories: string[], options: UpdateJobOptions = {}): Job {
    const jobId = `gitignore-update-repos-${Date.now()}`;

    return this.createJob(jobId, {
      type: 'gitignore-update',
      repositories,
      dryRun: options.dryRun ?? false,
      gitignoreEntry: options.gitignoreEntry ?? this.gitignoreEntry
    });
  }

  /**
   * Create a dry-run job to preview changes
   */
  createDryRunJob(options: UpdateJobOptions = {}): Job {
    const jobId = `gitignore-dryrun-${Date.now()}`;

    return this.createJob(jobId, {
      type: 'gitignore-update',
      baseDir: options.baseDir ?? this.baseDir,
      dryRun: true,
      gitignoreEntry: options.gitignoreEntry ?? this.gitignoreEntry,
      excludeDirs: options.excludeDirs ?? this.excludeDirs,
      maxDepth: options.maxDepth ?? this.maxDepth
    });
  }
}

// file: sidequest/workers/repomix-worker.ts
import { SidequestServer, type Job, type SidequestServerOptions } from '../core/server.ts';
import { generateReport } from '../utils/report-generator.ts';
import { spawn, execSync } from 'child_process';
import { captureProcessOutput } from '@shared/process-io';
import fs from 'fs/promises';
import path from 'path';
import os from 'os';
import { createComponentLogger, logError } from '../utils/logger.ts';
import { config } from '../core/config.ts';
import { TIMEOUTS, LIMITS } from '../core/constants.ts';

const logger = createComponentLogger('RepomixWorker');

interface RepomixWorkerOptions extends SidequestServerOptions {
  outputBaseDir?: string;
  codeBaseDir?: string;
  respectGitignore?: boolean;
  additionalIgnorePatterns?: string[];
}

interface RepomixCommandResult {
  stdout: string;
  stderr: string;
}

/**
 * RepomixWorker - Executes repomix jobs
 *
 * Respects .gitignore files by default - any directories or files listed
 * in .gitignore will be automatically excluded from processing.
 *
 * Options:
 * - respectGitignore: Respect .gitignore files (default: true)
 * - additionalIgnorePatterns: Array of additional patterns to ignore (default: [])
 * - outputBaseDir: Base directory for output files
 * - codeBaseDir: Base directory for source code
 */
export class RepomixWorker extends SidequestServer {
  outputBaseDir: string;
  codeBaseDir: string;
  respectGitignore: boolean;
  additionalIgnorePatterns: string[];

  /**
   * constructor.
   */
  constructor(options: RepomixWorkerOptions = {}) {
    super({
      ...options,
      jobType: 'repomix'
    });
    this.outputBaseDir = options.outputBaseDir ?? './condense';
    this.codeBaseDir = options.codeBaseDir ?? path.join(os.homedir(), 'code');

    // Gitignore handling (respects .gitignore by default)
    this.respectGitignore = options.respectGitignore !== false; // Default: true

    // Default ignore patterns from config (includes README.md and markdown files)
    // Can be overridden via options or environment variable
    this.additionalIgnorePatterns = options.additionalIgnorePatterns
      ?? (config as Record<string, unknown>).repomixIgnorePatterns as string[]
      ?? [];

    if (this.additionalIgnorePatterns.length > 0) {
      logger.info(
        { patterns: this.additionalIgnorePatterns },
        'RepomixWorker configured with ignore patterns (README files will be skipped)'
      );
    }

    // Pre-flight check: Verify repomix is available
    this.#verifyRepomixAvailable();
  }

  /**
   * Verify repomix is available via npx
   * Throws if repomix cannot be found
   */
  #verifyRepomixAvailable(): void {
    try {
      execSync('npx repomix --version', {
        stdio: 'ignore',
        timeout: TIMEOUTS.LONG_MS, // Allow time during heavy system load
        env: process.env, // Inherit full PATH from parent
      });
      logger.info('Pre-flight check: repomix is available');
    } catch (error) {
      const err = error as NodeJS.ErrnoException;
      // ETIMEDOUT can happen under heavy load - treat as available but warn
      if (err.code === 'ETIMEDOUT') {
        logger.warn('Pre-flight check timed out after 30s - assuming repomix is available');
        return;
      }
      const errorMessage =
        'repomix is not available. Please install it:\n' +
        '  npm install\n' +
        'Or verify package.json includes 'repomix' dependency.\n' +
        `PATH: ${process.env.PATH}`;
      logError(logger, err, errorMessage);
      throw new Error(errorMessage);
    }
  }

  /**
   * Run repomix for a specific directory
   */
  async runJobHandler(job: Job): Promise<unknown> {
    const startTime = Date.now();
    const { sourceDir, relativePath } = job.data as { sourceDir: string; relativePath: string };

    // Create output directory matching the source structure
    const outputDir = path.join(this.outputBaseDir, relativePath);
    await fs.mkdir(outputDir, { recursive: true });

    const outputFile = path.join(outputDir, 'repomix-output.txt');

    logger.info({ jobId: job.id, sourceDir, outputFile }, 'Running repomix');

    try {
      const { stdout, stderr } = await this.#runRepomixCommand(sourceDir);

      // Save the output to the appropriate location
      await fs.writeFile(outputFile, stdout);

      if (stderr) {
        logger.warn({ jobId: job.id, stderr }, 'Repomix warnings');
      }

      const result: Record<string, unknown> = {
        sourceDir,
        outputFile,
        relativePath,
        size: (await fs.stat(outputFile)).size,
        timestamp: new Date().toISOString()
      };

      // Generate HTML/JSON reports
      const endTime = Date.now();
      const repoName = path.basename(sourceDir);
      const reportPaths = await generateReport({
        jobId: job.id,
        jobType: 'repomix',
        status: 'completed',
        result,
        startTime,
        endTime,
        parameters: job.data,
        metadata: {
          repoName,
          outputSize: result.size
        }
      });

      result.reportPaths = reportPaths;
      logger.info({ reportPaths }, 'Repomix reports generated');

      return result;
    } catch (error) {
      const err = error as Error & { stdout?: string };
      // Even if command fails, try to save any output
      if (err.stdout) {
        await fs.writeFile(outputFile, err.stdout);
      }
      throw error;
    }
  }

  /**
   * Securely run repomix command using npx (prevents command injection)
   * Uses npx to ensure local repomix from node_modules is used
   *
   * By default, repomix respects .gitignore files and excludes:
   * - Files and directories listed in .gitignore
   * - Common patterns (node_modules, .git, etc.)
   */
  async #runRepomixCommand(cwd: string): Promise<RepomixCommandResult> {
    // Pre-flight check: Validate working directory exists before spawning
    // This prevents cryptic 'uv_cwd' ENOENT errors when directory is deleted
    try {
      const stats = await fs.stat(cwd);
      if (!stats.isDirectory()) {
        const error = new Error(`Working directory is not a directory: ${cwd}`) as Error & { code: string };
        error.code = 'ENOTDIR';
        throw error;
      }
    } catch (statError) {
      const err = statError as NodeJS.ErrnoException;
      if (err.code === 'ENOENT') {
        const error = new Error(
          `Working directory no longer exists: ${cwd}\n` +
          'This can happen when scanning temporary directories that are cleaned up before the scan completes.'
        ) as Error & { code: string; originalError: unknown };
        error.code = 'ENOENT';
        error.originalError = statError;
        logger.error({ cwd, error: statError }, 'Working directory deleted before repomix could run');
        throw error;
      }
      throw statError;
    }

    return new Promise((resolve, reject) => {
      // Build repomix arguments
      const args = ['repomix'];

      // Disable gitignore if requested (NOT recommended)
      if (!this.respectGitignore) {
        args.push('--no-gitignore');
        logger.warn({ cwd }, 'Running repomix with --no-gitignore (not recommended)');
      }

      // Add additional ignore patterns if specified
      if (this.additionalIgnorePatterns.length > 0) {
        args.push('--ignore', this.additionalIgnorePatterns.join(','));
        logger.info(
          { cwd, patterns: this.additionalIgnorePatterns },
          'Adding additional ignore patterns'
        );
      }

      logger.debug({ cwd, args }, 'Spawning repomix with arguments');

      const proc = spawn('npx', args, {
        cwd,
        timeout: TIMEOUTS.REPOMIX_MS,
        env: process.env, // Inherit full PATH from parent to locate npx
      });

      const output = captureProcessOutput(proc);

      proc.on('close', (code) => {
        const stdout = output.getStdout();
        const stderr = output.getStderr();
        if (code === 0) {
          resolve({ stdout, stderr });
        } else {
          logger.error({
            code,
            cwd,
            args,
            stdout: stdout.slice(-LIMITS.MAX_OUTPUT_CHARS),
            stderr: stderr.slice(-LIMITS.MAX_OUTPUT_CHARS)
          }, `repomix exited with code ${code}`);

          const error = new Error(
            `repomix exited with code ${code}\n` +
            `stderr: ${stderr.slice(-LIMITS.STDERR_SHORT_TAIL_CHARS)}\n` +
            `Reproduce: cd ${cwd} && npx repomix ${args.slice(1).join(' ')}`
          ) as Error & { code: number | null; stdout: string; stderr: string };
          error.code = code;
          error.stdout = stdout;
          error.stderr = stderr;
          reject(error);
        }
      });

      proc.on('error', (spawnError) => {
        const stdout = output.getStdout();
        const stderr = output.getStderr();
        // Enhance error message for common spawn failures
        let enhancedError: Error & { code?: string; syscall?: string; originalError?: Error; stdout?: string; stderr?: string } = spawnError;
        const nodeErr = spawnError as NodeJS.ErrnoException;
        if (nodeErr.syscall === 'uv_cwd' || nodeErr.syscall === 'spawn') {
          enhancedError = new Error(
            `Failed to spawn repomix process: ${spawnError.message}\n` +
            `Working directory: ${cwd}\n` +
            'This usually means the directory was deleted during the scan.'
          ) as typeof enhancedError;
          enhancedError.code = nodeErr.code;
          enhancedError.syscall = nodeErr.syscall;
          enhancedError.originalError = spawnError;
          logger.error({ cwd, error: spawnError }, 'Spawn failed - directory may have been deleted');
        }
        enhancedError.stdout = stdout;
        enhancedError.stderr = stderr;
        reject(enhancedError);
      });
    });
  }

  /**
   * Create a repomix job for a directory
   */
  createRepomixJob(sourceDir: string, relativePath: string): Job {
    const jobId = `repomix-${relativePath.replace(/\//g, '-')}-${Date.now()}`;

    return this.createJob(jobId, {
      sourceDir,
      relativePath,
      type: 'repomix'
    });
  }
}

// file: sidequest/workers/claude-health-worker.ts
/**
 * Claude Health Check Worker - AlephAuto Integration
 *
 * Comprehensive health monitoring for Claude Code environment including:
 * - Skills, hooks, agents, commands inventory
 * - Configuration validation (settings.json, skill-rules.json)
 * - Hook permissions and registration
 * - Plugin analysis and duplicate detection
 * - Directory structure verification
 * - Environment variable status
 * - Performance log analysis
 *
 * @extends SidequestServer
 */

import { SidequestServer, type Job, type SidequestServerOptions } from '../core/server.ts';
import { config } from '../core/config.ts';
import { BYTES_PER_KB, LIMITS, MAX_SCORE, TIMEOUTS } from '../core/constants.ts';
import { HEALTH_SCORE_THRESHOLDS } from '../core/score-thresholds.ts';
import { createComponentLogger, logError, logWarn, logStart } from '../utils/logger.ts';
import { generateReport } from '../utils/report-generator.ts';
import { exec } from 'child_process';
import { promisify } from 'util';
import fs from 'fs/promises';
import path from 'path';

const execAsync = promisify(exec);
const logger = createComponentLogger('ClaudeHealth');

// --- Type definitions ---

type ClaudeHealthWorkerOptions = SidequestServerOptions;

interface Thresholds {
  maxPlugins: number;
  warnPlugins: number;
  maxHookExecutionTime: number;
  minDiskSpace: number;
  maxLogSize: number;
}

interface CheckOptions {
  detailed?: boolean;
  validateConfig?: boolean;
  checkPerformance?: boolean;
  analyzePlugins?: boolean;
}

interface EnvironmentCheck {
  direnv: boolean;
  direnvConfigured: boolean;
  direnvAllowed: boolean;
  nodeVersion: string | null;
  npmVersion: string | null;
  envVars: Record<string, string | null>;
}

interface DirectoryInfo {
  exists: boolean;
  path: string;
  size?: number | null;
  error?: string;
}

interface ConfigCheck {
  settingsJson: Record<string, unknown>;
  skillRulesJson: Record<string, unknown>;
  packageJson: Record<string, unknown>;
  envrc: Record<string, unknown>;
}

interface HookInfo {
  name: string;
  executable: boolean;
  size: number;
}

interface HooksCheck {
  totalHooks: number;
  executableHooks: number;
  registeredHooks: number;
  hooks: HookInfo[];
}

interface ComponentCounts {
  skills: number;
  agents: number;
  commands: number;
  activeTasks: number;
  archivedTasks: number;
  templates: number;
}

interface DuplicateCategory {
  category: string;
  plugins: string[];
  count: number;
}

interface PluginsCheck {
  totalPlugins: number;
  enabledPlugins: string[];
  duplicateCategories: DuplicateCategory[];
  exceededThresholds: {
    maxPlugins: boolean;
    warnPlugins: boolean;
  };
}

interface SlowHookDetail {
  hook: string;
  duration: number;
}

interface PerformanceCheck {
  logExists: boolean;
  logSize?: number;
  totalEntries?: number;
  recentEntries?: number;
  slowHooks?: number;
  failures?: number;
  slowHookDetails?: SlowHookDetail[];
  message?: string;
}

interface AllChecks {
  environment: EnvironmentCheck;
  directories: Record<string, DirectoryInfo>;
  configuration: ConfigCheck | null;
  hooks: HooksCheck;
  components: ComponentCounts;
  plugins: PluginsCheck | null;
  performance: PerformanceCheck | null;
}

interface Issue {
  type: string;
  message: string;
  action?: string;
}

interface Analysis {
  issues: Issue[];
  warnings: Issue[];
  successes: Issue[];
  healthScore: number;
}

interface Recommendation {
  priority: 'high' | 'medium' | 'info';
  type: string;
  message: string;
  action: string;
}

interface Summary {
  healthScore: number;
  status: 'healthy' | 'warning' | 'critical';
  criticalIssues: number;
  warnings: number;
  message: string;
}

interface HealthCheckResult {
  success: boolean;
  timestamp: string;
  duration: number;
  checks: AllChecks;
  analysis: Analysis;
  recommendations: Recommendation[];
  summary: Summary;
  reportPaths?: unknown;
}

class ClaudeHealthWorker extends SidequestServer {
  claudeDir: string;
  devDir: string;
  healthScriptPath: string;
  thresholds: Thresholds;

  /**
   * constructor.
   */
  constructor(options: ClaudeHealthWorkerOptions = {}) {
    super({
      ...options,
      jobType: 'claude-health',
      maxConcurrent: options.maxConcurrent ?? 1, // Single concurrent health check
    });

    this.claudeDir = path.join(config.homeDir, '.claude');
    this.devDir = path.join(config.homeDir, 'dev');
    this.healthScriptPath = path.join(
      config.homeDir,
      'code/jobs/sidequest/claude-health-check.sh'
    );

    this.thresholds = {
      maxPlugins: 30,
      warnPlugins: 20,
      maxHookExecutionTime: TIMEOUTS.POLL_INTERVAL_MS, // Max hook execution time
      minDiskSpace: BYTES_PER_KB * BYTES_PER_KB * LIMITS.MIN_DISK_SPACE_MB,
      maxLogSize: LIMITS.MAX_BUFFER_MB * BYTES_PER_KB * BYTES_PER_KB // 10MB
    };

    logger.info({
      claudeDir: this.claudeDir,
      healthScriptPath: this.healthScriptPath
    }, 'Claude Health Worker initialized');
  }

  /**
   * Run comprehensive health check job
   */
  async runJobHandler(job: Job): Promise<HealthCheckResult> {
    const startTime = Date.now();
    logStart(logger, 'Claude health check', { jobId: job.id });

    try {
      const checks = await this.runAllChecks((job.data as CheckOptions) ?? {});
      const analysis = this.analyzeResults(checks);
      const recommendations = this.generateRecommendations(analysis);

      const result: HealthCheckResult = {
        success: true,
        timestamp: new Date().toISOString(),
        duration: Date.now() - startTime,
        checks,
        analysis,
        recommendations,
        summary: this.generateSummary(analysis, recommendations)
      };

      logger.info({
        jobId: job.id,
        issueCount: recommendations.filter(r => r.priority === 'high').length,
        duration: result.duration
      }, 'Claude health check completed');

      // Generate HTML/JSON reports
      const endTime = Date.now();
      const reportPaths = await generateReport({
        jobId: job.id,
        jobType: 'claude-health',
        status: 'completed',
        result,
        startTime,
        endTime,
        parameters: job.data ?? {},
        metadata: {
          healthScore: analysis.healthScore,
          criticalIssues: recommendations.filter(r => r.priority === 'high').length,
          warnings: recommendations.filter(r => r.priority === 'medium').length
        }
      });

      result.reportPaths = reportPaths;
      logger.info({ reportPaths }, 'Health check reports generated');

      return result;
    } catch (error) {
      logError(logger, error as Error, 'Claude health check failed', { jobId: job.id });
      throw error;
    }
  }

  /**
   * Run all health checks
   */
  async runAllChecks(options: CheckOptions = {}): Promise<AllChecks> {
    // Run checks in parallel where possible
    const [
      environment,
      directories,
      configuration,
      hooks,
      components,
      plugins,
      performance
    ] = await Promise.all([
      this.checkEnvironment(),
      this.checkDirectories(),
      options.validateConfig !== false ? this.checkConfiguration() : null,
      this.checkHooks(),
      this.checkComponents(options.detailed),
      options.analyzePlugins !== false ? this.checkPlugins() : null,
      options.checkPerformance !== false ? this.checkPerformance() : null
    ]);

    return {
      environment,
      directories,
      configuration,
      hooks,
      components,
      plugins,
      performance
    };
  }

  /**
   * Check environment variables and dependencies
   */
  async checkEnvironment(): Promise<EnvironmentCheck> {
    const checks: EnvironmentCheck = {
      direnv: false,
      direnvConfigured: false,
      direnvAllowed: false,
      nodeVersion: null,
      npmVersion: null,
      envVars: {}
    };

    try {
      // Check direnv
      try {
        await execAsync('which direnv');
        checks.direnv = true;
      } catch {
        checks.direnv = false;
      }

      // Check if direnv hook is in shell config
      try {
        const { stdout } = await execAsync('grep -q 'direnv hook' ~/.zshrc && echo 'configured' || echo 'not configured'');
        checks.direnvConfigured = stdout.trim() === 'configured';
      } catch {
        checks.direnvConfigured = false;
      }

      // Check Node.js version
      const { stdout: nodeVersion } = await execAsync('node --version');
      checks.nodeVersion = nodeVersion.trim();

      // Check npm version
      const { stdout: npmVersion } = await execAsync('npm --version');
      checks.npmVersion = npmVersion.trim();

      // Check critical environment variables
      const varNames = [
        'CLAUDE_CONFIG_DIR',
        'CLAUDE_PROJECT_DIR',
        'CLAUDE_ACTIVE_DOCS',
        'CLAUDE_HOOKS_DIR'
      ];

      for (const varName of varNames) {
        checks.envVars[varName] = process.env[varName] ?? null;
      }

      checks.direnvAllowed = Object.values(checks.envVars).every(v => v !== null);

    } catch (error) {
      logWarn(logger, error as Error, 'Error checking environment');
    }

    return checks;
  }

  /**
   * Check directory structure
   */
  async checkDirectories(): Promise<Record<string, DirectoryInfo>> {
    const requiredDirs: Record<string, string> = {
      '.claude': this.claudeDir,
      'skills': path.join(this.claudeDir, 'skills'),
      'hooks': path.join(this.claudeDir, 'hooks'),
      'agents': path.join(this.claudeDir, 'agents'),
      'commands': path.join(this.claudeDir, 'commands'),
      'scripts': path.join(this.claudeDir, 'scripts'),
      'logs': path.join(this.claudeDir, 'logs'),
      'dev': this.devDir,
      'dev/active': path.join(this.devDir, 'active'),
      'dev/archive': path.join(this.devDir, 'archive'),
      'dev/templates': path.join(this.devDir, 'templates')
    };

    const checks: Record<string, DirectoryInfo> = {};

    for (const [name, dirPath] of Object.entries(requiredDirs)) {
      try {
        const stats = await fs.stat(dirPath);
        checks[name] = {
          exists: stats.isDirectory(),
          path: dirPath,
          size: null
        };
      } catch (error) {
        const err = error as NodeJS.ErrnoException;
        checks[name] = {
          exists: false,
          path: dirPath,
          error: err.code
        };
      }
    }

    return checks;
  }

  /**
   * Check configuration files
   */
  async checkConfiguration(): Promise<ConfigCheck> {
    const checks: ConfigCheck = {
      settingsJson: {},
      skillRulesJson: {},
      packageJson: {},
      envrc: {}
    };

    // Check settings.json
    const settingsPath = path.join(this.claudeDir, 'settings.json');
    try {
      const data = await fs.readFile(settingsPath, 'utf-8');
      const settings = JSON.parse(data) as Record<string, unknown>;
      checks.settingsJson = {
        exists: true,
        valid: true,
        hooks: settings.hooks ? Object.keys(settings.hooks as Record<string, unknown>).length : 0,
        enabledPlugins: settings.enabledPlugins ? Object.keys(settings.enabledPlugins as Record<string, unknown>).length : 0
      };
    } catch (error) {
      const err = error as NodeJS.ErrnoException;
      checks.settingsJson = {
        exists: err.code !== 'ENOENT',
        valid: false,
        error: err.message
      };
    }

    // Check skill-rules.json
    const skillRulesPath = path.join(this.claudeDir, 'skills', 'skill-rules.json');
    try {
      const data = await fs.readFile(skillRulesPath, 'utf-8');
      const skillRules = JSON.parse(data) as Record<string, unknown>;
      checks.skillRulesJson = {
        exists: true,
        valid: true,
        skillCount: skillRules.skills ? Object.keys(skillRules.skills as Record<string, unknown>).length : 0
      };
    } catch (error) {
      const err = error as NodeJS.ErrnoException;
      checks.skillRulesJson = {
        exists: err.code !== 'ENOENT',
        valid: false,
        error: err.message
      };
    }

    // Check package.json
    const packagePath = path.join(this.claudeDir, 'package.json');
    try {
      const data = await fs.readFile(packagePath, 'utf-8');
      const pkg = JSON.parse(data) as Record<string, unknown>;
      checks.packageJson = {
        exists: true,
        valid: true,
        scripts: pkg.scripts ? Object.keys(pkg.scripts as Record<string, unknown>).length : 0
      };
    } catch (error) {
      const err = error as NodeJS.ErrnoException;
      checks.packageJson = {
        exists: err.code !== 'ENOENT',
        valid: false,
        error: err.message
      };
    }

    // Check .envrc
    const envrcPath = path.join(this.claudeDir, '.envrc');
    try {
      await fs.access(envrcPath);
      checks.envrc = { exists: true };
    } catch {
      checks.envrc = { exists: false };
    }

    return checks;
  }

  /**
   * Check hooks
   */
  async checkHooks(): Promise<HooksCheck> {
    const hooksDir = path.join(this.claudeDir, 'hooks');
    const checks: HooksCheck = {
      totalHooks: 0,
      executableHooks: 0,
      registeredHooks: 0,
      hooks: []
    };

    try {
      const files = await fs.readdir(hooksDir);
      const shellHooks = files.filter(f => f.endsWith('.sh'));

      checks.totalHooks = shellHooks.length;

      for (const hook of shellHooks) {
        const hookPath = path.join(hooksDir, hook);
        const stats = await fs.stat(hookPath);
        const isExecutable = (stats.mode & 0o111) !== 0;

        if (isExecutable) checks.executableHooks++;

        checks.hooks.push({
          name: hook,
          executable: isExecutable,
          size: stats.size
        });
      }

      // Check registered hooks
      const settingsPath = path.join(this.claudeDir, 'settings.json');
      try {
        const data = await fs.readFile(settingsPath, 'utf-8');
        const settings = JSON.parse(data) as Record<string, unknown>;
        checks.registeredHooks = settings.hooks ? Object.keys(settings.hooks as Record<string, unknown>).length : 0;
      } catch (e) {
        logWarn(logger, e as Error, 'Could not check registered hooks');
      }

    } catch (error) {
      logWarn(logger, error as Error, 'Error checking hooks');
    }

    return checks;
  }

  /**
   * Check component counts
   */
  async checkComponents(_detailed = false): Promise<ComponentCounts> {
    const counts: ComponentCounts = {
      skills: 0,
      agents: 0,
      commands: 0,
      activeTasks: 0,
      archivedTasks: 0,
      templates: 0
    };

    try {
      // Count skills
      const skillsDir = path.join(this.claudeDir, 'skills');
      const skillFiles = await fs.readdir(skillsDir);
      counts.skills = skillFiles.filter(f => f.endsWith('.md')).length;

      // Count agents
      const agentsDir = path.join(this.claudeDir, 'agents');
      const agentFiles = await fs.readdir(agentsDir);
      counts.agents = agentFiles.filter(f => f.endsWith('.md')).length;

      // Count commands
      const commandsDir = path.join(this.claudeDir, 'commands');
      const commandFiles = await fs.readdir(commandsDir);
      counts.commands = commandFiles.filter(f => f.endsWith('.md')).length;

      // Count active tasks
      const activeDir = path.join(this.devDir, 'active');
      try {
        const activeTasks = await fs.readdir(activeDir);
        counts.activeTasks = activeTasks.filter(f => !f.startsWith('.')).length;
      } catch {
        counts.activeTasks = 0;
      }

      // Count archived tasks
      const archiveDir = path.join(this.devDir, 'archive');
      try {
        const archivedTasks = await fs.readdir(archiveDir);
        counts.archivedTasks = archivedTasks.filter(f => !f.startsWith('.')).length;
      } catch {
        counts.archivedTasks = 0;
      }

      // Count templates
      const templatesDir = path.join(this.devDir, 'templates');
      try {
        const templates = await fs.readdir(templatesDir);
        counts.templates = templates.filter(f => f.endsWith('.md')).length;
      } catch {
        counts.templates = 0;
      }

    } catch (error) {
      logWarn(logger, error as Error, 'Error checking components');
    }

    return counts;
  }

  /**
   * Check plugins (integrate with plugin manager)
   */
  async checkPlugins(): Promise<PluginsCheck | null> {
    try {
      const settingsPath = path.join(this.claudeDir, 'settings.json');
      const data = await fs.readFile(settingsPath, 'utf-8');
      const settings = JSON.parse(data) as Record<string, unknown>;

      const enabledPlugins = (settings.enabledPlugins ?? {}) as Record<string, unknown>;
      const totalPlugins = Object.keys(enabledPlugins).length;

      // Basic duplicate detection (category-based)
      const categories: Record<string, string[]> = {};
      for (const plugin of Object.keys(enabledPlugins)) {
        const category = plugin.split(/[@-]/)[0];
        if (!categories[category]) categories[category] = [];
        categories[category].push(plugin);
      }

      const duplicateCategories: DuplicateCategory[] = Object.entries(categories)
        .filter(([, plugins]) => plugins.length > 1)
        .map(([category, plugins]) => ({ category, plugins, count: plugins.length }));

      return {
        totalPlugins,
        enabledPlugins: Object.keys(enabledPlugins),
        duplicateCategories,
        exceededThresholds: {
          maxPlugins: totalPlugins > this.thresholds.maxPlugins,
          warnPlugins: totalPlugins > this.thresholds.warnPlugins
        }
      };
    } catch (error) {
      logWarn(logger, error as Error, 'Error checking plugins');
      return null;
    }
  }

  /**
   * Check performance logs
   */
  async checkPerformance(): Promise<PerformanceCheck | null> {
    const perfLogPath = path.join(this.claudeDir, 'logs', 'hook-performance.log');

    try {
      const stats = await fs.stat(perfLogPath);
      const logSize = stats.size;

      // Read recent entries
      const data = await fs.readFile(perfLogPath, 'utf-8');
      const lines = data.split('\n').filter(l => l.trim());
      const recentEntries = lines.slice(-LIMITS.PERF_LOG_RECENT_ENTRIES);

      // Parse slow hooks
      const slowHooks: SlowHookDetail[] = recentEntries
        .filter(line => line.includes('SLOW'))
        .map(line => {
          const match = line.match(/\[([^\]]+)\].*?(\d+)ms/);
          return match ? { hook: match[1], duration: parseInt(match[2]) } : null;
        })
        .filter((entry): entry is SlowHookDetail => entry !== null);

      // Parse failures
      const failures = recentEntries.filter(line => line.includes('failed')).length;

      return {
        logExists: true,
        logSize,
        totalEntries: lines.length,
        recentEntries: recentEntries.length,
        slowHooks: slowHooks.length,
        failures,
        slowHookDetails: slowHooks.slice(0, LIMITS.MAX_SLOW_HOOKS_DISPLAY) // Top slowest
      };
    } catch (error) {
      const err = error as NodeJS.ErrnoException;
      if (err.code === 'ENOENT') {
        return {
          logExists: false,
          message: 'Performance log not created yet'
        };
      }
      logWarn(logger, err, 'Error checking performance');
      return null;
    }
  }

  /**
   * Analyze health check results
   */
  analyzeResults(checks: AllChecks): Analysis {
    const issues: Issue[] = [];
    const warnings: Issue[] = [];
    const successes: Issue[] = [];

    // Environment analysis
    if (!checks.environment?.direnv) {
      warnings.push({ type: 'environment', message: 'direnv not installed' });
    } else if (!checks.environment?.direnvConfigured) {
      warnings.push({ type: 'environment', message: 'direnv hook not configured in shell' });
    } else if (!checks.environment?.direnvAllowed) {
      warnings.push({ type: 'environment', message: 'Environment variables not loaded (run: direnv allow)' });
    } else {
      successes.push({ type: 'environment', message: 'Environment properly configured' });
    }

    // Directory analysis
    const missingDirs = Object.entries(checks.directories ?? {})
      .filter(([, info]) => !info.exists)
      .map(([name]) => name);

    if (missingDirs.length > 0) {
      issues.push({ type: 'directories', message: `Missing directories: ${missingDirs.join(', ')}` });
    } else {
      successes.push({ type: 'directories', message: 'All required directories exist' });
    }

    // Configuration analysis
    if (!(checks.configuration?.settingsJson as Record<string, unknown>)?.valid) {
      issues.push({ type: 'configuration', message: 'settings.json is invalid or missing' });
    }
    if (!(checks.configuration?.skillRulesJson as Record<string, unknown>)?.valid) {
      issues.push({ type: 'configuration', message: 'skill-rules.json is invalid or missing' });
    }
    if ((checks.configuration?.settingsJson as Record<string, unknown>)?.valid && (checks.configuration?.skillRulesJson as Record<string, unknown>)?.valid) {
      successes.push({ type: 'configuration', message: 'Configuration files valid' });
    }

    // Hooks analysis
    const nonExecutableHooks = (checks.hooks?.totalHooks ?? 0) - (checks.hooks?.executableHooks ?? 0);
    if (nonExecutableHooks > 0) {
      issues.push({
        type: 'hooks',
        message: `${nonExecutableHooks} hook(s) not executable`,
        action: 'Run: chmod +x ~/.claude/hooks/*.sh'
      });
    }

    if ((checks.hooks?.registeredHooks ?? 0) === 0) {
      warnings.push({ type: 'hooks', message: 'No hooks registered in settings.json' });
    }

    // Plugin analysis
    if (checks.plugins?.exceededThresholds?.maxPlugins) {
      issues.push({
        type: 'plugins',
        message: `Too many plugins enabled (${checks.plugins.totalPlugins} > ${this.thresholds.maxPlugins})`,
        action: 'Review and disable unused plugins'
      });
    } else if (checks.plugins?.exceededThresholds?.warnPlugins) {
      warnings.push({
        type: 'plugins',
        message: `High plugin count (${checks.plugins.totalPlugins})`,
        action: 'Consider reviewing plugin usage'
      });
    }

    if ((checks.plugins?.duplicateCategories?.length ?? 0) > 0) {
      warnings.push({
        type: 'plugins',
        message: `Found ${checks.plugins!.duplicateCategories.length} categories with duplicate plugins`,
        action: 'Review and consolidate duplicate plugins'
      });
    }

    // Performance analysis
    if (checks.performance?.logExists) {
      if ((checks.performance.slowHooks ?? 0) > 0) {
        warnings.push({
          type: 'performance',
          message: `${checks.performance.slowHooks} slow hook executions detected`,
          action: 'Review hook performance'
        });
      }
      if ((checks.performance.failures ?? 0) > 0) {
        issues.push({
          type: 'performance',
          message: `${checks.performance.failures} hook failures detected`,
          action: 'Check hook logs for errors'
        });
      }
    }

    return {
      issues,
      warnings,
      successes,
      healthScore: this.calculateHealthScore(issues, warnings, successes)
    };
  }

  /**
   * Calculate overall health score (0-100)
   */
  calculateHealthScore(issues: Issue[], warnings: Issue[], successes: Issue[]): number {
    const totalChecks = issues.length + warnings.length + successes.length;
    if (totalChecks === 0) return MAX_SCORE;

    const issueWeight = 20;
    const warningWeight = 5;
    const successWeight = 10;

    const deductions = (issues.length * issueWeight) + (warnings.length * warningWeight);
    const additions = successes.length * successWeight;

    return Math.max(0, Math.min(MAX_SCORE, MAX_SCORE - deductions + (additions / totalChecks)));
  }

  /**
   * Generate recommendations
   */
  generateRecommendations(analysis: Analysis): Recommendation[] {
    const recommendations: Recommendation[] = [];

    // Critical issues first
    for (const issue of analysis.issues) {
      recommendations.push({
        priority: 'high',
        type: issue.type,
        message: issue.message,
        action: issue.action ?? 'Review and fix'
      });
    }

    // Warnings
    for (const warning of analysis.warnings) {
      recommendations.push({
        priority: 'medium',
        type: warning.type,
        message: warning.message,
        action: warning.action ?? 'Review recommended'
      });
    }

    // Success message if health score is high
    if (analysis.healthScore >= LIMITS.HIGH_HEALTH_SCORE && recommendations.length === 0) {
      recommendations.push({
        priority: 'info',
        type: 'healthy',
        message: `Claude environment is healthy (Score: ${analysis.healthScore}/100)`,
        action: 'No action needed'
      });
    }

    return recommendations;
  }

  /**
   * Generate summary
   */
  generateSummary(analysis: Analysis, recommendations: Recommendation[]): Summary {
    const critical = recommendations.filter(r => r.priority === 'high').length;
    const warningCount = recommendations.filter(r => r.priority === 'medium').length;

    return {
      healthScore: analysis.healthScore,
      status: analysis.healthScore >= HEALTH_SCORE_THRESHOLDS.HEALTHY_MIN_SCORE
        ? 'healthy'
        : analysis.healthScore >= HEALTH_SCORE_THRESHOLDS.WARNING_MIN_SCORE ? 'warning' : 'critical',
      criticalIssues: critical,
      warnings: warningCount,
      message: this.getStatusMessage(analysis.healthScore, critical, warningCount)
    };
  }

  /**
   * Get status message based on health score
   */
  getStatusMessage(healthScore: number, critical: number, warnings: number): string {
    if (healthScore >= HEALTH_SCORE_THRESHOLDS.HEALTHY_MIN_SCORE && critical === 0 && warnings === 0) {
      return 'Claude environment is healthy';
    } else if (healthScore >= HEALTH_SCORE_THRESHOLDS.WARNING_MIN_SCORE) {
      return `Claude environment has ${warnings} warning(s)`;
    } else {
      return `Claude environment has ${critical} critical issue(s)`;
    }
  }

  /**
   * Create a health check job
   */
