import test from 'node:test';
import assert from 'node:assert/strict';
import fs from 'fs/promises';
import os from 'os';
import path from 'path';
import { spawn } from 'child_process';
import { fileURLToPath } from 'url';

interface ScriptRunResult {
  code: number | null;
  signal: NodeJS.Signals | null;
  stdout: string;
  stderr: string;
  timedOut: boolean;
}

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const REPO_ROOT = path.resolve(__dirname, '..');
const DIRECT_EXEC_TEST_TIMEOUT_MS = 3_000;
const KEEP_ALIVE_CHECK_MS = 1_200;

const GUARDED_PIPELINES = [
  'pipeline-runners/git-activity-pipeline.ts',
  'pipeline-runners/bugfix-audit-pipeline.ts',
  'pipeline-runners/plugin-management-pipeline.ts',
  'pipeline-runners/schema-enhancement-pipeline.ts',
  'pipeline-runners/duplicate-detection-pipeline.ts',
  'pipeline-runners/repo-cleanup-pipeline.ts',
  'pipeline-runners/gitignore-pipeline.ts'
];

async function runViaSymlinkWithSpace(scriptRelativePath: string): Promise<ScriptRunResult> {
  const tempDir = await fs.mkdtemp(path.join(os.tmpdir(), 'direct-exec-guard-'));
  const realScriptPath = path.join(REPO_ROOT, scriptRelativePath);
  const linkPath = path.join(tempDir, `entry with space ${path.basename(scriptRelativePath)}`);
  await fs.symlink(realScriptPath, linkPath);

  try {
    return await new Promise<ScriptRunResult>((resolve, reject) => {
      const child = spawn(
        process.execPath,
        ['--strip-types', linkPath],
        {
          cwd: REPO_ROOT,
          env: {
            ...process.env,
            RUN_ON_STARTUP: 'false',
            NODE_ENV: 'test',
            LOG_LEVEL: 'info'
          },
          stdio: ['ignore', 'pipe', 'pipe']
        }
      );

      let stdout = '';
      let stderr = '';
      let settled = false;
      let timedOut = false;

      child.stdout.on('data', (chunk) => {
        stdout += String(chunk);
      });
      child.stderr.on('data', (chunk) => {
        stderr += String(chunk);
      });

      const timeout = setTimeout(() => {
        timedOut = true;
        child.kill('SIGKILL');
      }, KEEP_ALIVE_CHECK_MS);

      const hardTimeout = setTimeout(() => {
        if (!settled) {
          child.kill('SIGKILL');
          reject(new Error(`Timed out waiting for ${scriptRelativePath} to exit`));
        }
      }, DIRECT_EXEC_TEST_TIMEOUT_MS);

      child.on('error', (error) => {
        if (settled) return;
        settled = true;
        clearTimeout(timeout);
        clearTimeout(hardTimeout);
        reject(error);
      });

      child.on('exit', (code, signal) => {
        if (settled) return;
        settled = true;
        clearTimeout(timeout);
        clearTimeout(hardTimeout);
        resolve({ code, signal, stdout, stderr, timedOut });
      });
    });
  } finally {
    await fs.rm(tempDir, { recursive: true, force: true });
  }
}

for (const scriptRelativePath of GUARDED_PIPELINES) {
  test(`${scriptRelativePath} executes directly via symlink path with spaces`, async () => {
    const result = await runViaSymlinkWithSpace(scriptRelativePath);
    assert.equal(
      result.timedOut,
      true,
      `${scriptRelativePath} exited early (code=${result.code}, signal=${result.signal}). stdout:\n${result.stdout}\nstderr:\n${result.stderr}`
    );
  });
}

// file: sidequest/pipeline-runners/schema-enhancement-pipeline.ts
#!/usr/bin/env -S node --strip-types
import { SchemaEnhancementWorker } from '../workers/schema-enhancement-worker.ts';
import { config } from '../core/config.ts';
import { CONCURRENCY, PROCESS } from '../core/constants.ts';
import { createComponentLogger, logError, logStart } from '../utils/logger.ts';
import { BasePipeline, type JobStats } from './base-pipeline.ts';
import fs from 'fs/promises';
import path from 'path';
import { isDirectExecution } from '../utils/execution-helpers.ts';

const logger = createComponentLogger('SchemaEnhancementPipeline');

interface ReadmeFile {
  fullPath: string;
  relativePath: string;
  name: string;
  dirPath: string;
}

interface RepoContext extends Record<string, unknown> {
  totalReadmes: number;
  baseDir: string;
  hasPackageJson: boolean;
  hasPyproject: boolean;
  gitRemote: string | null;
}

interface EnhancementResult {
  status: string;
  readmesFound?: number;
  enhanced?: number;
  duration?: number;
  jobs?: JobStats;
  [key: string]: unknown;
}

interface SchemaEnhancementOptions {
  gitWorkflowEnabled?: boolean;
  gitBranchPrefix?: string;
  gitBaseBranch?: string;
  gitDryRun?: boolean;
  outputBaseDir?: string;
  dryRun?: boolean;
  baseDir?: string;
  [key: string]: unknown;
}

/**
 * Schema Enhancement Pipeline
 * Automatically enhances README files with Schema.org structured data
 */
class SchemaEnhancementPipeline extends BasePipeline<SchemaEnhancementWorker> {
  private excludeDirs: Set<string>;
  private baseDir: string;
  private options: SchemaEnhancementOptions;

  /**
   * constructor.
   */
  constructor(options: SchemaEnhancementOptions = {}) {
    super(new SchemaEnhancementWorker({
      ...options,
      maxConcurrent: config.maxConcurrent ?? CONCURRENCY.DEFAULT_IO_BOUND,
      logDir: config.logDir,
      sentryDsn: config.sentryDsn,
      gitWorkflowEnabled: options.gitWorkflowEnabled ?? config.enableGitWorkflow,
      gitBranchPrefix: options.gitBranchPrefix || 'docs',
      gitBaseBranch: options.gitBaseBranch || config.gitBaseBranch,
      gitDryRun: options.gitDryRun ?? config.gitDryRun,
      outputBaseDir: options.outputBaseDir || './document-enhancement-impact-measurement',
      dryRun: options.dryRun || false
    }));

    this.options = options;

    this.excludeDirs = new Set([
      'node_modules',
      '.git',
      'dist',
      'build',
      'coverage',
      'venv',
      '__pycache__'
    ]);

    this.baseDir = options.baseDir || config.codeBaseDir || config.homeDir;
    this.setupDefaultEventListeners(logger, {
      onCreated: (job) => ({ readmePath: (job.data as Record<string, unknown>).relativePath }),
      onStarted: (job) => ({ readmePath: (job.data as Record<string, unknown>).relativePath }),
      onCompleted: (job) => {
        const result = job.result as Record<string, unknown>;
        const impact = result.impact as Record<string, unknown> | undefined;
        return { status: result.status, schemaType: result.schemaType, impactScore: impact?.impactScore };
      },
      onFailed: (job) => ({ readmePath: (job.data as Record<string, unknown>).relativePath })
    });
  }

  /**
   * Recursively scan directory for README files
   */
  async scanForReadmes(dir: string, baseDir: string = dir, results: ReadmeFile[] = []): Promise<ReadmeFile[]> {
    try {
      const entries = await fs.readdir(dir, { withFileTypes: true });

      for (const entry of entries) {
        const fullPath = path.join(dir, entry.name);

        if (entry.isDirectory()) {
          // Skip excluded directories
          if (this.excludeDirs.has(entry.name)) {
            continue;
          }

          // Recursively scan subdirectories
          await this.scanForReadmes(fullPath, baseDir, results);
        } else if (entry.name === 'README.md') {
          const relativePath = path.relative(baseDir, fullPath);
          results.push({
            fullPath,
            relativePath,
            name: entry.name,
            dirPath: path.dirname(fullPath)
          });
        }
      }
    } catch (error) {
      logger.error({ dir, error: error instanceof Error ? error.message : String(error) }, 'Error scanning directory');
    }

    return results;
  }

  /**
   * Scan directory for README files
   */
  async scanDirectory(directory: string): Promise<ReadmeFile[]> {
    logger.info({ directory }, 'Scanning for README files');

    const readmeFiles = await this.scanForReadmes(directory);

    logger.info({
      readmeFiles: readmeFiles.length
    }, 'Directory scan complete');

    return readmeFiles;
  }

  /**
   * Create enhancement jobs for README files
   */
  async createEnhancementJobs(readmeFiles: ReadmeFile[]): Promise<void> {
    const context = {
      totalReadmes: readmeFiles.length,
      baseDir: this.baseDir
    };

    for (const readme of readmeFiles) {
      // Add context about the repository
      const repoContext: RepoContext = {
        ...context,
        hasPackageJson: false, // Would need to check
        hasPyproject: false,   // Would need to check
        gitRemote: null        // Would need to extract
      };

      await this.worker.createEnhancementJob(readme, repoContext);
    }

    logger.info({ jobsCreated: readmeFiles.length }, 'Enhancement jobs created');
  }

  /**
   * Run enhancement on directory
   */
  async runEnhancement(directory: string = this.baseDir): Promise<EnhancementResult> {
    logStart(logger, 'schema enhancement pipeline', { directory });

    const startTime = Date.now();

    try {
      // Scan for README files
      const readmeFiles = await this.scanDirectory(directory);

      if (readmeFiles.length === 0) {
        logger.warn({ directory }, 'No README files found');
        return {
          status: 'completed',
          readmesFound: 0,
          enhanced: 0
        };
      }

      // Create enhancement jobs
      await this.createEnhancementJobs(readmeFiles);

      // Wait for completion
      await this.waitForCompletion();

      const duration = Date.now() - startTime;
      const stats = this.worker.getEnhancementStats();
      const jobStats = this.getStats();

      // Generate summary report
      await this.worker.generateSummaryReport();

      logger.info({
        duration,
        stats,
        jobStats
      }, 'Schema enhancement pipeline completed');

      return {
        status: 'completed',
        duration,
        ...stats,
        jobs: jobStats
      };
    } catch (error) {
      logError(logger, error, 'Schema enhancement pipeline failed');
      throw error;
    }
  }

  /**
   * Schedule enhancement runs
   */
  scheduleEnhancements(cronSchedule: string = '0 3 * * 0') {
    return this.scheduleCron(logger, 'schema enhancement', cronSchedule, () => this.runEnhancement());
  }
}

// Run if executed directly
if (isDirectExecution(import.meta.url)) {
  const cronSchedule = process.env.SCHEMA_ENHANCEMENT_CRON_SCHEDULE || '0 3 * * 0'; // Sunday 3 AM

  // Parse command line arguments
  const args = process.argv.slice(PROCESS.ARGV_START);
  const options: SchemaEnhancementOptions = {
    dryRun: false,
    gitWorkflowEnabled: config.enableGitWorkflow
  };

  let directory: string = config.codeBaseDir || config.homeDir;
  let runNow = config.runOnStartup;

  for (let i = 0; i < args.length; i++) {
    if (args[i] === '--run-now' || args[i] === '--run') {
      runNow = true;
    } else if (args[i] === '--dry-run') {
      options.dryRun = true;
    } else if (args[i] === '--dir' && args[i + 1]) {
      directory = args[i + 1];
      i++;
    } else if (args[i] === '--git-workflow') {
      options.gitWorkflowEnabled = true;
    } else if (args[i] === '--no-git-workflow') {
      options.gitWorkflowEnabled = false;
    }
  }

  const pipeline = new SchemaEnhancementPipeline(options);

  if (runNow) {
    logger.info({ directory, options }, 'Running schema enhancement immediately');

    pipeline.runEnhancement(directory)
      .then((result) => {
        logger.info({ result }, 'Enhancement completed successfully');
        process.exit(0);
      })
      .catch((error: unknown) => {
        logError(logger, error, 'Enhancement failed');
        process.exit(1);
      });
  } else {
    logStart(logger, 'schema enhancement pipeline in scheduled mode', { cronSchedule });
    pipeline.scheduleEnhancements(cronSchedule);
    logger.info('Schema enhancement pipeline running. Press Ctrl+C to stop.');
  }
}

export { SchemaEnhancementPipeline };

