// file: sidequest/pipeline-runners/duplicate-detection-pipeline.ts
#!/usr/bin/env -S npx tsx

/**
 * Duplicate Detection Pipeline - TypeScript Version
 *
 * Automated duplicate detection scanning system with cron scheduling.
 * Scans repositories on a configured schedule, detects duplicates, generates reports.
 *
 * Usage:
 *   tsx duplicate-detection-pipeline.ts                    # Start cron server
 *   RUN_ON_STARTUP=true tsx duplicate-detection-pipeline.ts # Run immediately
 */

import { DuplicateDetectionWorker } from '../workers/duplicate-detection-worker.ts';
import { createComponentLogger } from '../utils/logger.ts';
import { config } from '../core/config.ts';
import { TIMEOUTS } from '../core/constants.ts';
// @ts-ignore - no declaration file for node-cron
import cron from 'node-cron';
import * as Sentry from '@sentry/node';
import { isDirectExecution } from '../utils/execution-helpers.ts';

import type { Logger } from 'pino';

const logger: Logger = createComponentLogger('DuplicateDetectionPipeline');

// Re-export worker and types for any external consumers.
// Types previously re-exported here (JobStatus, ScanType, JobData, ScanResult,
// DuplicateGroup, Suggestion, PRCreationResult, JobResult, Inter/IntraProjectScanJobResult)
// are now imported directly from '../pipeline-core/types/duplicate-detection-types.ts'.
export { DuplicateDetectionWorker };
export type {
  RetryInfo,
  RetryMetrics,
  WorkerScanMetrics,
  DuplicateDetectionWorkerOptions
} from '../pipeline-core/types/duplicate-detection-types.ts';

/**
 * Main execution
 */
async function main(): Promise<void> {
  const cronSchedule = process.env.DUPLICATE_SCAN_CRON_SCHEDULE || '0 2 * * *';
  const runOnStartup = config.runOnStartup;

  logger.info({ cronSchedule, runOnStartup }, 'Starting duplicate detection pipeline');

  try {
    // Initialize worker
    const worker = new DuplicateDetectionWorker({
      maxConcurrentScans: 3
    });

    await worker.initialize();

    logger.info('Duplicate detection pipeline initialized');

    const stats = worker.configLoader.getStats();
    logger.info({
      totalRepositories: stats.totalRepositories,
      enabledRepositories: stats.enabledRepositories,
      repositoryGroups: stats.groups
    }, 'Loaded duplicate-detection configuration');

    // Schedule cron job
    if (!runOnStartup) {
      logger.info({ cronSchedule }, 'Scheduling nightly duplicate scans');

      cron.schedule(cronSchedule, async () => {
        logger.info('Cron job triggered');
        try {
          await worker.runNightlyScan();
        } catch (error) {
          logger.error({ error }, 'Nightly scan failed');
          Sentry.captureException(error);
        }
      });

      logger.info('Duplicate detection scheduler is running');

      // Notify PM2 that process is ready (fork mode)
      if (process.send) {
        process.send('ready');
        logger.info('Sent ready signal to PM2');
      }

      // Keep-alive: prevent process from exiting
      // The cron scheduler keeps the event loop active, but we add this as a safeguard
      setInterval(() => {
        logger.debug('Worker keep-alive heartbeat');
      }, TIMEOUTS.FIVE_MINUTES_MS);
    } else {
      logger.info('Running scan immediately (runOnStartup=true)');
      await worker.runNightlyScan();

      const metrics = worker.getScanMetrics();
      logger.info({
        totalScans: metrics.totalScans,
        duplicatesFound: metrics.totalDuplicatesFound,
        suggestionsGenerated: metrics.totalSuggestionsGenerated,
        highImpactDuplicates: metrics.highImpactDuplicates
      }, 'Startup scan completed');

      if (worker.enablePRCreation) {
        logger.info({
          prsCreated: metrics.prsCreated,
          prCreationErrors: metrics.prCreationErrors
        }, 'PR creation metrics');
      }

      process.exit(0);
    }

  } catch (error) {
    logger.error({ error, message: (error as Error).message }, 'Pipeline initialization failed');
    Sentry.captureException(error);
    process.exit(1);
  }
}

// PM2 loads this file via dynamic import(), so process.argv[1] points to
// PM2's ProcessContainerFork, not this script. Detect PM2 via pm_id env var.
if (isDirectExecution(import.meta.url) || process.env.pm_id !== undefined) {
  main().catch((error) => {
    logger.error({ error }, 'Fatal error in duplicate detection pipeline');
    process.exit(1);
  });
}

// file: sidequest/pipeline-runners/base-pipeline.ts
import type { Job, JobStats } from '../core/server.ts';
import { SidequestServer } from '../core/server.ts';
import { JOB_EVENTS, RETRY_EVENTS } from '../core/constants.ts';
import { logError } from '../utils/logger.ts';
import cron from 'node-cron';
import type { Logger } from 'pino';

export type { Job, JobStats };

/**
 * Base class for pipeline runners that wrap a SidequestServer worker.
 * Provides shared waitForCompletion(), scheduleCron(), and getStats().
 */
export abstract class BasePipeline<TWorker extends SidequestServer = SidequestServer> {
  protected worker: TWorker;

  /**
   * constructor.
   */
  constructor(worker: TWorker) {
    this.worker = worker;
  }

  /**
   * Wait for all queued and active jobs to drain using events.
   * Listens for job:completed, job:failed, and retry:created to avoid
   * polling race conditions and premature resolution during retries.
   * Precondition: all jobs must be enqueued before calling this method.
   */
  waitForCompletion(): Promise<void> {
    return new Promise<void>((resolve) => {
      /**
       * cleanup.
       */
      const cleanup = () => {
        this.worker.off(JOB_EVENTS.COMPLETED, checkAndResolve);
        this.worker.off(JOB_EVENTS.FAILED, checkAndResolve);
        this.worker.off(RETRY_EVENTS.CREATED, checkAndResolve);
      };

      /**
       * checkAndResolve.
       */
      const checkAndResolve = () => {
        const stats = this.worker.getStats();
        if (stats.active === 0 && stats.queued === 0 && stats.pendingRetries === 0) {
          cleanup();
          resolve();
        }
      };

      // Register listeners before checking to avoid missing events between
      // the check and registration.
      this.worker.on(JOB_EVENTS.COMPLETED, checkAndResolve);
      this.worker.on(JOB_EVENTS.FAILED, checkAndResolve);
      this.worker.on(RETRY_EVENTS.CREATED, checkAndResolve);
      // Immediate check handles already-drained case.
      checkAndResolve();
    });
  }

  /**
   * Schedule a cron job with validation, logging, and error handling.
   */
  protected scheduleCron(
    logger: Logger,
    name: string,
    cronSchedule: string,
    runFn: () => Promise<unknown>
  ): cron.ScheduledTask {
    if (!cron.validate(cronSchedule)) {
      throw new Error(`Invalid cron schedule: ${cronSchedule}`);
    }

    logger.info({ cronSchedule }, `Scheduling ${name}`);

    const task = cron.schedule(cronSchedule, async () => {
      logger.info(`Cron triggered - starting ${name}`);
      try {
        await runFn();
      } catch (error) {
        logError(logger, error, `Scheduled ${name} failed`);
      }
    });

    logger.info(`${name} scheduled`);
    return task;
  }

  /**
   * Register standard event listeners for CREATED, STARTED, COMPLETED, FAILED.
   *
   * @param logger Pipeline-specific logger instance.
   * @param handlers Optional per-event data extractors. Each returns extra fields to log.
   */
  protected setupDefaultEventListeners(
    logger: Logger,
    handlers?: {
      onCreated?: (job: Job) => Record<string, unknown>;
      onStarted?: (job: Job) => Record<string, unknown>;
      onCompleted?: (job: Job) => Record<string, unknown>;
      onFailed?: (job: Job) => Record<string, unknown>;
    }
  ): void {
    this.worker.on(JOB_EVENTS.CREATED, (job: Job) => {
      logger.info({ jobId: job.id, ...handlers?.onCreated?.(job) }, 'Job created');
    });

    this.worker.on(JOB_EVENTS.STARTED, (job: Job) => {
      logger.info({ jobId: job.id, ...handlers?.onStarted?.(job) }, 'Job started');
    });

    this.worker.on(JOB_EVENTS.COMPLETED, (job: Job) => {
      const duration = job.completedAt && job.startedAt
        ? job.completedAt.getTime() - job.startedAt.getTime()
        : undefined;
      logger.info({ jobId: job.id, duration, ...handlers?.onCompleted?.(job) }, 'Job completed');
    });

    this.worker.on(JOB_EVENTS.FAILED, (job: Job) => {
      logError(logger, job.error, 'Job failed', { jobId: job.id, ...handlers?.onFailed?.(job) });
    });
  }

  /**
   * getStats.
   */
  getStats(): JobStats {
    return this.worker.getStats();
  }
}

