#!/usr/bin/env -S node --strip-types
import { PluginManagerWorker } from '../utils/plugin-manager.ts';
import { config } from '../core/config.ts';
import { createComponentLogger, logError, logStart } from '../utils/logger.ts';
import { BasePipeline, type JobStats } from './base-pipeline.ts';
import { isDirectExecution } from '../utils/execution-helpers.ts';

const logger = createComponentLogger('PluginPipeline');

interface AuditOptions {
  detailed?: boolean;
}

interface AuditRecommendation {
  priority: string;
  type: string;
  message: string;
  action: string;
  details?: Array<{
    category: string;
    plugins: string[];
    suggestion: string;
  }>;
}

interface AuditResult {
  totalPlugins: number;
  duplicateCategories?: Array<{ category: string; count: number }>;
  recommendations?: AuditRecommendation[];
}

/**
 * Plugin Management Pipeline
 * Automatically audits Claude Code plugins on a schedule
 */
class PluginManagementPipeline extends BasePipeline<PluginManagerWorker> {
  /**
   * constructor.
   */
  constructor(options: Record<string, unknown> = {}) {
    super(new PluginManagerWorker({
      maxConcurrent: 1,
      logDir: config.logDir,
      sentryDsn: config.sentryDsn,
      ...options
    }));

    this.setupDefaultEventListeners(logger, {
      onStarted: (job) => ({ detailed: (job.data as Record<string, unknown>).detailed }),
      onCompleted: (job) => {
        const result = job.result as unknown as AuditResult;
        this.displayRecommendations(result);
        return {
          totalPlugins: result.totalPlugins,
          duplicateCategories: result.duplicateCategories?.length ?? 0,
          recommendations: result.recommendations?.length ?? 0
        };
      }
    });
  }

  /**
   * Display audit recommendations
   */
  private displayRecommendations(result: AuditResult): void {
    if (!result.recommendations || result.recommendations.length === 0) {
      return;
    }

    logger.info('\n╔════════════════════════════════════════════════════════════════╗');
    logger.info('║          Plugin Audit Recommendations                          ║');
    logger.info('╚════════════════════════════════════════════════════════════════╝\n');

    result.recommendations.forEach((rec) => {
      const priorityIcon: Record<string, string> = {
        high: '🔴',
        medium: '🟡',
        info: '✅'
      };
      const icon = priorityIcon[rec.priority] || '📌';

      logger.info(`${icon} [${rec.priority.toUpperCase()}] ${rec.type}`);
      logger.info(`   ${rec.message}`);
      logger.info(`   Action: ${rec.action}`);

      if (rec.details) {
        logger.info('   Details:');
        rec.details.forEach((detail) => {
          logger.info(`     • ${detail.category}: ${detail.plugins.join(', ')}`);
          logger.info(`       → ${detail.suggestion}`);
        });
      }
      logger.info('');
    });
  }

  /**
   * Run a single audit
   */
  async runAudit(options: AuditOptions = {}): Promise<JobStats> {
    logStart(logger, 'plugin audit', { options });

    const startTime = Date.now();

    try {
      // Create audit job
      const job = this.worker.addJob({
        detailed: options.detailed ?? false
      });

      logger.info({ jobId: job.id }, 'Audit job created');

      // Wait for completion
      await this.waitForCompletion();

      const duration = Date.now() - startTime;
      const stats = this.getStats();

      logger.info({
        duration,
        stats
      }, 'Plugin audit pipeline completed');

      return stats;
    } catch (error) {
      logError(logger, error, 'Plugin audit pipeline failed');
      throw error;
    }
  }

  /**
   * Schedule automatic plugin audits
   */
  scheduleAudits(cronSchedule: string = '0 9 * * 1') {
    return this.scheduleCron(logger, 'plugin audit', cronSchedule, () => this.runAudit({ detailed: false }));
  }
}

// Run if executed directly
if (isDirectExecution(import.meta.url)) {
  const pipeline = new PluginManagementPipeline();

  const runOnStartup = config.runOnStartup;
  const detailed = process.env.DETAILED === 'true';
  const pluginCronSchedule = process.env.PLUGIN_CRON_SCHEDULE || '0 9 * * 1'; // Monday 9 AM

  if (runOnStartup) {
    logger.info({ detailed }, 'Running plugin audit immediately');

    pipeline.runAudit({ detailed })
      .then(() => {
        logger.info('Plugin audit completed successfully');
        process.exit(0);
      })
      .catch((error: unknown) => {
        logError(logger, error, 'Plugin audit failed');
        process.exit(1);
      });
  } else {
    logStart(logger, 'plugin audit scheduler', { cronSchedule: pluginCronSchedule });
    pipeline.scheduleAudits(pluginCronSchedule);

    // Keep process alive
    logger.info('Plugin audit scheduler running. Press Ctrl+C to exit.');
  }

  // Graceful shutdown
  process.on('SIGINT', () => {
    logger.info('Received SIGINT, shutting down...');
    process.exit(0);
  });

  process.on('SIGTERM', () => {
    logger.info('Received SIGTERM, shutting down...');
    process.exit(0);
  });
}

export { PluginManagementPipeline };

// file: sidequest/pipeline-runners/git-activity-pipeline.ts
#!/usr/bin/env -S node --strip-types
import { GitActivityWorker } from '../workers/git-activity-worker.ts';
import { config } from '../core/config.ts';
import { CONCURRENCY, GIT_ACTIVITY, NUMBER_BASE, PROCESS } from '../core/constants.ts';
import { createComponentLogger, logError, logStart } from '../utils/logger.ts';
import { BasePipeline, type Job, type JobStats } from './base-pipeline.ts';
import { isDirectExecution } from '../utils/execution-helpers.ts';

const logger = createComponentLogger('GitActivityPipeline');

export interface ReportOptions {
  reportType?: string;
  sinceDate?: string;
  untilDate?: string;
  days?: number;
}

const ISO_DATE_PATTERN = /^\d{4}-\d{2}-\d{2}$/;
type DefaultReportType =
  | typeof GIT_ACTIVITY.WEEKLY_REPORT_TYPE
  | typeof GIT_ACTIVITY.MONTHLY_REPORT_TYPE;

const VALID_DEFAULT_REPORT_TYPES = new Set<DefaultReportType>([
  GIT_ACTIVITY.WEEKLY_REPORT_TYPE,
  GIT_ACTIVITY.MONTHLY_REPORT_TYPE
]);

function isDefaultReportType(reportType: string | undefined): reportType is DefaultReportType {
  return reportType !== undefined && VALID_DEFAULT_REPORT_TYPES.has(reportType as DefaultReportType);
}

interface ParsedCliArgs {
  options: ReportOptions;
  runNow: boolean;
  errors: string[];
}

const JOB_SELECTION_STRATEGY = {
  CUSTOM: 'custom',
  MONTHLY: 'monthly',
  WEEKLY: 'weekly',
  GENERIC: 'generic'
} as const;

type JobSelectionStrategy =
  (typeof JOB_SELECTION_STRATEGY)[keyof typeof JOB_SELECTION_STRATEGY];

interface JobSelection {
  strategy: JobSelectionStrategy;
  options: ReportOptions;
}

interface OutputFile {
  path: string;
  size: number;
  exists: boolean;
}

interface JobData {
  reportType?: string;
  days?: number;
}

interface JobResult {
  reportType: string;
  stats: {
    totalCommits: number;
    totalRepositories: number;
  };
  outputFiles: OutputFile[];
}

/**
 * Git Activity Report Pipeline
 * Automatically generates git activity reports on a schedule
 */
class GitActivityPipeline extends BasePipeline<GitActivityWorker> {
  private reportType: string;

  /**
   * constructor.
   */
  constructor(options: Record<string, unknown> = {}) {
    super(new GitActivityWorker({
      maxConcurrent: config.maxConcurrent ?? CONCURRENCY.DEFAULT_IO_BOUND,
      logDir: config.logDir,
      sentryDsn: config.sentryDsn,
      codeBaseDir: config.codeBaseDir,
      ...options
    }));

    const configuredReportType = options.reportType as string | undefined;
    this.reportType = isDefaultReportType(configuredReportType)
      ? configuredReportType
      : GIT_ACTIVITY.DEFAULT_REPORT_TYPE;
    this.setupDefaultEventListeners(logger, {
      onCreated: (job) => ({ reportType: (job.data as unknown as JobData).reportType }),
      onStarted: (job) => {
        const data = job.data as unknown as JobData;
        return { reportType: data.reportType, days: data.days };
      },
      onCompleted: (job) => {
        const result = job.result as unknown as JobResult;
        // Log output file locations
        result.outputFiles.forEach((file: OutputFile) => {
          if (file.exists) {
            logger.info({ path: file.path, size: file.size }, 'Output file generated');
          }
        });
        return {
          reportType: result.reportType,
          totalCommits: result.stats.totalCommits,
          totalRepositories: result.stats.totalRepositories,
          filesGenerated: result.outputFiles.length
        };
      }
    });
  }

  /**
   * Run a single report
   */
  async runReport(options: ReportOptions = {}): Promise<JobStats> {
    logStart(logger, 'git activity report', { options });

    const startTime = Date.now();

    try {
      // Create job based on options
      let job: Job;

      const selection = selectGitActivityJob(options, this.reportType);
      if (selection.strategy === JOB_SELECTION_STRATEGY.CUSTOM) {
        job = this.worker.createCustomReportJob(selection.options.sinceDate!, selection.options.untilDate!);
      } else if (selection.strategy === JOB_SELECTION_STRATEGY.MONTHLY) {
        job = this.worker.createMonthlyReportJob();
      } else if (selection.strategy === JOB_SELECTION_STRATEGY.WEEKLY) {
        job = this.worker.createWeeklyReportJob();
      } else {
        job = this.worker.createReportJob(selection.options);
      }

      logger.info({ jobId: job.id }, 'Report job created');

      // Wait for completion
      await this.waitForCompletion();

      const duration = Date.now() - startTime;
      const stats = this.getStats();

      logger.info({
        duration,
        stats
      }, 'Git activity report pipeline completed');

      return stats;
    } catch (error) {
      logError(logger, error, 'Git activity report pipeline failed');
      throw error;
    }
  }

  /**
   * Schedule weekly reports
   */
  scheduleWeeklyReports(cronSchedule: string = GIT_ACTIVITY.DEFAULT_WEEKLY_CRON) {
    return this.scheduleCron(
      logger,
      'weekly git activity report',
      cronSchedule,
      () => this.runReport({ reportType: GIT_ACTIVITY.WEEKLY_REPORT_TYPE })
    );
  }

  /**
   * Schedule monthly reports
   */
  scheduleMonthlyReports(cronSchedule: string = GIT_ACTIVITY.DEFAULT_MONTHLY_CRON) {
    return this.scheduleCron(
      logger,
      'monthly git activity report',
      cronSchedule,
      () => this.runReport({ reportType: GIT_ACTIVITY.MONTHLY_REPORT_TYPE })
    );
  }
}

export function selectGitActivityJob(
  options: ReportOptions,
  defaultReportType: string = GIT_ACTIVITY.DEFAULT_REPORT_TYPE
): JobSelection {
  const normalizedOptions: ReportOptions = {
    ...options,
    reportType: options.reportType ?? defaultReportType
  };

  if (normalizedOptions.sinceDate) {
    return normalizedOptions.untilDate
      ? { strategy: JOB_SELECTION_STRATEGY.CUSTOM, options: normalizedOptions }
      : { strategy: JOB_SELECTION_STRATEGY.GENERIC, options: normalizedOptions };
  }

  if (
    normalizedOptions.reportType === GIT_ACTIVITY.MONTHLY_REPORT_TYPE
    || normalizedOptions.days === GIT_ACTIVITY.MONTHLY_WINDOW_DAYS
  ) {
    return { strategy: JOB_SELECTION_STRATEGY.MONTHLY, options: normalizedOptions };
  }

  if (
    normalizedOptions.reportType === GIT_ACTIVITY.WEEKLY_REPORT_TYPE
    || normalizedOptions.days === GIT_ACTIVITY.WEEKLY_WINDOW_DAYS
  ) {
    return { strategy: JOB_SELECTION_STRATEGY.WEEKLY, options: normalizedOptions };
  }

  return { strategy: JOB_SELECTION_STRATEGY.GENERIC, options: normalizedOptions };
}

export function parseGitActivityCliArgs(args: string[], runOnStartup: boolean): ParsedCliArgs {
  const options: ReportOptions = {};
  const errors: string[] = [];
  let runNow = runOnStartup;

  for (let i = 0; i < args.length; i++) {
    const arg = args[i];
    if (arg === '--run-now' || arg === '--run') {
      runNow = true;
    } else if (arg === '--weekly') {
      options.reportType = GIT_ACTIVITY.WEEKLY_REPORT_TYPE;
    } else if (arg === '--monthly') {
      options.reportType = GIT_ACTIVITY.MONTHLY_REPORT_TYPE;
    } else if (arg === '--start-date' || arg === '--since') {
      if (!args[i + 1] || args[i + 1].startsWith('--')) {
        errors.push(`${arg} requires a YYYY-MM-DD value`);
        continue;
      }
      options.sinceDate = args[i + 1];
      i++;
    } else if (arg === '--end-date' || arg === '--until') {
      if (!args[i + 1] || args[i + 1].startsWith('--')) {
        errors.push(`${arg} requires a YYYY-MM-DD value`);
        continue;
      }
      options.untilDate = args[i + 1];
      i++;
    } else if (arg === '--days') {
      if (!args[i + 1] || args[i + 1].startsWith('--')) {
        errors.push('--days requires a positive integer value');
        continue;
      }
      const parsedDays = parseInt(args[i + 1], NUMBER_BASE.DECIMAL);
      if (Number.isNaN(parsedDays) || parsedDays <= 0) {
        errors.push(`--days must be a positive integer (received: ${args[i + 1]})`);
      } else {
        options.days = parsedDays;
      }
      i++;
    } else if (arg.startsWith('--')) {
      errors.push(`Unknown flag: ${arg}`);
    } else {
      errors.push(`Unexpected positional argument: ${arg}`);
    }
  }

  if (options.untilDate && !options.sinceDate) {
    errors.push('--end-date requires --start-date');
  }
  if (options.sinceDate && !ISO_DATE_PATTERN.test(options.sinceDate)) {
    errors.push(`--start-date must match YYYY-MM-DD (received: ${options.sinceDate})`);
  }
  if (options.untilDate && !ISO_DATE_PATTERN.test(options.untilDate)) {
    errors.push(`--end-date must match YYYY-MM-DD (received: ${options.untilDate})`);
  }

  return { options, runNow, errors };
}

// Run if executed directly
if (isDirectExecution(import.meta.url)) {
  const pipeline = new GitActivityPipeline();

  const weeklyCronSchedule = process.env.GIT_CRON_SCHEDULE || GIT_ACTIVITY.DEFAULT_WEEKLY_CRON; // Sunday 8 PM
  const monthlyCronSchedule = process.env.GIT_MONTHLY_CRON_SCHEDULE || GIT_ACTIVITY.DEFAULT_MONTHLY_CRON; // 1st of month 8 AM

  const args = process.argv.slice(PROCESS.ARGV_START);
  const { options, runNow, errors } = parseGitActivityCliArgs(args, config.runOnStartup);
  if (errors.length > 0) {
    logger.error({ args, errors }, 'Invalid CLI options');
    process.exit(1);
  }

  if (runNow) {
    logger.info('Running git activity report immediately');

    // Default to weekly if no options specified
    if (!options.reportType && !options.sinceDate && !options.days) {
      options.reportType = GIT_ACTIVITY.DEFAULT_REPORT_TYPE;
    }

    pipeline.runReport(options)
      .then(() => {
        logger.info('Report completed successfully');
        process.exit(0);
      })
      .catch((error: unknown) => {
        logError(logger, error, 'Report failed');
        process.exit(1);
      });
  } else {
    logStart(logger, 'git activity pipeline in scheduled mode', {
      weeklyCronSchedule,
      monthlyCronSchedule
    });
    pipeline.scheduleWeeklyReports(weeklyCronSchedule);
    pipeline.scheduleMonthlyReports(monthlyCronSchedule);
    logger.info('Git activity pipeline running. Press Ctrl+C to stop.');
  }
}

export { GitActivityPipeline };

// file: sidequest/pipeline-runners/dashboard-populate-pipeline.ts
#!/usr/bin/env -S node --strip-types

/**
 * Dashboard Populate Pipeline - AlephAuto Integration
 *
 * Runs the quality-metrics-dashboard populate pipeline on a schedule.
 * Derives rule-based and LLM-based metrics from Claude Code session telemetry,
 * then syncs aggregated results to Cloudflare KV.
 */

import { DashboardPopulateWorker } from '../workers/dashboard-populate-worker.ts';
import { createComponentLogger, logError } from '../utils/logger.ts';
import * as Sentry from '@sentry/node';
import cron from 'node-cron';
import type { Job } from '../core/server.ts';
import { JOB_EVENTS, NUMBER_BASE, PROCESS, TIMEOUTS } from '../core/constants.ts';
import { isDirectExecution } from '../utils/execution-helpers.ts';

const logger = createComponentLogger('DashboardPopulatePipeline');

const CRON_SCHEDULE = process.env.DASHBOARD_CRON_SCHEDULE || '0 6,18 * * *';

// Parse CLI args
const args = process.argv.slice(PROCESS.ARGV_START);
const RUN_WITH_CRON = args.includes('--cron');
const RUN_ON_STARTUP = process.env.RUN_ON_STARTUP === 'true'
  || args.includes('--run-now')
  || args.includes('--run');

interface CliOptions {
  seed: boolean;
  dryRun: boolean;
  skipJudge: boolean;
  skipSync: boolean;
  limit: number | undefined;
}

const cliOptions: CliOptions = {
  seed: !args.includes('--no-seed'),
  dryRun: args.includes('--dry-run'),
  skipJudge: args.includes('--skip-judge'),
  skipSync: args.includes('--skip-sync'),
  limit: undefined
};

const limitIdx = args.indexOf('--limit');
if (limitIdx !== -1 && args[limitIdx + 1]) {
  cliOptions.limit = parseInt(args[limitIdx + 1], NUMBER_BASE.DECIMAL);
}

if (process.env.DASHBOARD_SEED === 'false') {
  cliOptions.seed = false;
}

function waitForJobTerminalStatus(worker: DashboardPopulateWorker, jobId: string): Promise<void> {
  return new Promise((resolve, reject) => {
    let timeoutHandle: NodeJS.Timeout | null = null;

    const cleanup = () => {
      if (timeoutHandle) {
        clearTimeout(timeoutHandle);
      }
      worker.off(JOB_EVENTS.COMPLETED, onCompleted);
      worker.off(JOB_EVENTS.FAILED, onFailed);
    };

    const rejectWithFailure = (job: Job) => {
      const message = job.error?.message ?? `Startup dashboard job ${job.id} failed`;
      cleanup();
      reject(new Error(message));
    };

    const onCompleted = (job: Job) => {
      if (job.id !== jobId) return;
      cleanup();
      resolve();
    };

    const onFailed = (job: Job) => {
      if (job.id !== jobId) return;
      rejectWithFailure(job);
    };

    worker.on(JOB_EVENTS.COMPLETED, onCompleted);
    worker.on(JOB_EVENTS.FAILED, onFailed);

    timeoutHandle = setTimeout(() => {
      cleanup();
      reject(new Error(`Timed out waiting for startup dashboard job ${jobId} after ${TIMEOUTS.ONE_HOUR_MS}ms`));
    }, TIMEOUTS.ONE_HOUR_MS);

    const currentJob = worker.getJob(jobId);
    if (!currentJob) {
      cleanup();
      reject(new Error(`Startup dashboard job ${jobId} was not found after creation`));
      return;
    }
    if (currentJob.status === 'completed') {
      cleanup();
      resolve();
      return;
    }
    if (currentJob.status === 'failed') {
      rejectWithFailure(currentJob);
    }
  });
}

/**
 * main.
 */
async function main(): Promise<void> {
  logger.info({
    cronSchedule: CRON_SCHEDULE,
    seed: cliOptions.seed,
    dryRun: cliOptions.dryRun,
    runOnStartup: RUN_ON_STARTUP
  }, 'Starting Dashboard Populate Pipeline');

  const worker = new DashboardPopulateWorker({ maxConcurrent: 1 });

  worker.on(JOB_EVENTS.CREATED, (job: Job) => {
    logger.info({
      jobId: job.id,
      seed: job.data.seed,
      dryRun: job.data.dryRun
    }, 'Job created');
  });

  worker.on(JOB_EVENTS.STARTED, (job: Job) => {
    logger.info({ jobId: job.id }, 'Job started');
  });

  worker.on(JOB_EVENTS.COMPLETED, (job: Job) => {
    const result = job.result as Record<string, unknown> | null;
    const durationMs = result?.durationMs;
    const steps = result?.steps as Array<unknown> | undefined;
    logger.info({
      jobId: job.id,
      durationMs,
      steps: steps?.length ?? 0
    }, 'Job completed');
  });

  worker.on(JOB_EVENTS.FAILED, (job: Job) => {
    logError(logger, job.error, 'Job failed', { jobId: job.id, retryCount: job.retryCount });
    Sentry.captureException(new Error(job.error?.message ?? 'Unknown error'), {
      tags: { component: 'dashboard-populate-pipeline', job_id: job.id }
    });
  });

  let startupJob: Job | null = null;

  if (RUN_ON_STARTUP) {
    logger.info({ ...cliOptions }, 'Running populate immediately');
    try {
      startupJob = worker.createPopulateJob(cliOptions);
    } catch (error) {
      logError(logger, error, 'Failed to create startup job');
      Sentry.captureException(error, {
        tags: { component: 'dashboard-populate-pipeline', phase: 'startup' }
      });
      if (!RUN_WITH_CRON) {
        throw error;
      }
    }
  }

  if (RUN_ON_STARTUP && !RUN_WITH_CRON) {
    if (!startupJob) {
      throw new Error('Startup dashboard populate job was not created');
    }
    logger.info({ jobId: startupJob.id }, 'Waiting for startup dashboard job to finish');
    await waitForJobTerminalStatus(worker, startupJob.id);
    logger.info({ jobId: startupJob.id }, 'Startup dashboard job completed; exiting');
    return;
  }

  logger.info({ schedule: CRON_SCHEDULE }, 'Scheduling dashboard populate');

  cron.schedule(CRON_SCHEDULE, () => {
    logger.info('Cron triggered dashboard populate');
    try {
      worker.createPopulateJob(cliOptions);
    } catch (error) {
      logError(logger, error, 'Failed to create scheduled job');
      Sentry.captureException(error, {
        tags: { component: 'dashboard-populate-pipeline', phase: 'cron' }
      });
    }
  });

  logger.info('Dashboard Populate Pipeline is running');

  process.on('SIGTERM', () => {
    logger.info('Received SIGTERM, shutting down gracefully');
    process.exit(0);
  });

  process.on('SIGINT', () => {
    logger.info('Received SIGINT, shutting down gracefully');
    process.exit(0);
  });
}

if (isDirectExecution(import.meta.url)) {
  main().catch((error) => {
    logError(logger, error, 'Fatal error in dashboard populate pipeline');
    Sentry.captureException(error, {
      tags: { component: 'dashboard-populate-pipeline', phase: 'startup' }
    });
    process.exit(1);
  });
}

