/**
 * Error Helper Utilities
 *
 * Provides safe error message extraction and error object conversion
 * to prevent cascading TypeErrors when handling errors.
 *
 * @module lib/utils/error-helpers
 */

interface ToErrorObjectOptions {
  fallbackMessage?: string;
  metadata?: Record<string, unknown>;
}

interface ErrorObject {
  message: string;
  stack: string | undefined;
  type: string;
  isError: boolean;
  metadata: Record<string, unknown>;
  name?: string;
  code?: unknown;
}

interface SerializedError {
  message: string;
  type: string;
  name?: string;
  stack?: string;
  cause?: SerializedError;
  code?: unknown;
}

interface FormatErrorOptions {
  includeType?: boolean;
  includeCode?: boolean;
}

/**
 * Safe error message.
 *
 * @param {unknown} error - The error
 * @param {*} [fallback='Unknown error'] - Fallback value
 *
 * @returns {string} The resulting string
 */
export function safeErrorMessage(error: unknown, fallback = 'Unknown error'): string {
  // Handle null/undefined
  if (error === null || error === undefined) {
    return fallback;
  }

  // Handle Error objects (standard and custom)
  if (error instanceof Error) {
    return error.message || fallback;
  }

  // Handle error-like objects with message property
  if (typeof error === 'object' && 'message' in error && typeof (error as { message: unknown }).message === 'string') {
    return (error as { message: string }).message || fallback;
  }

  // Handle strings
  if (typeof error === 'string') {
    return error || fallback;
  }

  // Handle primitives and other objects
  try {
    const stringified = String(error);
    // Avoid unhelpful '[object Object]' messages
    if (stringified === '[object Object]') {
      return JSON.stringify(error);
    }
    return stringified;
  } catch {
    return fallback;
  }
}

/**
 * Safe error stack.
 *
 * @param {unknown} error - The error
 *
 * @returns {string | undefined} The resulting string
 */
export function safeErrorStack(error: unknown): string | undefined {
  if (error === null || error === undefined) {
    return undefined;
  }

  // Handle Error objects
  if (error instanceof Error && error.stack) {
    return error.stack;
  }

  // Handle error-like objects with stack property
  if (typeof error === 'object' && 'stack' in error && typeof (error as { stack: unknown }).stack === 'string') {
    return (error as { stack: string }).stack;
  }

  return undefined;
}

/**
 * To error object.
 *
 * @param {unknown} error - The error
 * @param {ToErrorObjectOptions} [options={}] - Options dictionary
 *
 * @returns {ErrorObject} The ErrorObject
 */
export function toErrorObject(error: unknown, options: ToErrorObjectOptions = {}): ErrorObject {
  const {
    fallbackMessage = 'Unknown error',
    metadata = {}
  } = options;

  const errorObj: ErrorObject = {
    message: safeErrorMessage(error, fallbackMessage),
    stack: safeErrorStack(error),
    type: getErrorType(error),
    isError: error instanceof Error,
    metadata
  };

  // Include error name if available
  if (error instanceof Error && error.name) {
    errorObj.name = error.name;
  }

  // Include error code if available (for system errors, etc.)
  if (error && typeof error === 'object' && 'code' in error) {
    errorObj.code = (error as { code: unknown }).code;
  }

  return errorObj;
}

/**
 * Get the error type.
 *
 * @param {unknown} error - The error
 *
 * @returns {string} The error type
 */
function getErrorType(error: unknown): string {
  if (error === null || error === undefined) {
    return error === null ? 'null' : 'undefined';
  }

  if (error instanceof Error) {
    return error.constructor.name || 'Error';
  }

  return typeof error;
}

/**
 * Check if error like.
 *
 * @param {unknown} value - The value
 *
 * @returns {boolean} True if error like, False otherwise
 */
export function isErrorLike(value: unknown): boolean {
  if (value instanceof Error) {
    return true;
  }

  if (value && typeof value === 'object') {
    return 'message' in value || 'stack' in value;
  }

  return false;
}

/**
 * Serialize error.
 *
 * @param {unknown} error - The error
 * @param {*} [includeStack=true] - The includeStack
 *
 * @returns {SerializedError} The SerializedError
 */
export function serializeError(error: unknown, includeStack = true): SerializedError {
  const serialized: SerializedError = {
    message: safeErrorMessage(error),
    type: getErrorType(error)
  };

  if (error instanceof Error) {
    serialized.name = error.name;
    if (includeStack && error.stack) {
      serialized.stack = error.stack;
    }
    if (error.cause) {
      serialized.cause = serializeError(error.cause, includeStack);
    }
  }

  // Include code for system errors
  if (error && typeof error === 'object' && 'code' in error) {
    serialized.code = (error as { code: unknown }).code;
  }

  return serialized;
}

/**
 * Format error message.
 *
 * @param {unknown} error - The error
 * @param {FormatErrorOptions} [options={}] - Options dictionary
 *
 * @returns {string} The resulting string
 */
export function formatErrorMessage(error: unknown, options: FormatErrorOptions = {}): string {
  const {
    includeType = false,
    includeCode = false
  } = options;

  const message = safeErrorMessage(error);
  const parts: string[] = [];

  if (includeCode && error && typeof error === 'object' && 'code' in error) {
    parts.push(`[${(error as { code: unknown }).code}]`);
  } else if (includeType) {
    parts.push(`[${getErrorType(error)}]`);
  }

  parts.push(message);

  return parts.join(' ');
}

/**
 * Combine errors.
 *
 * @param {unknown[]} errors - The errors
 * @param {*} [separator='; '] - The separator
 *
 * @returns {string} The resulting string
 */
export function combineErrors(errors: unknown[], separator = '; '): string {
  if (!Array.isArray(errors) || errors.length === 0) {
    return 'Unknown error';
  }

  return errors
    .map(error => safeErrorMessage(error))
    .filter(msg => msg && msg !== 'Unknown error')
    .join(separator);
}

// file: sidequest/pipeline-core/scanners/codebase-health-scanner.ts
#!/usr/bin/env node
/**
 * Codebase Health Scanner CLI
 *
 * Command-line interface for running codebase health scans:
 * - Timeout pattern detection
 * - Root directory analysis
 * - Import dependency analysis
 *
 * Based on AlephAuto debugging session: Nov 18, 2025
 *
 * Usage:
 *   node codebase-health-scanner.ts /path/to/repo --scan timeout
 *   node codebase-health-scanner.ts /path/to/repo --scan root
 *   node codebase-health-scanner.ts /path/to/repo --scan all
 *   node codebase-health-scanner.ts /path/to/repo --scan all --output report.md
 *
 * @module lib/scanners/codebase-health-scanner
 */

import { TimeoutPatternDetector } from './timeout-pattern-detector.ts';
import type { TimeoutFindings } from './timeout-pattern-detector.ts';
import { RootDirectoryAnalyzer } from './root-directory-analyzer.ts';
import type { RootDirectoryAnalysis } from './root-directory-analyzer.ts';
import { FORMATTING, PROCESS } from '../../core/constants.ts';
import { createComponentLogger, logError } from '../../utils/logger.ts';
import * as fs from 'fs/promises';
import * as path from 'path';

const logger = createComponentLogger('CodebaseHealthScanner');

interface ScanResults {
  repository: string;
  timestamp: string;
  scans: {
    timeout?: TimeoutFindings;
    root?: RootDirectoryAnalysis;
  };
}

interface HealthScanOptions {
  logger?: typeof logger;
  scanTimeout?: boolean;
  scanRoot?: boolean;
}

/**
 * Print CLI usage details to stderr.
 */
function printUsage(): void {
  const lines = [
    'Usage: node codebase-health-scanner.ts <repo-path> [options]',
    '',
    'Options:',
    '  --scan <type>       Scan type: timeout, root, all (default: all)',
    '  --output <file>     Output file path (markdown report)',
    '  --json              Output JSON instead of markdown',
    '',
    'Examples:',
    '  node codebase-health-scanner.ts ~/code/myproject --scan timeout',
    '  node codebase-health-scanner.ts ~/code/myproject --scan all --output report.md'
  ];

  process.stderr.write(`${lines.join('\n')}\n`);
}

/**
 * Main.
 *
 * @returns {Promise<void>} The Promise<void>
 * @async
 */
async function main(): Promise<void> {
  const args = process.argv.slice(PROCESS.ARGV_START);

  // Parse arguments
  const repoPath = args[0];
  const scanType = args.includes('--scan')
    ? args[args.indexOf('--scan') + 1]
    : 'all';
  const outputFile = args.includes('--output')
    ? args[args.indexOf('--output') + 1]
    : null;
  const jsonOutput = args.includes('--json');

  // Validate repo path
  if (!repoPath) {
    printUsage();
    process.exit(1);
  }

  const resolvedPath = path.resolve(repoPath);

  logger.info(`Starting codebase health scan: ${resolvedPath}`);
  logger.info(`Scan type: ${scanType}`);

  const results: ScanResults = {
    repository: resolvedPath,
    timestamp: new Date().toISOString(),
    scans: {}
  };

  try {
    // Run timeout pattern detection
    if (scanType === 'timeout' || scanType === 'all') {
      logger.info('Running timeout pattern detection...');
      const detector = new TimeoutPatternDetector({ logger });
      const findings = await detector.scan(resolvedPath);
      results.scans.timeout = findings;

      logger.info(
        `Timeout scan complete: ${findings.statistics.total_issues} issues in ${findings.statistics.affected_files} files`
      );
    }

    // Run root directory analysis
    if (scanType === 'root' || scanType === 'all') {
      logger.info('Running root directory analysis...');
      const analyzer = new RootDirectoryAnalyzer({ logger });
      const analysis = await analyzer.analyze(resolvedPath);
      results.scans.root = analysis;

      logger.info(
        `Root analysis complete: ${analysis.statistics.total_root_files} files, ${analysis.statistics.reduction_potential} can be moved`
      );
    }

    // Generate output
    if (jsonOutput) {
      const output = JSON.stringify(results, null, FORMATTING.JSON_INDENT);
      if (outputFile) {
        await fs.writeFile(outputFile, output);
        logger.info(`JSON report saved to: ${outputFile}`);
      } else {
        process.stdout.write(`${output}\n`);
      }
    } else {
      const report = generateMarkdownReport(results);
      if (outputFile) {
        await fs.writeFile(outputFile, report);
        logger.info(`Markdown report saved to: ${outputFile}`);
      } else {
        process.stdout.write(`\n${report}\n`);
      }
    }

    logger.info('Scan complete!');
    process.exit(0);

  } catch (error) {
    logError(logger, error, 'Scan failed');
    process.exit(1);
  }
}

/**
 * Generate the markdown report.
 *
 * @param {ScanResults} results - The results
 *
 * @returns {string} The created markdown report
 */
function generateMarkdownReport(results: ScanResults): string {
  const lines: string[] = [
    '# Codebase Health Report',
    '',
    `**Repository:** ${results.repository}`,
    `**Generated:** ${results.timestamp}`,
    '',
    '---',
    ''
  ];

  // Timeout scan report
  if (results.scans.timeout) {
    const timeout = results.scans.timeout;
    const detector = new TimeoutPatternDetector({ logger });

    lines.push('## Timeout Pattern Detection');
    lines.push('');
    lines.push(detector.generateReport(timeout));
    lines.push('');
  }

  // Root directory analysis report
  if (results.scans.root) {
    const root = results.scans.root;
    const analyzer = new RootDirectoryAnalyzer({ logger });

    lines.push('## Root Directory Analysis');
    lines.push('');
    lines.push(analyzer.generateReport(root));
    lines.push('');
  }

  // Summary
  lines.push('---', '', '## Summary', '');

  if (results.scans.timeout) {
    const stats = results.scans.timeout.statistics;
    lines.push(
      `- **Timeout Issues:** ${stats.total_issues} issues in ${stats.affected_files} files`,
      `  - High: ${stats.severity_breakdown.high || 0}`,
      `  - Medium: ${stats.severity_breakdown.medium || 0}`,
      `  - Low: ${stats.severity_breakdown.low || 0}`,
      ''
    );
  }

  if (results.scans.root) {
    const stats = results.scans.root.statistics;
    lines.push(
      `- **Root Directory:** ${stats.total_root_files} files (${stats.reduction_percentage}% reduction possible)`,
      `  - Can move: ${stats.reduction_potential} files`,
      `  - Final count: ${stats.final_root_files} files`,
      ''
    );
  }

  lines.push(
    '---',
    '',
    '## Next Steps',
    '',
    '1. Review high severity timeout issues first',
    '2. Plan root directory cleanup in phases',
    '3. Create git branch for changes: `git checkout -b health/cleanup`',
    '4. Implement fixes incrementally',
    '5. Test after each phase',
    ''
  );

  return lines.join('\n');
}

/**
 * Run health scan.
 *
 * @param {string} repoPath - The repoPath
 * @param {HealthScanOptions} [options={}] - Options dictionary
 *
 * @returns {Promise<ScanResults>} The Promise<ScanResults>
 * @async
 */
export async function runHealthScan(repoPath: string, options: HealthScanOptions = {}): Promise<ScanResults> {
  const results: ScanResults = {
    repository: path.resolve(repoPath),
    timestamp: new Date().toISOString(),
    scans: {}
  };

  const loggerInstance = options.logger ?? logger;

  if (options.scanTimeout !== false) {
    const detector = new TimeoutPatternDetector({ logger: loggerInstance });
    results.scans.timeout = await detector.scan(repoPath);
  }

  if (options.scanRoot !== false) {
    const analyzer = new RootDirectoryAnalyzer({ logger: loggerInstance });
    results.scans.root = await analyzer.analyze(repoPath);
  }

  return results;
}

// Run CLI if executed directly
if (import.meta.url === `file://${process.argv[1]}`) {
  main().catch(error => {
    logError(logger, error, 'Fatal error');
    process.exit(1);
  });
}

