/**
 * Migration Git Manager — handles git stash/unstash and rollback for migration transformations.
 */

import { runCommand } from '@shared/process-io';
import { createComponentLogger, logError } from '../../utils/logger.ts';
import * as Sentry from '@sentry/node';

const logger = createComponentLogger('MigrationGitManager');

const STASH_MESSAGE = 'migration-transformer-backup';
const DEFAULT_STASH_REF = 'stash@{0}';

export class MigrationGitManager {
  private readonly dryRun: boolean;
  constructor(dryRun: boolean) { this.dryRun = dryRun; }

  async stashChanges(repositoryPath: string): Promise<string | null> {
    if (this.dryRun) {
      logger.info({ repositoryPath }, 'Dry run: Would stash changes');
      return null;
    }

    try {
      const status = await runCommand(repositoryPath, 'git', ['status', '--porcelain']);
      if (!status.trim()) return null;

      await runCommand(repositoryPath, 'git', ['stash', 'push', '-u', '-m', STASH_MESSAGE]);
      // Note: stash@{N} is positional — assumes exclusive git access while running.
      const stashRef = (await runCommand(repositoryPath, 'git', ['stash', 'list', '--format=%gd', '-n1'])).trim();
      logger.info({ repositoryPath, stashRef }, 'Stashed pre-existing changes');
      return stashRef || DEFAULT_STASH_REF;
    } catch (error) {
      logger.warn({ error, repositoryPath }, 'Failed to stash changes, continuing without backup');
      return null;
    }
  }

  async unstashChanges(repositoryPath: string, stashRef: string, required = false): Promise<void> {
    try {
      await runCommand(repositoryPath, 'git', ['stash', 'pop', stashRef]);
      logger.info({ repositoryPath, stashRef }, 'Restored stashed changes');
    } catch (error) {
      if (required) {
        logError(logger, error, 'Failed to restore stashed changes — manual git stash pop needed', { repositoryPath, stashRef });
        throw error;
      }
      logger.warn({ error, repositoryPath, stashRef }, 'Failed to restore stashed changes (may need manual git stash pop)');
    }
  }

  async rollback(repositoryPath: string): Promise<void> {
    logger.info({ repositoryPath }, 'Rolling back transformations');

    if (this.dryRun) {
      logger.info('Dry run: Would rollback transformations');
      return;
    }

    try {
      await runCommand(repositoryPath, 'git', ['checkout', '.']);
      await runCommand(repositoryPath, 'git', ['clean', '-fd']);
      logger.info('Rollback completed via git checkout + clean');
    } catch (error) {
      logError(logger, error, 'Rollback failed', { repositoryPath });
      Sentry.captureException(error, {
        tags: { component: 'migration-transformer', operation: 'rollback' },
        extra: { repositoryPath }
      });
      throw error;
    }
  }
}

// file: sidequest/pipeline-core/git/branch-manager.ts
/**
 * Branch Manager - Generic Git branch and PR management for AlephAuto jobs
 *
 * Provides branch creation, change detection, commit, push, and PR creation
 * for any AlephAuto worker that modifies code.
 */

import { runCommand } from '@shared/process-io'; // non-git CLI calls (gh)
import { runGitCommand } from '../utils/process-helpers.ts'; // git operations
import { createComponentLogger, logError } from '../../utils/logger.ts';
import { GIT } from '../../core/constants.ts';
import * as Sentry from '@sentry/node';

const logger = createComponentLogger('BranchManager');

export interface BranchManagerOptions {
  baseBranch?: string;
  branchPrefix?: string;
  dryRun?: boolean;
}

export interface JobBranchContext {
  jobId: string;
  jobType: string;
  description?: string;
}

export interface BranchResult {
  branchName: string;
  originalBranch: string;
}

export interface CommitContext {
  message: string;
  jobId: string;
  description?: string;
}

export interface PRContext {
  branchName: string;
  title: string;
  body: string;
  labels?: string[];
}

/**
 * Branch Manager for Git operations
 */
export class BranchManager {
  baseBranch: string;
  branchPrefix: string;
  dryRun: boolean;

    /**
   * Constructor.
   *
   * @param {BranchManagerOptions} [options={}] - Options dictionary
   */
  constructor(options: BranchManagerOptions = {}) {
    this.baseBranch = options.baseBranch || 'main';
    this.branchPrefix = options.branchPrefix || 'automated';
    this.dryRun = options.dryRun ?? false;
  }

    /**
   * Check if has changes.
   *
   * @param {string} repositoryPath - The repositoryPath
   *
   * @returns {Promise<boolean>} True if changes, False otherwise
   * @async
   */
  async hasChanges(repositoryPath: string): Promise<boolean> {
    try {
      const status = await runGitCommand(repositoryPath, ['status', '--porcelain']);
      return status.trim().length > 0;
    } catch (error) {
      logger.warn({ error, repositoryPath }, 'Failed to check git status');
      return false;
    }
  }

    /**
   * Get the changed files.
   *
   * @param {string} repositoryPath - The repositoryPath
   *
   * @returns {Promise<string[]>} The changed files
   * @async
   */
  async getChangedFiles(repositoryPath: string): Promise<string[]> {
    try {
      const status = await runGitCommand(repositoryPath, ['status', '--porcelain']);

      const files = status
        .split('\n')
        .filter(line => line.trim().length > 0)
        .map(line => {
          const filePath = line.substring(3).trim();
          // Handle renames: 'R  old -> new' → extract the new path
          const renameIdx = filePath.indexOf(' -> ');
          return renameIdx !== -1 ? filePath.substring(renameIdx + 4) : filePath;
        });

      return files;
    } catch (error) {
      logger.warn({ error, repositoryPath }, 'Failed to get changed files');
      return [];
    }
  }

    /**
   * Get the current branch.
   *
   * @param {string} repositoryPath - The repositoryPath
   *
   * @returns {Promise<string>} The current branch
   * @async
   */
  async getCurrentBranch(repositoryPath: string): Promise<string> {
    try {
      const branch = await runGitCommand(repositoryPath, ['rev-parse', '--abbrev-ref', 'HEAD']);
      return branch.trim();
    } catch (error) {
      logger.warn({ error, repositoryPath }, 'Failed to get current branch');
      return '';
    }
  }

    /**
   * Check if git repository.
   *
   * @param {string} repositoryPath - The repositoryPath
   *
   * @returns {Promise<boolean>} True if git repository, False otherwise
   * @async
   */
  async isGitRepository(repositoryPath: string): Promise<boolean> {
    try {
      await runGitCommand(repositoryPath, ['rev-parse', '--git-dir']);
      return true;
    } catch {
      return false;
    }
  }

    /**
   * Create the job branch.
   *
   * @param {string} repositoryPath - The repositoryPath
   * @param {JobBranchContext} jobContext - The jobContext
   *
   * @returns {Promise<BranchResult>} The created job branch
   * @async
   */
  async createJobBranch(repositoryPath: string, jobContext: JobBranchContext): Promise<BranchResult> {
    const span = Sentry.startInactiveSpan({
      op: 'git.create_branch',
      name: 'Create Job Branch'
    });

    try {
      const isGitRepo = await this.isGitRepository(repositoryPath);
      if (!isGitRepo) {
        logger.info({ repositoryPath }, 'Not a git repository, skipping branch creation');
        return { branchName: '', originalBranch: '' };
      }

      const originalBranch = await this.getCurrentBranch(repositoryPath);

      logger.info({
        repositoryPath,
        originalBranch,
        jobId: jobContext.jobId
      }, 'Creating job branch');

      await runGitCommand(repositoryPath, ['checkout', this.baseBranch]);

      if (!this.dryRun) {
        try {
          await runGitCommand(repositoryPath, ['pull', 'origin', this.baseBranch]);
        } catch (error) {
          logger.warn({ error }, 'Failed to pull latest changes, continuing anyway');
        }
      }

      const branchName = this._generateBranchName(jobContext);
      await runGitCommand(repositoryPath, ['checkout', '-b', branchName]);

      logger.info({ branchName, repositoryPath }, 'Branch created and checked out');

      span?.setStatus('ok');
      return { branchName, originalBranch };

    } catch (error) {
      span?.setStatus('internal_error');
      logError(logger, error, 'Failed to create job branch', { repositoryPath, jobContext });

      Sentry.captureException(error, {
        tags: {
          component: 'branch-manager',
          operation: 'create_branch',
          jobType: jobContext.jobType
        },
        extra: {
          repositoryPath,
          jobContext
        }
      });

      throw error;
    } finally {
      if (span) span.end();
    }
  }

    /**
   * Commit changes.
   *
   * @param {string} repositoryPath - The repositoryPath
   * @param {CommitContext} commitContext - The commitContext
   *
   * @returns {Promise<string>} The resulting string
   * @async
   */
  async commitChanges(repositoryPath: string, commitContext: CommitContext): Promise<string> {
    const span = Sentry.startInactiveSpan({
      op: 'git.commit',
      name: 'Commit Changes'
    });

    try {
      logger.info({ repositoryPath, jobId: commitContext.jobId }, 'Committing changes');

      const hasChanges = await this.hasChanges(repositoryPath);
      if (!hasChanges) {
        logger.info({ repositoryPath }, 'No changes to commit');
        span?.setStatus('ok');
        return '';
      }

      const changedFiles = await this.getChangedFiles(repositoryPath);
      logger.info({ changedFiles, count: changedFiles.length }, 'Files changed');

      await runGitCommand(repositoryPath, ['add', '.']);

      const commitMessage = this._generateCommitMessage(commitContext, changedFiles);
      await runGitCommand(repositoryPath, ['commit', '-m', commitMessage]);

      const commitSha = await runGitCommand(repositoryPath, ['rev-parse', 'HEAD']);

      logger.info({ commitSha: commitSha.trim(), filesCount: changedFiles.length }, 'Changes committed');

      span?.setStatus('ok');
      return commitSha.trim();

    } catch (error) {
      span?.setStatus('internal_error');
      logError(logger, error, 'Failed to commit changes', { repositoryPath, commitContext });

      Sentry.captureException(error, {
        tags: {
          component: 'branch-manager',
          operation: 'commit',
          jobId: commitContext.jobId
        },
        extra: {
          repositoryPath,
          commitContext
        }
      });

      throw error;
    } finally {
      if (span) span.end();
    }
  }

    /**
   * Push branch.
   *
   * @param {string} repositoryPath - The repositoryPath
   * @param {string} branchName - The branchName
   *
   * @returns {Promise<boolean>} True if successful, False otherwise
   * @async
   */
  async pushBranch(repositoryPath: string, branchName: string): Promise<boolean> {
    const span = Sentry.startInactiveSpan({
      op: 'git.push',
      name: 'Push Branch'
    });

    try {
      if (this.dryRun) {
        logger.info({ branchName }, 'Dry run: Skipping branch push');
        span?.setStatus('ok');
        return false;
      }

      logger.info({ repositoryPath, branchName }, 'Pushing branch to remote');

      await runGitCommand(repositoryPath, ['push', '-u', 'origin', branchName]);

      logger.info({ branchName }, 'Branch pushed successfully');

      span?.setStatus('ok');
      return true;

    } catch (error) {
      span?.setStatus('internal_error');
      logError(logger, error, 'Failed to push branch', { repositoryPath, branchName });

      Sentry.captureException(error, {
        tags: {
          component: 'branch-manager',
          operation: 'push'
        },
        extra: {
          repositoryPath,
          branchName
        }
      });

      return false;
    } finally {
      if (span) span.end();
    }
  }

    /**
   * Create the pull request.
   *
   * @param {string} repositoryPath - The repositoryPath
   * @param {PRContext} prContext - The prContext
   *
   * @returns {Promise<string | null>} The created pull request
   * @async
   */
  async createPullRequest(repositoryPath: string, prContext: PRContext): Promise<string | null> {
    const span = Sentry.startInactiveSpan({
      op: 'git.create_pr',
      name: 'Create Pull Request'
    });

    try {
      if (this.dryRun) {
        logger.info({ branch: prContext.branchName }, 'Dry run: Skipping PR creation');
        span?.setStatus('ok');
        return `dry-run-${prContext.branchName}`;
      }

      logger.info({
        repositoryPath,
        branchName: prContext.branchName,
        title: prContext.title
      }, 'Creating pull request');

      const args = [
        'pr',
        'create',
        '--title', prContext.title,
        '--body', prContext.body,
        '--base', this.baseBranch,
        '--head', prContext.branchName
      ];

      if (prContext.labels && prContext.labels.length > 0) {
        args.push('--label', prContext.labels.join(','));
      }

      const prUrl = await runCommand(repositoryPath, 'gh', args);

      logger.info({ prUrl: prUrl.trim() }, 'Pull request created');

      span?.setStatus('ok');
      return prUrl.trim();

    } catch (error) {
      span?.setStatus('internal_error');
      logError(logger, error, 'Failed to create pull request', { repositoryPath, prContext });

      Sentry.captureException(error, {
        tags: {
          component: 'branch-manager',
          operation: 'create_pr'
        },
        extra: {
          repositoryPath,
          prContext
        }
      });

      return null;
    } finally {
      if (span) span.end();
    }
  }

    /**
   * Cleanup branch.
   *
   * @param {string} repositoryPath - The repositoryPath
   * @param {string} branchName - The branchName
   * @param {string} originalBranch - The originalBranch
   *
   * @returns {Promise<void>} The Promise<void>
   * @async
   */
  async cleanupBranch(repositoryPath: string, branchName: string, originalBranch: string): Promise<void> {
    try {
      logger.info({ repositoryPath, branchName, originalBranch }, 'Cleaning up branch');

      const targetBranch = originalBranch || this.baseBranch;
      await runGitCommand(repositoryPath, ['checkout', targetBranch]);

      await runGitCommand(repositoryPath, ['branch', '-D', branchName]);

      logger.info({ branchName }, 'Branch cleaned up');

    } catch (error) {
      logger.warn({ error, branchName }, 'Failed to cleanup branch (non-critical)');
    }
  }

  private _generateBranchName(jobContext: JobBranchContext): string {
    const timestamp = Date.now();
    const jobType = (jobContext.jobType || 'job').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '');
    const description = jobContext.description
      ? `-${jobContext.description.toLowerCase().replace(/[^a-z0-9]+/g, '-').substring(0, GIT.BRANCH_DESCRIPTION_MAX_CHARS).replace(/-+$/, '')}`
      : '';

    return `${this.branchPrefix}/${jobType}${description}-${timestamp}`;
  }

  private _generateCommitMessage(commitContext: CommitContext, changedFiles: string[]): string {
    const lines = [
      commitContext.message,
      ''
    ];

    if (commitContext.description) {
      lines.push(commitContext.description, '');
    }

    lines.push(
      `Job ID: ${commitContext.jobId}`,
      `Files changed: ${changedFiles.length}`,
      '',
      '\u{1F916} Generated with [Claude Code](https://claude.com/claude-code)',
      '',
      'Co-Authored-By: Claude <noreply@anthropic.com>'
    );

    return lines.join('\n');
  }

}

// file: sidequest/pipeline-core/git/pr-creator.ts
/**
 * PR Creator - Automated Pull Request creation for consolidation suggestions
 *
 * Automatically creates Git branches and pull requests for duplicate code consolidation.
 * Uses gh CLI for PR creation and Git commands for branch management.
 */

import { runCommand } from '@shared/process-io';
import { runGitCommand } from '../utils/process-helpers.ts';
import fs from 'fs/promises';
import path from 'path';
import { createComponentLogger, logError } from '../../utils/logger.ts';
import * as Sentry from '@sentry/node';
import { MigrationTransformer } from './migration-transformer.ts';
import { LIMITS, MARKDOWN_REPORT } from '../../core/constants.ts';
import type { MigrationStep } from '../types/migration-types.ts';

const logger = createComponentLogger('PRCreator');
const STRATEGY_RATIONALE_PREVIEW_CHARS = 80;

interface Suggestion {
  suggestion_id: string;
  automated_refactor_possible: boolean;
  impact_score: number;
  target_location?: string;
  target_name?: string;
  proposed_implementation?: string;
  strategy?: string;
  strategy_rationale: string;
  complexity?: string;
  migration_risk?: string;
  usage_example?: string;
  migration_steps: MigrationStep[];
}

interface ScanResult {
  suggestions?: Suggestion[];
}

export interface PRCreatorOptions {
  baseBranch?: string;
  branchPrefix?: string;
  dryRun?: boolean;
  maxSuggestionsPerPR?: number;
}

export interface PRCreationResults {
  prsCreated: number;
  prUrls: string[];
  errors: Array<{ batch: number; error: string; suggestions: string[] }>;
  skipped: number;
}

/**
 * PR Creator for automated consolidation suggestions
 */
export class PRCreator {
  baseBranch: string;
  branchPrefix: string;
  dryRun: boolean;
  maxSuggestionsPerPR: number;
  migrationTransformer: MigrationTransformer;

    /**
   * Constructor.
   *
   * @param {PRCreatorOptions} [options={}] - Options dictionary
   */
  constructor(options: PRCreatorOptions = {}) {
    this.baseBranch = options.baseBranch || 'main';
    this.branchPrefix = options.branchPrefix || 'consolidate';
    this.dryRun = options.dryRun ?? false;
    this.maxSuggestionsPerPR = options.maxSuggestionsPerPR || LIMITS.DEFAULT_MAX_SUGGESTIONS_PER_PR;
    this.migrationTransformer = new MigrationTransformer({
      dryRun: this.dryRun
    });
  }

  async createPRsForSuggestions(
    scanResult: ScanResult,
    repositoryPath: string,
    _options: Record<string, unknown> = {}
  ): Promise<PRCreationResults> {
    logger.info({
      repositoryPath,
      totalSuggestions: scanResult.suggestions?.length || 0
    }, 'Creating PRs for consolidation suggestions');

    if (!scanResult.suggestions || scanResult.suggestions.length === 0) {
      logger.info('No suggestions to process');
      return {
        prsCreated: 0,
        prUrls: [],
        errors: [],
        skipped: 0
      };
    }

    const results: PRCreationResults = {
      prsCreated: 0,
      prUrls: [],
      errors: [],
      skipped: 0
    };

    // Filter suggestions that can be automated
    const automatableSuggestions = scanResult.suggestions.filter(
      s => s.automated_refactor_possible && s.impact_score >= MARKDOWN_REPORT.MEDIUM_SCORE_MIN
    );

    logger.info({
      total: scanResult.suggestions.length,
      automatable: automatableSuggestions.length
    }, 'Filtered automatable suggestions');

    if (automatableSuggestions.length === 0) {
      logger.info('No automatable suggestions found');
      results.skipped = scanResult.suggestions.length;
      return results;
    }

    // Group suggestions for batching
    const suggestionBatches = this._batchSuggestions(automatableSuggestions);

    logger.info({
      batches: suggestionBatches.length
    }, 'Created suggestion batches');

    for (let i = 0; i < suggestionBatches.length; i++) {
      const batch = suggestionBatches[i];

      try {
        const prUrl = await this._createPRForBatch(
          batch,
          repositoryPath,
          i + 1,
          _options
        );

        if (prUrl) {
          results.prsCreated++;
          results.prUrls.push(prUrl);
        } else {
          results.skipped += batch.length;
        }
      } catch (error) {
        logError(logger, error, 'Failed to create PR for batch', { batch: i + 1 });
        results.errors.push({
          batch: i + 1,
          error: error instanceof Error ? error.message : String(error),
          suggestions: batch.map(s => s.suggestion_id)
        });

        Sentry.captureException(error, {
          tags: {
            component: 'pr-creator',
            batch: i + 1
          },
          extra: {
            repositoryPath,
            suggestions: batch.map(s => s.suggestion_id)
          }
        });
      }
    }

    logger.info(results, 'PR creation completed');
    return results;
  }

  private async _createPRForBatch(
    suggestions: Suggestion[],
    repositoryPath: string,
    batchNumber: number,
    _options: Record<string, unknown>
  ): Promise<string | null> {
    const branchName = this._generateBranchName(suggestions, batchNumber);

    logger.info({
      branchName,
      suggestions: suggestions.length,
      batchNumber
    }, 'Creating PR for suggestion batch');

    try {
      await runGitCommand(repositoryPath, ['checkout', this.baseBranch]);

      if (!this.dryRun) {
        await runGitCommand(repositoryPath, ['pull', 'origin', this.baseBranch]);
      }

      await runGitCommand(repositoryPath, ['checkout', '-b', branchName]);

      const filesModified = await this._applySuggestions(suggestions, repositoryPath);

      if (filesModified.length === 0) {
        logger.warn({ branchName }, 'No files were modified, skipping PR creation');
        await runGitCommand(repositoryPath, ['checkout', this.baseBranch]);
        await runGitCommand(repositoryPath, ['branch', '-D', branchName]);
        return null;
      }

      const filesToStage = Array.from(new Set(
        filesModified
          .map((filePath) => path.isAbsolute(filePath) ? path.relative(repositoryPath, filePath) : filePath)
          .filter((filePath) => filePath.length > 0 && !filePath.startsWith('..'))
      ));
      if (filesToStage.length === 0) {
        logger.warn({ branchName }, 'No in-repository files to stage, skipping PR creation');
        await runGitCommand(repositoryPath, ['checkout', this.baseBranch]);
        await runGitCommand(repositoryPath, ['branch', '-D', branchName]);
        return null;
      }
      await runGitCommand(repositoryPath, ['add', '--', ...filesToStage]);

      const commitMessage = this._generateCommitMessage(suggestions, filesModified);
      await runGitCommand(repositoryPath, ['commit', '-m', commitMessage]);

      if (this.dryRun) {
        logger.info({ branchName }, 'Dry run: Skipping push and PR creation');
        await runGitCommand(repositoryPath, ['checkout', this.baseBranch]);
        await runGitCommand(repositoryPath, ['branch', '-D', branchName]);
        return `dry-run-${branchName}`;
      }

      await runGitCommand(repositoryPath, ['push', '-u', 'origin', branchName]);

      const prDescription = this._generatePRDescription(suggestions, filesModified);
      const prTitle = this._generatePRTitle(suggestions, batchNumber);
      const prUrl = await this._createPR(repositoryPath, branchName, prTitle, prDescription);

      logger.info({ prUrl, branchName }, 'PR created successfully');
      return prUrl;

    } catch (error) {
      logError(logger, error, 'Failed to create PR', { branchName });

      try {
        await runGitCommand(repositoryPath, ['checkout', this.baseBranch]);
        await runGitCommand(repositoryPath, ['branch', '-D', branchName]);
      } catch (cleanupError) {
        logger.warn({ error: cleanupError }, 'Failed to cleanup branch');
      }

      throw error;
    }
  }

  private async _applySuggestions(suggestions: Suggestion[], repositoryPath: string): Promise<string[]> {
    const filesModified: string[] = [];

    for (const suggestion of suggestions) {
      try {
        if (suggestion.target_location && suggestion.proposed_implementation) {
          const targetPath = path.join(repositoryPath, suggestion.target_location);

          await fs.mkdir(path.dirname(targetPath), { recursive: true });
          await fs.writeFile(targetPath, suggestion.proposed_implementation, 'utf-8');
          filesModified.push(suggestion.target_location);

          logger.info({
            file: suggestion.target_location,
            suggestionId: suggestion.suggestion_id
          }, 'Created consolidated file');
        }

        if (suggestion.migration_steps && suggestion.migration_steps.length > 0) {
          try {
            const migrationResult = await this.migrationTransformer.applyMigrationSteps(
              suggestion,
              repositoryPath
            );

            for (const file of migrationResult.filesModified) {
              if (!filesModified.includes(file)) {
                filesModified.push(file);
              }
            }

            logger.info({
              suggestionId: suggestion.suggestion_id,
              filesModified: migrationResult.filesModified.length,
              transformations: migrationResult.transformations.length,
              errors: migrationResult.errors.length,
              backupPath: migrationResult.backupPath
            }, 'Applied migration steps');

            if (migrationResult.errors.length > 0) {
              logger.warn({
                errors: migrationResult.errors
              }, 'Some migration transformations failed');
            }

          } catch (migrationError) {
            logError(logger, migrationError, 'Failed to apply migration steps', {
              suggestionId: suggestion.suggestion_id
            });

            Sentry.captureException(migrationError, {
              tags: {
                component: 'pr-creator',
                operation: 'apply-migration-steps'
              },
              extra: {
                suggestionId: suggestion.suggestion_id,
                repositoryPath
              }
            });
          }
        }

      } catch (error) {
        logError(logger, error, 'Failed to apply suggestion', {
          suggestionId: suggestion.suggestion_id
        });
      }
    }

    return filesModified;
  }

  private async _createPR(cwd: string, branch: string, title: string, body: string): Promise<string> {
    return runCommand(cwd, 'gh', [
      'pr',
      'create',
      '--title', title,
      '--body', body,
      '--base', this.baseBranch,
      '--head', branch
    ]);
  }

  private _batchSuggestions(suggestions: Suggestion[]): Suggestion[][] {
    const batches: Suggestion[][] = [];

    for (let i = 0; i < suggestions.length; i += this.maxSuggestionsPerPR) {
      batches.push(suggestions.slice(i, i + this.maxSuggestionsPerPR));
    }

    return batches;
  }

  private _generateBranchName(_suggestions: Suggestion[], batchNumber: number): string {
    const timestamp = Date.now();
    return `${this.branchPrefix}/batch-${batchNumber}-${timestamp}`;
  }

  private _generateCommitMessage(suggestions: Suggestion[], filesModified: string[]): string {
    const consolidationCount = suggestions.length;
    const fileCount = filesModified.length;

    return [
      `refactor: consolidate ${consolidationCount} duplicate code pattern${consolidationCount > 1 ? 's' : ''}`,
      '',
      `This commit consolidates ${consolidationCount} identified duplicate code pattern${consolidationCount > 1 ? 's' : ''} across ${fileCount} file${fileCount > 1 ? 's' : ''}.`,
      '',
      'Consolidations:',
      ...suggestions.map((s, i) => `${i + 1}. ${s.target_name || s.suggestion_id}: ${s.strategy_rationale.substring(0, STRATEGY_RATIONALE_PREVIEW_CHARS)}...`),
      '',
      'Files created:',
      ...filesModified.map(f => `- ${f}`),
      '',
      'Co-Authored-By: Claude <noreply@anthropic.com>'
    ].join('\n');
  }

  private _generatePRTitle(suggestions: Suggestion[], batchNumber: number): string {
    const consolidationCount = suggestions.length;
    return `refactor: consolidate ${consolidationCount} duplicate code pattern${consolidationCount > 1 ? 's' : ''} (batch ${batchNumber})`;
  }

  private _generatePRDescription(suggestions: Suggestion[], filesModified: string[]): string {
    const consolidationCount = suggestions.length;

    return [
      '## Summary',
      '',
      `This PR consolidates ${consolidationCount} identified duplicate code pattern${consolidationCount > 1 ? 's' : ''} to improve code maintainability and reduce duplication.`,
      '',
      '## Consolidations',
      '',
      ...suggestions.map((s, i) => {
        return [
          `### ${i + 1}. ${s.target_name || s.suggestion_id}`,
          '',
          `**Strategy:** ${s.strategy}`,
          `**Impact Score:** ${s.impact_score}/100`,
          `**Complexity:** ${s.complexity}`,
          `**Risk:** ${s.migration_risk}`,
          '',
          `**Rationale:** ${s.strategy_rationale}`,
          '',
          `**Target Location:** \`${s.target_location}\``,
          '',
          s.migration_steps.length > 0 ? '**Migration Steps:**' : '',
          ...s.migration_steps.map(step => `${step.step_number}. ${step.description}`),
          ''
        ].join('\n');
      }),
      '## Files Modified',
      '',
      ...filesModified.map(f => `- \`${f}\``),
      '',
      '## Testing',
      '',
      '- [ ] Unit tests pass',
      '- [ ] Integration tests pass',
      '- [ ] Manual testing completed',
      '- [ ] Code review completed',
      '',
      '## Migration Notes',
      '',
      'This PR creates consolidated utility files. The actual migration of existing code to use these utilities should be done in follow-up PRs.',
      '',
      suggestions.map((s) => {
        if (s.usage_example) {
          return [
            `### ${s.target_name || s.suggestion_id} Usage`,
            '',
            '```javascript',
            s.usage_example,
            '```',
            ''
          ].join('\n');
        }
        return '';
      }).filter(Boolean).join('\n'),
      '---',
      '',
      'Generated with [Claude Code](https://claude.com/claude-code)'
    ].join('\n');
  }
}

