<head>
    <meta charset='UTF-8'>
    <meta name='viewport' content='width=device-width, initial-scale=1.0'>
    <title>${escapeHtml(title)}</title>
    <style>
        ${getScanReportStyles()}
    </style>
</head>
<body>
    <div class='container'>
        ${this._generateHeader(scanResult, title, isInterProject)}
        ${this._generateMetrics(scanResult, isInterProject)}
        ${this._generateSummaryCharts(scanResult, isInterProject)}
        ${isInterProject ? this._generateCrossRepoSection(scanResult) : ''}
        ${this._generateDuplicateGroups(scanResult, isInterProject)}
        ${this._generateSuggestions(scanResult, isInterProject)}
        ${this._generateFooter()}
    </div>
    <script>
        // Add interactivity hooks here if needed.
    </script>
</body>
</html>`;

    return html;
  }

  /**
   * Save HTML report to file
   */
  static async saveReport(scanResult: ScanResult, outputPath: string, options: HTMLReportOptions = {}): Promise<string> {
    return saveGeneratedReport(outputPath, this.generateReport(scanResult, options));
  }

  private static _generateHeader(scanResult: ScanResult, title: string, isInterProject: boolean): string {
    const scanDate = new Date(scanResult.scan_metadata?.scanned_at ?? Date.now());
    const duration = scanResult.scan_metadata?.duration_seconds ?? 0;

    return `
    <header>
        <h1>🔍 ${escapeHtml(title)}</h1>
        <div class='header-meta'>
            <span class='meta-item'>
                <strong>Scan Type:</strong> ${isInterProject ? 'Inter-Project' : 'Intra-Project'}
            </span>
            <span class='meta-item'>
                <strong>Date:</strong> ${scanDate.toLocaleString()}
            </span>
            <span class='meta-item'>
                <strong>Duration:</strong> ${formatDuration(duration)}
            </span>
        </div>
    </header>`;
  }

  private static _generateMetrics(scanResult: ScanResult, isInterProject: boolean): string {
    const metrics = scanResult.metrics ?? {};

    if (isInterProject) {
      return `
    <section class='metrics'>
        <h2>📊 Scan Metrics</h2>
        <div class='metrics-grid'>
            <div class='metric-card'>
                <div class='metric-value'>${metrics.total_repositories_scanned ?? 0}</div>
                <div class='metric-label'>Repositories Scanned</div>
            </div>
            <div class='metric-card'>
                <div class='metric-value'>${metrics.total_code_blocks ?? 0}</div>
                <div class='metric-label'>Code Blocks</div>
            </div>
            <div class='metric-card highlight'>
                <div class='metric-value'>${metrics.total_cross_repository_groups ?? 0}</div>
                <div class='metric-label'>Cross-Repo Duplicates</div>
            </div>
            <div class='metric-card'>
                <div class='metric-value'>${metrics.cross_repository_duplicated_lines ?? 0}</div>
                <div class='metric-label'>Duplicated Lines</div>
            </div>
            <div class='metric-card success'>
                <div class='metric-value'>${metrics.shared_package_candidates ?? 0}</div>
                <div class='metric-label'>Shared Package Candidates</div>
            </div>
            <div class='metric-card'>
                <div class='metric-value'>${metrics.mcp_server_candidates ?? 0}</div>
                <div class='metric-label'>MCP Server Candidates</div>
            </div>
        </div>
    </section>`;
    }

    return `
    <section class='metrics'>
        <h2>📊 Scan Metrics</h2>
        <div class='metrics-grid'>
            <div class='metric-card'>
                <div class='metric-value'>${metrics.total_code_blocks ?? 0}</div>
                <div class='metric-label'>Code Blocks Detected</div>
            </div>
            <div class='metric-card highlight'>
                <div class='metric-value'>${metrics.total_duplicate_groups ?? 0}</div>
                <div class='metric-label'>Duplicate Groups</div>
            </div>
            <div class='metric-card'>
                <div class='metric-value'>${metrics.exact_duplicates ?? 0}</div>
                <div class='metric-label'>Exact Duplicates</div>
            </div>
            <div class='metric-card'>
                <div class='metric-value'>${metrics.total_duplicated_lines ?? 0}</div>
                <div class='metric-label'>Duplicated Lines</div>
            </div>
            <div class='metric-card success'>
                <div class='metric-value'>${metrics.potential_loc_reduction ?? 0}</div>
                <div class='metric-label'>Potential LOC Reduction</div>
            </div>
            <div class='metric-card'>
                <div class='metric-value'>${metrics.quick_wins ?? 0}</div>
                <div class='metric-label'>Quick Wins</div>
            </div>
        </div>
    </section>`;
  }

  private static _generateSummaryCharts(scanResult: ScanResult, isInterProject: boolean): string {
    const suggestions = isInterProject
      ? (scanResult.cross_repository_suggestions ?? [])
      : (scanResult.suggestions ?? []);

    // Count by strategy
    const strategyCounts: Record<string, number> = {};
    suggestions.forEach(s => {
      strategyCounts[s.strategy] = (strategyCounts[s.strategy] ?? 0) + 1;
    });

    // Count by complexity
    const complexityCounts: Record<string, number> = {};
    suggestions.forEach(s => {
      complexityCounts[s.complexity] = (complexityCounts[s.complexity] ?? 0) + 1;
    });

    return `
    <section class='charts'>
        <h2>📈 Distribution</h2>
        <div class='charts-grid'>
            <div class='chart-card'>
                <h3>By Strategy</h3>
                <div class='chart-bars'>
                    ${Object.entries(strategyCounts).map(([strategy, count]) => `
                    <div class='chart-bar-row'>
                        <span class='chart-label'>${escapeHtml(strategy.replaceAll('_', ' '))}</span>
                        <div class='chart-bar-container'>
                            <div class='chart-bar strategy-${sanitizeCssClass(strategy, VALID_STRATEGIES)}' style='width: ${(count / suggestions.length * MAX_SCORE).toFixed(1)}%'></div>
                        </div>
                        <span class='chart-count'>${count}</span>
                    </div>
                    `).join('')}
                </div>
            </div>
            <div class='chart-card'>
                <h3>By Complexity</h3>
                <div class='chart-bars'>
                    ${Object.entries(complexityCounts).map(([complexity, count]) => `
                    <div class='chart-bar-row'>
                        <span class='chart-label'>${escapeHtml(complexity)}</span>
                        <div class='chart-bar-container'>
                            <div class='chart-bar complexity-${sanitizeCssClass(complexity, VALID_COMPLEXITIES)}' style='width: ${(count / suggestions.length * MAX_SCORE).toFixed(1)}%'></div>
                        </div>
                        <span class='chart-count'>${count}</span>
                    </div>
                    `).join('')}
                </div>
            </div>
        </div>
    </section>`;
  }

  private static _generateCrossRepoSection(scanResult: ScanResult): string {
    const repos = scanResult.scanned_repositories ?? [];

    return `
    <section class='cross-repo'>
        <h2>🔗 Scanned Repositories</h2>
        <div class='repo-grid'>
            ${repos.map(repo => `
            <div class="repo-card ${repo.error ? 'error' : ''}">
                <div class='repo-name'>${escapeHtml(repo.name)}</div>
                ${repo.error ? `
                <div class='repo-error'>❌ ${escapeHtml(repo.error)}</div>
                ` : `
                <div class='repo-stats'>
                    <span>${repo.code_blocks ?? 0} blocks</span>
                    <span>${repo.duplicate_groups ?? 0} groups</span>
                </div>
                `}
            </div>
            `).join('')}
        </div>
    </section>`;
  }

  private static _generateDuplicateGroups(scanResult: ScanResult, isInterProject: boolean): string {
    const groups = isInterProject
      ? (scanResult.cross_repository_duplicates ?? [])
      : (scanResult.duplicate_groups ?? []);

    const topGroups = groups
      .sort((a, b) => b.impact_score - a.impact_score)
      .slice(0, LIMITS.DISPLAY_TOP_N);

    if (topGroups.length === 0) {
      return `
    <section class='duplicates'>
        <h2>🎯 Duplicate Groups</h2>
        <p class='empty-state'>No duplicate groups detected.</p>
    </section>`;
    }

    return `
    <section class='duplicates'>
        <h2>🎯 Top Duplicate Groups</h2>
        <div class='duplicates-list'>
            ${topGroups.map((group, index) => `
            <div class='duplicate-card'>
                <div class='duplicate-header'>
                    <div class='duplicate-rank'>#${index + 1}</div>
                    <div class='duplicate-title'>
                        <strong>${escapeHtml(group.group_id)}</strong>
                        <span class='duplicate-pattern'>${escapeHtml(group.pattern_id)}</span>
                    </div>
                    <div class='duplicate-impact ${this._getImpactClass(group.impact_score)}'>
                        ${group.impact_score.toFixed(0)}% impact
                    </div>
                </div>
                <div class='duplicate-stats'>
                    <span class='stat-badge'>
                        📦 ${group.occurrence_count} occurrences
                    </span>
                    ${isInterProject ? `
                    <span class='stat-badge'>
                        🔗 ${group.repository_count ?? 0} repositories
                    </span>
                    ` : ''}
                    <span class='stat-badge'>
                        📄 ${group.affected_files?.length ?? 0} files
                    </span>
                    <span class='stat-badge'>
                        📏 ${group.total_lines} lines
                    </span>
                </div>
                <div class='duplicate-files'>
                    <strong>Affected files:</strong>
                    <ul>
                        ${(group.affected_files ?? []).slice(0, MARKDOWN_REPORT.MAX_AFFECTED_FILES).map(file => `
                        <li><code>${escapeHtml(file)}</code></li>
                        `).join('')}
                        ${(group.affected_files?.length ?? 0) > MARKDOWN_REPORT.MAX_AFFECTED_FILES ? `<li><em>... and ${(group.affected_files?.length ?? 0) - MARKDOWN_REPORT.MAX_AFFECTED_FILES} more</em></li>` : ''}
                    </ul>
                </div>
            </div>
            `).join('')}
        </div>
    </section>`;
  }

  private static _generateSuggestions(scanResult: ScanResult, isInterProject: boolean): string {
    const suggestions = isInterProject
      ? (scanResult.cross_repository_suggestions ?? [])
      : (scanResult.suggestions ?? []);

    const topSuggestions = suggestions
      .sort((a, b) => b.roi_score - a.roi_score)
      .slice(0, LIMITS.DISPLAY_TOP_N);

    if (topSuggestions.length === 0) {
      return `
    <section class='suggestions'>
        <h2>💡 Consolidation Suggestions</h2>
        <p class='empty-state'>No suggestions generated.</p>
    </section>`;
    }

    return `
    <section class='suggestions'>
        <h2>💡 Top Consolidation Suggestions</h2>
        <div class='suggestions-list'>
            ${topSuggestions.map((suggestion, index) => `
            <div class="suggestion-card ${suggestion.breaking_changes ? 'breaking' : ''}">
                <div class='suggestion-header'>
                    <div class='suggestion-rank'>#${index + 1}</div>
                    <div class='suggestion-title'>
                        <strong>${escapeHtml(suggestion.suggestion_id)}</strong>
                        <span class='suggestion-strategy strategy-${sanitizeCssClass(suggestion.strategy, VALID_STRATEGIES)}'>
                            ${escapeHtml(suggestion.strategy.replaceAll('_', ' '))}
                        </span>
                    </div>
                    <div class='suggestion-roi ${this._getROIClass(suggestion.roi_score)}'>
                        ROI: ${suggestion.roi_score.toFixed(0)}%
                    </div>
                </div>
                <div class='suggestion-body'>
                    <p class='suggestion-rationale'>${escapeHtml(suggestion.strategy_rationale ?? '')}</p>
                    ${suggestion.target_location ? `
                    <p class='suggestion-target'>
                        <strong>Target:</strong> <code>${escapeHtml(suggestion.target_location)}</code>
                    </p>
                    ` : ''}
                    <div class='suggestion-metrics'>
                        <span class='metric-badge'>
                            Impact: ${suggestion.impact_score.toFixed(0)}%
                        </span>
                        <span class='metric-badge complexity-${sanitizeCssClass(suggestion.complexity, VALID_COMPLEXITIES)}'>
                            ${escapeHtml(suggestion.complexity)} complexity
                        </span>
                        <span class='metric-badge risk-${sanitizeCssClass(suggestion.migration_risk, VALID_RISKS)}'>
                            ${escapeHtml(suggestion.migration_risk)} risk
                        </span>
                        ${suggestion.estimated_effort_hours != null ? `
                        <span class='metric-badge'>
                            ~${suggestion.estimated_effort_hours}h effort
                        </span>
                        ` : ''}
                    </div>
                    ${suggestion.breaking_changes ? `
                    <div class='warning-box'>
                        ⚠️ <strong>Breaking Change:</strong> This consolidation may require API changes
                    </div>
                    ` : ''}
                </div>
            </div>
            `).join('')}
        </div>
    </section>`;
  }

  private static _generateFooter(): string {
    return `
    <footer>
        <p>Generated by Duplicate Detection Pipeline | ${new Date().toLocaleString()}</p>
    </footer>`;
  }

  private static _getImpactClass(score: number): string {
    if (score >= REPORT_SCORE_CLASS_THRESHOLDS.IMPACT_HIGH_MIN_SCORE) return 'impact-high';
    if (score >= REPORT_SCORE_CLASS_THRESHOLDS.IMPACT_MEDIUM_MIN_SCORE) return 'impact-medium';
    return 'impact-low';
  }

  private static _getROIClass(score: number): string {
    if (score >= REPORT_SCORE_CLASS_THRESHOLDS.ROI_HIGH_MIN_SCORE) return 'roi-high';
    if (score >= REPORT_SCORE_CLASS_THRESHOLDS.ROI_MEDIUM_MIN_SCORE) return 'roi-medium';
    return 'roi-low';
  }

}

// file: sidequest/pipeline-core/reports/markdown-report-generator.ts
/**
 * Markdown Report Generator
 *
 * Generates concise Markdown summaries of duplicate detection scan results.
 * Suitable for terminal viewing, GitHub README integration, and quick reviews.
 */

import { saveGeneratedReport } from '../utils/index.ts';
import { MARKDOWN_REPORT } from '../../core/constants.ts';
import { formatDuration } from '../../utils/time-helpers.ts';
import type { ScanResult } from './json-report-generator.ts';

export interface MarkdownReportOptions {
  includeDetails?: boolean;
  maxDuplicates?: number;
  maxSuggestions?: number;
}

/**
 * Generate Markdown summary reports from scan results
 */
export class MarkdownReportGenerator {
  /**
   * Generate a complete Markdown report
   */
  static generateReport(scanResult: ScanResult, options: MarkdownReportOptions = {}): string {
    const includeDetails = options.includeDetails !== false;
    const maxDuplicates = options.maxDuplicates ?? MARKDOWN_REPORT.DEFAULT_MAX_DUPLICATES;
    const maxSuggestions = options.maxSuggestions ?? MARKDOWN_REPORT.DEFAULT_MAX_SUGGESTIONS;
    const isInterProject = scanResult.scan_type === 'inter-project';

    let markdown = '';

    // Header
    markdown += this._generateHeader(scanResult, isInterProject);
    markdown += '\n\n';

    // Metrics
    markdown += this._generateMetrics(scanResult, isInterProject);
    markdown += '\n\n';

    // Repository Information (inter-project only)
    if (isInterProject) {
      markdown += this._generateRepositoryInfo(scanResult);
      markdown += '\n\n';
    }

    // Top Duplicate Groups
    markdown += this._generateDuplicateGroups(scanResult, isInterProject, maxDuplicates, includeDetails);
    markdown += '\n\n';

    // Top Suggestions
    markdown += this._generateSuggestions(scanResult, isInterProject, maxSuggestions, includeDetails);
    markdown += '\n\n';

    // Footer
    markdown += this._generateFooter(scanResult);

    return markdown;
  }

  /**
   * Generate a concise summary (for quick overview)
   */
  static generateSummary(scanResult: ScanResult): string {
    const isInterProject = scanResult.scan_type === 'inter-project';
    const metrics = scanResult.metrics ?? {};

    let summary = '# Duplicate Detection Summary\n\n';

    if (isInterProject) {
      summary += `**Scanned:** ${metrics.total_repositories_scanned ?? 0} repositories\n`;
      summary += `**Code Blocks:** ${metrics.total_code_blocks ?? 0}\n`;
      summary += `**Cross-Repo Duplicates:** ${metrics.total_cross_repository_groups ?? 0}\n`;
      summary += `**Suggestions:** ${metrics.total_suggestions ?? 0}\n`;
      summary += `**Shared Package Candidates:** ${metrics.shared_package_candidates ?? 0}\n`;
      summary += `**MCP Server Candidates:** ${metrics.mcp_server_candidates ?? 0}\n`;
    } else {
      summary += `**Code Blocks:** ${metrics.total_code_blocks ?? 0}\n`;
      summary += `**Duplicate Groups:** ${metrics.total_duplicate_groups ?? 0}\n`;
      summary += `**Duplicated Lines:** ${metrics.total_duplicated_lines ?? 0}\n`;
      summary += `**Suggestions:** ${metrics.total_suggestions ?? 0}\n`;
      summary += `**Quick Wins:** ${metrics.quick_wins ?? 0}\n`;
    }

    return summary;
  }

  /**
   * Save Markdown report to file
   */
  static async saveReport(scanResult: ScanResult, outputPath: string, options: MarkdownReportOptions = {}): Promise<string> {
    return saveGeneratedReport(outputPath, this.generateReport(scanResult, options));
  }

  /**
   * Save concise summary to file
   */
  static async saveSummary(scanResult: ScanResult, outputPath: string): Promise<string> {
    return saveGeneratedReport(outputPath, this.generateSummary(scanResult));
  }

  // Private helper methods

  /**
   * Generate report header
   * @private
   */
  private static _generateHeader(scanResult: ScanResult, isInterProject: boolean): string {
    const metadata = scanResult.scan_metadata ?? {};
    const repoInfo = scanResult.repository_info ?? {};
    const scanType = isInterProject ? 'Inter-Project' : 'Intra-Project';

    let header = `# ${scanType} Duplicate Detection Report\n\n`;

    if (isInterProject) {
      header += `**Repositories:** ${metadata.repository_count ?? 0}\n`;
    } else {
      header += `**Repository:** ${repoInfo.name ?? 'Unknown'}\n`;
      header += `**Path:** \`${repoInfo.path ?? 'Unknown'}\`\n`;
    }

    header += `**Scanned:** ${new Date(metadata.scanned_at ?? Date.now()).toLocaleString()}\n`;
    header += `**Duration:** ${formatDuration(metadata.duration_seconds ?? null)}\n`;

    return header;
  }

  /**
   * Generate metrics table
   * @private
   */
  private static _generateMetrics(scanResult: ScanResult, isInterProject: boolean): string {
    const metrics = scanResult.metrics ?? {};

    let markdown = '## Metrics\n\n';

    if (isInterProject) {
      markdown += '| Metric | Value |\n';
      markdown += '|--------|-------|\n';
      markdown += `| Repositories Scanned | ${metrics.total_repositories_scanned ?? 0} |\n`;
      markdown += `| Total Code Blocks | ${metrics.total_code_blocks ?? 0} |\n`;
      markdown += `| Intra-Project Groups | ${metrics.total_intra_project_groups ?? 0} |\n`;
      markdown += `| Cross-Repo Groups | ${metrics.total_cross_repository_groups ?? 0} |\n`;
      markdown += `| Cross-Repo Occurrences | ${metrics.cross_repository_occurrences ?? 0} |\n`;
      markdown += `| Cross-Repo Duplicated Lines | ${metrics.cross_repository_duplicated_lines ?? 0} |\n`;
      markdown += `| Total Suggestions | ${metrics.total_suggestions ?? 0} |\n`;
      markdown += `| Shared Package Candidates | ${metrics.shared_package_candidates ?? 0} |\n`;
      markdown += `| MCP Server Candidates | ${metrics.mcp_server_candidates ?? 0} |\n`;
      markdown += `| Avg Repos per Duplicate | ${metrics.average_repositories_per_duplicate ?? 0} |\n`;
    } else {
      markdown += '| Metric | Value |\n';
      markdown += '|--------|-------|\n';
      markdown += `| Total Code Blocks | ${metrics.total_code_blocks ?? 0} |\n`;
      markdown += `| Duplicate Groups | ${metrics.total_duplicate_groups ?? 0} |\n`;
      markdown += `| Exact Duplicates | ${metrics.exact_duplicates ?? 0} |\n`;
      markdown += `| Total Duplicated Lines | ${metrics.total_duplicated_lines ?? 0} |\n`;
      markdown += `| Potential LOC Reduction | ${metrics.potential_loc_reduction ?? 0} |\n`;
      markdown += `| Duplication Percentage | ${metrics.duplication_percentage?.toFixed(MARKDOWN_REPORT.PERCENTAGE_DECIMAL_PLACES) ?? 0}% |\n`;
      markdown += `| Total Suggestions | ${metrics.total_suggestions ?? 0} |\n`;
      markdown += `| Quick Wins | ${metrics.quick_wins ?? 0} |\n`;
      markdown += `| High Priority Suggestions | ${metrics.high_priority_suggestions ?? 0} |\n`;
    }

    return markdown;
  }

  /**
   * Generate repository information (inter-project only)
   * @private
   */
  private static _generateRepositoryInfo(scanResult: ScanResult): string {
    const repos = scanResult.scanned_repositories ?? [];

    let markdown = '## Scanned Repositories\n\n';
    markdown += '| Repository | Code Blocks | Duplicate Groups | Status |\n';
    markdown += '|------------|-------------|------------------|--------|\n';

    for (const repo of repos) {
      const status = repo.error ? `❌ ${repo.error}` : '✅ Success';
      markdown += `| ${repo.name} | ${repo.code_blocks ?? 0} | ${repo.duplicate_groups ?? 0} | ${status} |\n`;
    }

    return markdown;
  }

  /**
   * Generate duplicate groups section
   * @private
   */
  private static _generateDuplicateGroups(
    scanResult: ScanResult,
    isInterProject: boolean,
    maxGroups: number,
    includeDetails: boolean
  ): string {
    const groups = isInterProject
      ? (scanResult.cross_repository_duplicates ?? [])
      : (scanResult.duplicate_groups ?? []);

    let markdown = isInterProject
      ? '## Top Cross-Repository Duplicates\n\n'
      : '## Top Duplicate Groups\n\n';

    if (groups.length === 0) {
      markdown += '*No duplicates detected.*\n';
      return markdown;
    }

    // Sort by impact score descending
    const topGroups = [...groups]
      .sort((a, b) => b.impact_score - a.impact_score)
      .slice(0, maxGroups);

    for (const group of topGroups) {
      markdown += `### ${group.group_id}\n\n`;
      markdown += `- **Pattern:** ${group.pattern_id}\n`;
      markdown += `- **Category:** ${group.category}\n`;
      markdown += `- **Language:** ${group.language}\n`;
      markdown += `- **Occurrences:** ${group.occurrence_count}\n`;

      if (isInterProject) {
        markdown += `- **Repositories:** ${group.repository_count ?? 0} (${group.affected_repositories?.join(', ') ?? 'N/A'})\n`;
      }

      markdown += `- **Total Lines:** ${group.total_lines}\n`;
      markdown += `- **Impact Score:** ${this._formatScore(group.impact_score)}\n`;
      markdown += `- **Similarity:** ${(group.similarity_score * MARKDOWN_REPORT.PERCENTAGE_MULTIPLIER).toFixed(0)}% (${group.similarity_method})\n`;

      if (includeDetails) {
        markdown += `- **Affected Files:**\n`;
        const files = group.affected_files ?? [];
        const maxFiles = MARKDOWN_REPORT.MAX_AFFECTED_FILES;
        for (let i = 0; i < Math.min(files.length, maxFiles); i++) {
          markdown += `  - \`${files[i]}\`\n`;
        }
        if (files.length > maxFiles) {
          markdown += `  - *... and ${files.length - maxFiles} more*\n`;
        }
      }

      markdown += '\n';
    }

    return markdown;
  }

  /**
   * Generate suggestions section
   * @private
   */
  private static _generateSuggestions(
    scanResult: ScanResult,
    isInterProject: boolean,
    maxSuggestions: number,
    includeDetails: boolean
  ): string {
    const suggestions = isInterProject
      ? (scanResult.cross_repository_suggestions ?? [])
      : (scanResult.suggestions ?? []);

    let markdown = isInterProject
      ? '## Top Cross-Repository Suggestions\n\n'
      : '## Top Consolidation Suggestions\n\n';

    if (suggestions.length === 0) {
      markdown += '*No suggestions generated.*\n';
      return markdown;
    }

    // Sort by ROI score descending
    const topSuggestions = [...suggestions]
      .sort((a, b) => b.roi_score - a.roi_score)
      .slice(0, maxSuggestions);

    for (const suggestion of topSuggestions) {
      markdown += `### ${suggestion.suggestion_id}\n\n`;
      markdown += `- **Strategy:** ${this._formatStrategy(suggestion.strategy)}\n`;
      markdown += `- **Target:** \`${suggestion.target_location}\`\n`;
      markdown += `- **Impact Score:** ${this._formatScore(suggestion.impact_score)}\n`;
      markdown += `- **ROI Score:** ${this._formatScore(suggestion.roi_score)}\n`;
      markdown += `- **Complexity:** ${this._formatComplexity(suggestion.complexity)}\n`;
      markdown += `- **Risk:** ${this._formatRisk(suggestion.migration_risk)}\n`;

      if (isInterProject) {
        const repos = suggestion.affected_repositories ?? [];
        markdown += `- **Repositories:** ${repos.join(', ')}\n`;
      } else {
        markdown += `- **Affected Files:** ${suggestion.affected_files_count ?? 0}\n`;
      }

      if (suggestion.breaking_changes) {
        markdown += `- **⚠️ Breaking Changes:** Yes\n`;
      }

      if (suggestion.estimated_effort_hours != null) {
        markdown += `- **Estimated Effort:** ${suggestion.estimated_effort_hours}h\n`;
      }

      if (includeDetails && suggestion.strategy_rationale) {
        markdown += `\n**Rationale:** ${suggestion.strategy_rationale}\n`;
      }

      if (includeDetails && suggestion.migration_steps && suggestion.migration_steps.length > 0) {
        markdown += '\n**Migration Steps:**\n';
        for (const step of suggestion.migration_steps.slice(0, MARKDOWN_REPORT.MAX_MIGRATION_STEPS)) {
          const automated = step.automated ? '🤖' : '👤';
          markdown += `${step.step_number}. ${automated} ${step.description} *(${step.estimated_time})*\n`;
        }
        if (suggestion.migration_steps.length > MARKDOWN_REPORT.MAX_MIGRATION_STEPS) {
          markdown += `*... and ${suggestion.migration_steps.length - MARKDOWN_REPORT.MAX_MIGRATION_STEPS} more steps*\n`;
        }
      }

      markdown += '\n';
    }

    return markdown;
  }

  /**
   * Generate footer
   * @private
   */
  private static _generateFooter(scanResult: ScanResult): string {
    const metadata = scanResult.scan_metadata ?? {};

    let footer = '---\n\n';
    footer += '*Report generated by Duplicate Detection Pipeline*\n\n';

    if (metadata.total_code_blocks) {
      footer += `*Analyzed ${metadata.total_code_blocks} code blocks*\n`;
    }

    return footer;
  }

  /**
   * Format score with emoji indicator
   * @private
   */
  private static _formatScore(score: number): string {
    if (score >= MARKDOWN_REPORT.HIGH_SCORE_MIN) {
      return `🔴 ${score.toFixed(1)}/100 (High)`;
    } else if (score >= MARKDOWN_REPORT.MEDIUM_SCORE_MIN) {
      return `🟡 ${score.toFixed(1)}/100 (Medium)`;
    } else {
      return `🟢 ${score.toFixed(1)}/100 (Low)`;
    }
  }

  /**
   * Format strategy with emoji
   * @private
   */
  private static _formatStrategy(strategy: string): string {
    const strategyMap: Record<string, string> = {
      'local_util': '📁 Local Utility',
      'shared_package': '📦 Shared Package',
      'mcp_server': '🔌 MCP Server',
      'autonomous_agent': '🤖 Autonomous Agent'
    };
    return strategyMap[strategy] ?? strategy;
  }

  /**
   * Format complexity with emoji
   * @private
   */
  private static _formatComplexity(complexity: string): string {
    const complexityMap: Record<string, string> = {
      'trivial': '🟢 Trivial',
      'simple': '🟡 Simple',
      'moderate': '🟠 Moderate',
      'complex': '🔴 Complex'
    };
    return complexityMap[complexity] ?? complexity;
  }

  /**
   * Format risk with emoji
   * @private
   */
  private static _formatRisk(risk: string): string {
    const riskMap: Record<string, string> = {
      'minimal': '🟢 Minimal',
      'low': '🟡 Low',
      'medium': '🟠 Medium',
      'high': '🔴 High'
    };
    return riskMap[risk] ?? risk;
  }
}

// file: cloudflare-workers/n0ai-proxy/src/index.ts
/**
 * Cloudflare Worker: n0ai-proxy
 *
 * Secure proxy for n0ai.app content to populate SideQuest UI
 * Fetches full HTML content and API data from the AlephAuto dashboard
 */

import type { ExecutionContext } from '@cloudflare/workers-types';

export interface Env {
  TARGET_URL: string;
  ALLOWED_ORIGINS: string;
  QUALITY_METRICS_API_URL: string;
}

// Cache settings
const HTML_CACHE_TTL = 60; // 1 minute for HTML
const API_CACHE_TTL = 30; // 30 seconds for API data

interface ProxyResponse {
  content: string;
  contentType: string;
  statusCode: number;
  cached: boolean;
  fetchedAt: string;
  targetUrl: string;
}

interface ApiStatusResponse {
  status: string;
  pipelines: Array<{
    name: string;
    status: string;
    lastRun?: string;
  }>;
  uptime?: number;
  version?: string;
}

/**
 * getCorsHeaders.
 */
function getCorsHeaders(origin: string, allowedOrigins: string[]): Headers {
  const headers = new Headers();

  if (allowedOrigins.includes(origin) || allowedOrigins.includes('*')) {
    headers.set('Access-Control-Allow-Origin', origin);
  }

  headers.set('Access-Control-Allow-Methods', 'GET, OPTIONS');
  headers.set('Access-Control-Allow-Headers', 'Content-Type, Accept');
  headers.set('Access-Control-Max-Age', '86400');

  return headers;
}

/**
 * headersToObject.
 */
function headersToObject(headers: Headers): Record<string, string> {
  const obj: Record<string, string> = {};
  headers.forEach((value, key) => {
    obj[key] = value;
  });
  return obj;
}

/**
 * fetchContent.
 */
async function fetchContent(url: string, acceptType: string = 'text/html'): Promise<{
  content: string;
  contentType: string;
  status: number;
}> {
  const response = await fetch(url, {
    headers: {
      'Accept': acceptType,
      'User-Agent': 'n0ai-proxy/1.0 (Cloudflare Worker)'
    }
  });

  const content = await response.text();
  const contentType = response.headers.get('Content-Type') || 'text/html';

  return {
    content,
    contentType,
    status: response.status
  };
}

export default {
  /**
   * fetch.
   */
  async fetch(request: Request, env: Env, ctx: any): Promise<Response> {
    const url = new URL(request.url);
    const origin = request.headers.get('Origin') || '';
    const allowedOrigins = env.ALLOWED_ORIGINS.split(',').map((o) => o.trim());
    const corsHeaders = getCorsHeaders(origin, allowedOrigins);

    // Handle CORS preflight
    if (request.method === 'OPTIONS') {
      return new Response(null, { status: 204, headers: corsHeaders });
    }

    // Only allow GET requests
    if (request.method !== 'GET') {
      return new Response(JSON.stringify({ error: 'Method not allowed' }), {
        status: 405,
        headers: { ...headersToObject(corsHeaders), 'Content-Type': 'application/json' }
      });
    }

    const path = url.pathname;

    try {
      // Health check
      if (path === '/health') {
        return new Response(
          JSON.stringify({
            status: 'healthy',
            timestamp: new Date().toISOString(),
            targetUrl: env.TARGET_URL
          }),
          {
            headers: { ...headersToObject(corsHeaders), 'Content-Type': 'application/json' }
          }
        );
      }

      // Root path - fetch full HTML from n0ai.app
      if (path === '/' || path === '/html') {
        const cache = await (caches as any).open('default');
        const cacheKey = new Request(`${env.TARGET_URL}/html`, request);
        let cachedResponse = await cache.match(cacheKey);

        if (cachedResponse) {
          const cachedData = (await cachedResponse.json()) as ProxyResponse;
          cachedData.cached = true;

          return new Response(JSON.stringify(cachedData), {
            headers: {
              ...headersToObject(corsHeaders),
              'Content-Type': 'application/json',
              'Cache-Control': `public, max-age=${HTML_CACHE_TTL}`,
              'X-Cache': 'HIT'
            }
          });
        }

        // Fetch fresh HTML
        const result = await fetchContent(env.TARGET_URL, 'text/html');

        const responseData: ProxyResponse = {
          content: result.content,
          contentType: result.contentType,
          statusCode: result.status,
          cached: false,
          fetchedAt: new Date().toISOString(),
          targetUrl: env.TARGET_URL
        };

        const response = new Response(JSON.stringify(responseData), {
          headers: {
            ...headersToObject(corsHeaders),
            'Content-Type': 'application/json',
            'Cache-Control': `public, max-age=${HTML_CACHE_TTL}`,
            'X-Cache': 'MISS'
          }
        });

        // Store in cache
        ctx.waitUntil(cache.put(cacheKey, response.clone()));

        return response;
      }

      // API status endpoint - proxy to n0ai.app/api/status
      if (path === '/api/status' || path === '/status') {
        const cache = await (caches as any).open('default');
        const apiUrl = `${env.TARGET_URL}/api/status`;
        const cacheKey = new Request(apiUrl, request);
        let cachedResponse = await cache.match(cacheKey);

        if (cachedResponse) {
          const cachedData = await cachedResponse.json();
          return new Response(JSON.stringify({ ...cachedData, cached: true }), {
            headers: {
              ...headersToObject(corsHeaders),
              'Content-Type': 'application/json',
              'Cache-Control': `public, max-age=${API_CACHE_TTL}`,
              'X-Cache': 'HIT'
            }
          });
        }

        const result = await fetchContent(apiUrl, 'application/json');

        let data: ApiStatusResponse;
        try {
          data = JSON.parse(result.content);
        } catch {
          data = { status: 'unknown', pipelines: [] };
        }

        const responseData = {
          ...data,
          cached: false,
          fetchedAt: new Date().toISOString()
        };

        const response = new Response(JSON.stringify(responseData), {
          headers: {
            ...headersToObject(corsHeaders),
            'Content-Type': 'application/json',
            'Cache-Control': `public, max-age=${API_CACHE_TTL}`,
            'X-Cache': 'MISS'
          }
        });

        ctx.waitUntil(cache.put(cacheKey, response.clone()));

        return response;
      }

      // Health endpoint proxy
      if (path === '/api/health' || path === '/target-health') {
        const healthUrl = `${env.TARGET_URL}/health`;
        const result = await fetchContent(healthUrl, 'application/json');

        return new Response(result.content, {
          status: result.status,
          headers: {
            ...headersToObject(corsHeaders),
            'Content-Type': 'application/json'
          }
        });
      }

      // Dashboard quality metrics - proxy to quality-metrics-api worker
      if (path.startsWith('/api/dashboard')) {
        const cache = await (caches as any).open('default');
        const queryString = url.search || '';
        const metricsUrl = `${env.QUALITY_METRICS_API_URL}${path}${queryString}`;
        const cacheKey = new Request(metricsUrl, request);
        const cachedResponse = await cache.match(cacheKey);

        if (cachedResponse) {
          const cachedData = await cachedResponse.json();
          return new Response(JSON.stringify({ ...cachedData, cached: true }), {
            headers: {
              ...headersToObject(corsHeaders),
              'Content-Type': 'application/json',
              'Cache-Control': `public, max-age=${API_CACHE_TTL}`,
              'X-Cache': 'HIT'
            }
          });
        }

        const result = await fetchContent(metricsUrl, 'application/json');

        let data;
        try {
          data = JSON.parse(result.content);
        } catch {
          data = { error: 'Failed to parse quality metrics response' };
        }

        const responseData = {
          ...data,
          cached: false,
          fetchedAt: new Date().toISOString()
        };

        const response = new Response(JSON.stringify(responseData), {
          status: result.status,
          headers: {
            ...headersToObject(corsHeaders),
            'Content-Type': 'application/json',
            'Cache-Control': `public, max-age=${API_CACHE_TTL}`,
            'X-Cache': 'MISS'
          }
        });

        ctx.waitUntil(cache.put(cacheKey, response.clone()));

        return response;
      }

      // Proxy any other path to n0ai.app
      if (path.startsWith('/proxy')) {
        const targetPath = path.replace('/proxy', '') || '/';
        const targetUrl = `${env.TARGET_URL}${targetPath}`;

        const result = await fetchContent(targetUrl);

        const responseData: ProxyResponse = {
          content: result.content,
          contentType: result.contentType,
          statusCode: result.status,
          cached: false,
          fetchedAt: new Date().toISOString(),
          targetUrl
        };

        return new Response(JSON.stringify(responseData), {
          headers: {
            ...headersToObject(corsHeaders),
            'Content-Type': 'application/json'
          }
        });
      }

      // 404 for unknown routes
      return new Response(
        JSON.stringify({
          error: 'Not found',
          path,
          availableEndpoints: ['/', '/html', '/status', '/api/status', '/api/dashboard', '/health', '/target-health', '/proxy/*']
        }),
        {
          status: 404,
          headers: { ...headersToObject(corsHeaders), 'Content-Type': 'application/json' }
        }
      );
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Unknown error';

      return new Response(
        JSON.stringify({
          error: 'Failed to fetch content',
          message,
          timestamp: new Date().toISOString()
        }),
        {
          status: 500,
          headers: { ...headersToObject(corsHeaders), 'Content-Type': 'application/json' }
        }
      );
    }
  }
};

// file: api/middleware/validation.ts
/**
 * Request Validation Middleware
 *
 * Validates request bodies using Zod schemas and returns detailed error messages.
 */

import type { Request, Response, NextFunction } from 'express';
import { type ZodSchema, ZodError } from 'zod';
import { createComponentLogger } from '#sidequest/utils/logger.ts';
import { sendValidationError } from '../utils/api-error.ts';

// Module augmentation for type-safe validated query access
declare global {
  namespace Express {
    interface Request {
      validatedQuery?: unknown;
    }
  }
}

const logger = createComponentLogger('ValidationMiddleware');

/**
 * Structured validation error detail.
 */
interface ValidationErrorDetail {
  field: string;
  message: string;
  code: string;
}

/**
 * Formats Zod errors into API-friendly detail entries.
 *
 * @param error Zod validation error.
 * @returns List of normalized validation errors.
 */
function formatZodErrors(error: ZodError): ValidationErrorDetail[] {
  return error.errors.map(err => ({
    field: err.path.join('.'),
    message: err.message,
    code: err.code
  }));
}

/**
 * Creates middleware that validates `req.body` against a schema.
 *
 * @param schema Zod schema for request body.
 * @returns Express middleware function.
 */
export function validateRequest(schema: ZodSchema): (req: Request, res: Response, next: NextFunction) => void {
  return (req: Request, res: Response, next: NextFunction) => {
    try {
      // Validate request body against schema
      const validated = schema.parse(req.body);

      // Replace request body with validated data (type-safe)
      req.body = validated;

      next();
    } catch (error) {
      if (error instanceof ZodError) {
        const errors = formatZodErrors(error);

        logger.warn({
          path: req.path,
          method: req.method,
          errors
        }, 'Request validation failed');

        // Return detailed validation error
        return sendValidationError(res, 'Request validation failed', errors);
      }

      // Unknown error - pass to error handler
      logger.error({ error }, 'Unknown validation error');
      next(error);
    }
  };
}

/**
 * Creates middleware that validates query parameters.
 *
 * @param schema Zod schema for query params.
 * @returns Express middleware function.
 */
export function validateQuery(schema: ZodSchema): (req: Request, res: Response, next: NextFunction) => void {
  return (req: Request, res: Response, next: NextFunction) => {
    try {
      const validated = schema.parse(req.query);
      // Store in typed augmented property since req.query is read-only
      req.validatedQuery = validated;
      next();
    } catch (error) {
      if (error instanceof ZodError) {
        const errors = formatZodErrors(error);

        logger.warn({
          path: req.path,
          method: req.method,
          errors
        }, 'Query validation failed');

        return sendValidationError(res, 'Query parameter validation failed', errors);
      }

      next(error);
    }
  };
}

/**
 * Creates middleware that validates route params.
 *
 * @param schema Zod schema for route params.
 * @returns Express middleware function.
 */
export function validateParams(schema: ZodSchema): (req: Request, res: Response, next: NextFunction) => void {
  return (req: Request, res: Response, next: NextFunction) => {
    try {
      const validated = schema.parse(req.params);
      req.params = validated;
      next();
    } catch (error) {
      if (error instanceof ZodError) {
        const errors = formatZodErrors(error);

        logger.warn({
          path: req.path,
          method: req.method,
          errors
        }, 'Path parameter validation failed');

        return sendValidationError(res, 'Path parameter validation failed', errors);
      }

      next(error);
    }
  };
}

