// file: api/utils/api-error.ts
/**
 * API Error Response Utilities
 *
 * Provides standardized error response format across all API routes.
 * Format: { success: false, error: { code, message }, timestamp }
 */

import type { Response } from 'express';
import { createComponentLogger } from '#sidequest/utils/logger.ts';
import { HttpStatus, type HttpStatusCode } from '../../shared/constants/http-status.ts';

const logger = createComponentLogger('ApiError');

/**
 * Standard error codes
 */
export const ERROR_CODES = {
  // Client errors (4xx)
  BAD_REQUEST: 'BAD_REQUEST',
  UNAUTHORIZED: 'UNAUTHORIZED',
  FORBIDDEN: 'FORBIDDEN',
  NOT_FOUND: 'NOT_FOUND',
  CONFLICT: 'CONFLICT',
  INVALID_REQUEST: 'INVALID_REQUEST',
  INVALID_STATUS: 'INVALID_STATUS',
  INVALID_JOB_DATA: 'INVALID_JOB_DATA',

  // Server errors (5xx)
  INTERNAL_ERROR: 'INTERNAL_ERROR',
  SERVICE_UNAVAILABLE: 'SERVICE_UNAVAILABLE',

  // Rate limiting
  QUEUE_FULL: 'QUEUE_FULL',

  // Worker/Pipeline errors
  WORKER_NOT_FOUND: 'WORKER_NOT_FOUND',
  CANCEL_FAILED: 'CANCEL_FAILED',
  MIGRATION_NOT_CONFIGURED: 'MIGRATION_NOT_CONFIGURED'
} as const;

/**
 * API Error class with standardized JSON serialization
 */
export class ApiError extends Error {
  code: string;
  status: HttpStatusCode;
  details: object | null;

  /**
   * constructor.
   */
  constructor(code: string, message: string, status: HttpStatusCode = HttpStatus.BAD_REQUEST, details: object | null = null) {
    super(message);
    this.code = code;
    this.status = status;
    this.details = details;
    this.name = 'ApiError';
  }

  /**
   * toJSON.
   */
  toJSON() {
    const response: { success: false; error: { code: string; message: string; details?: object }; timestamp: string } = {
      success: false,
      error: {
        code: this.code,
        message: this.message
      },
      timestamp: new Date().toISOString()
    };

    if (this.details) {
      response.error.details = this.details;
    }

    return response;
  }
}

/**
 * Send standardized error response
 */
export function sendError(
  res: Response,
  code: string,
  message: string,
  status: HttpStatusCode = HttpStatus.BAD_REQUEST,
  details: object | null = null
) {
  const response: { success: false; error: { code: string; message: string; details?: object }; timestamp: string } = {
    success: false,
    error: {
      code,
      message
    },
    timestamp: new Date().toISOString()
  };

  if (details) {
    response.error.details = details;
  }

  logger.debug({ code, message, status, details }, 'Sending error response');

  return res.status(status).json(response);
}

/**
 * Send validation error response
 */
export function sendValidationError(res: Response, message: string, errors: unknown[] = []) {
  return sendError(res, ERROR_CODES.INVALID_REQUEST, message, HttpStatus.BAD_REQUEST, { errors });
}

/**
 * Send not found error response
 */
export function sendNotFoundError(res: Response, resource: string, identifier: string) {
  return sendError(
    res,
    ERROR_CODES.NOT_FOUND,
    `${resource} '${identifier}' not found`,
    HttpStatus.NOT_FOUND
  );
}

/**
 * Send internal server error response
 */
export function sendInternalError(res: Response, message = 'An internal error occurred') {
  return sendError(res, ERROR_CODES.INTERNAL_ERROR, message, HttpStatus.INTERNAL_SERVER_ERROR);
}

// file: api/utils/job-helpers.ts
import { JOB_EVENTS, JOB_EVENT_LABELS, RESERVED_JOB_KEYS } from '#sidequest/core/constants.ts';
import type { JobStatus } from '../types/job-status.ts';

/** Map job status to JOB_EVENTS constant */
export function jobStatusToEventType(status: JobStatus): string {
  if (status === 'completed') return JOB_EVENTS.COMPLETED;
  if (status === 'failed') return JOB_EVENTS.FAILED;
  if (status === 'running') return JOB_EVENTS.STARTED;
  return JOB_EVENTS.CREATED;
}

/** Map job status to human-readable label */
export function jobStatusToLabel(status: JobStatus): string {
  if (status === 'completed') return JOB_EVENT_LABELS.COMPLETED;
  if (status === 'failed') return JOB_EVENT_LABELS.FAILED;
  if (status === 'running') return JOB_EVENT_LABELS.STARTED;
  return JOB_EVENT_LABELS.CREATED;
}

/**
 * Returns a copy of jobData with all reserved system keys removed.
 * Prevents stale or injected control fields from carrying over on retry.
 */
export function filterReservedJobKeys(jobData: Record<string, unknown>): Record<string, unknown> {
  const result: Record<string, unknown> = {};
  for (const [key, value] of Object.entries(jobData)) {
    if (!RESERVED_JOB_KEYS.has(key)) {
      result[key] = value;
    }
  }
  return result;
}

// file: api/utils/crypto-helpers.ts
import crypto from 'crypto';

/**
 * Constant-time string comparison that does not leak length information.
 * Both values are HMAC'd to normalize length before comparison.
 */
export function timingSafeEqual(a: unknown, b: unknown): boolean {
  if (typeof a !== 'string' || typeof b !== 'string') return false;
  const key = crypto.randomBytes(32);
  const hmacA = crypto.createHmac('sha256', key).update(a).digest();
  const hmacB = crypto.createHmac('sha256', key).update(b).digest();
  return crypto.timingSafeEqual(hmacA, hmacB);
}

