/**
 * Port Manager Utility
 *
 * Provides port availability checking, dynamic port allocation, and graceful shutdown handling.
 * Prevents EADDRINUSE errors by detecting occupied ports and trying fallback ports.
 */

import type { Server as HttpServer } from 'http';
import net from 'net';
import { createComponentLogger } from '#sidequest/utils/logger.ts';
import { PORT } from '#sidequest/core/constants.ts';

const logger = createComponentLogger('PortManager');

interface PortFallbackOptions {
  preferredPort: number;
  maxPort?: number;
  host?: string;
  killExisting?: boolean;
}

interface GracefulShutdownOptions {
  onShutdown?: (signal: string) => void | Promise<void>;
  timeout?: number;
}

/**
 * Check if a port is available for binding
 */
/**
 * Check if port available.
 *
 * @param {number} port - The port number
 * @param {string} [host='0.0.0.0'] - The host address
 *
 * @returns {Promise<boolean>} True if port available, False otherwise
 * @async
 */
export async function isPortAvailable(port: number, host: string = '0.0.0.0'): Promise<boolean> {
  return new Promise((resolve) => {
    const server = net.createServer();

    // Enable SO_REUSEADDR to allow quick restarts
    server.on('error', (err: NodeJS.ErrnoException) => {
      if (err.code === 'EADDRINUSE') {
        logger.debug({ port, host }, 'Port is already in use');
        resolve(false);
      } else {
        logger.warn({ port, host, error: err.message }, 'Error checking port availability');
        resolve(false);
      }
    });

    server.on('listening', () => {
      server.close(() => {
        logger.debug({ port, host }, 'Port is available');
        resolve(true);
      });
    });

    server.listen(port, host);
  });
}

/**
 * Find an available port within a range
 */
/**
 * Find the available port.
 *
 * @param {number} startPort - The startPort
 * @param {number} endPort - The endPort
 * @param {string} [host='0.0.0.0'] - The host address
 *
 * @returns {Promise<number | null>} The available port
 * @async
 */
export async function findAvailablePort(startPort: number, endPort: number, host: string = '0.0.0.0'): Promise<number | null> {
  logger.info({ startPort, endPort, host }, 'Searching for available port');

  for (let port = startPort; port <= endPort; port++) {
    const available = await isPortAvailable(port, host);
    if (available) {
      logger.info({ port, host }, 'Found available port');
      return port;
    }
  }

  logger.error({ startPort, endPort, host }, 'No available ports found in range');
  return null;
}

/**
 * Kill processes using a specific port (macOS/Linux)
 */
/**
 * Kill process on port.
 *
 * @param {number} port - The port number
 *
 * @returns {Promise<boolean>} True if successful, False otherwise
 * @async
 */
export async function killProcessOnPort(port: number): Promise<boolean> {
  try {
    const { execFile } = await import('child_process');
    const { promisify } = await import('util');
    const execFileAsync = promisify(execFile);

    // Find process using the port
    const { stdout } = await execFileAsync('lsof', ['-ti', `:${port}`]);
    const pids = stdout.trim().split('\n').filter(Boolean);

    if (pids.length === 0) {
      logger.info({ port }, 'No processes found on port');
      return true;
    }

    // Validate each pid is a numeric string before passing to kill
    const numericPids = pids.filter(pid => /^\d+$/.test(pid.trim()));
    if (numericPids.length !== pids.length) {
      logger.error({ port, pids }, 'Unexpected non-numeric PID from lsof output');
      return false;
    }

    logger.info({ port, pids: numericPids }, 'Killing processes on port');

    // Kill all processes using execFile to avoid shell injection
    for (const pid of numericPids) {
      await execFileAsync('kill', ['-9', pid.trim()]);
      logger.info({ port, pid }, 'Killed process');
    }

    // Wait for port to be released
    await new Promise(resolve => setTimeout(resolve, PORT.RELEASE_DELAY_MS));

    return true;
  } catch (error) {
    logger.error({ port, error: (error as Error).message }, 'Failed to kill process on port');
    return false;
  }
}

/**
 * Setup graceful shutdown handlers for a server
 */
/**
 * Set up graceful shutdown.
 *
 * @param {HttpServer} httpServer - The httpServer
 * @param {GracefulShutdownOptions} [options={}] - Options dictionary
 */
export function setupGracefulShutdown(httpServer: HttpServer, options: GracefulShutdownOptions = {}): void {
  const {
    onShutdown = () => {},
    timeout = PORT.DEFAULT_SHUTDOWN_TIMEOUT_MS
  } = options;

  let isShuttingDown = false;

  /**
   * Shutdown.
   *
   * @param {string} signal - The signal
   * @async
   */
  const shutdown = async (signal: string) => {
    if (isShuttingDown) {
      logger.warn({ signal }, 'Shutdown already in progress');
      return;
    }

    isShuttingDown = true;
    logger.info({ signal }, 'Graceful shutdown initiated');

    // Set shutdown timeout
    const shutdownTimeout = setTimeout(() => {
      logger.error({ timeout }, 'Shutdown timeout exceeded, forcing exit');
      process.exit(1);
    }, timeout);

    try {
      // Run custom shutdown handler
      await onShutdown(signal);

      // Close HTTP server
      httpServer.close((err) => {
        clearTimeout(shutdownTimeout);

        if (err) {
          logger.error({ error: err.message }, 'Error during HTTP server shutdown');
          process.exit(1);
        } else {
          logger.info('HTTP server closed successfully');
          process.exit(0);
        }
      });

      // Stop accepting new connections immediately
      httpServer.closeAllConnections?.();
    } catch (error) {
      clearTimeout(shutdownTimeout);
      logger.error({ error: (error as Error).message }, 'Error during graceful shutdown');
      process.exit(1);
    }
  };

  // Register shutdown handlers
  process.on('SIGTERM', () => shutdown('SIGTERM'));
  process.on('SIGINT', () => shutdown('SIGINT'));
  process.on('SIGHUP', () => shutdown('SIGHUP'));

  // Handle uncaught errors
  process.on('uncaughtException', (error) => {
    logger.error({ error: error.message, stack: error.stack }, 'Uncaught exception');
    shutdown('uncaughtException');
  });

  process.on('unhandledRejection', (reason, promise) => {
    logger.error({ reason, promise }, 'Unhandled promise rejection');
    shutdown('unhandledRejection');
  });

  logger.info('Graceful shutdown handlers registered');
}

/**
 * Setup server with automatic port fallback
 */
/**
 * Set up server with port fallback.
 *
 * @param {HttpServer} httpServer - The httpServer
 * @param {PortFallbackOptions} options - Options dictionary
 *
 * @returns {Promise<number>} The Promise<number>
 * @async
 */
export async function setupServerWithPortFallback(httpServer: HttpServer, options: PortFallbackOptions): Promise<number> {
  const {
    preferredPort,
    maxPort = preferredPort + PORT.FALLBACK_RANGE,
    host = '0.0.0.0',
    killExisting = false
  } = options;

  if (!preferredPort) {
    throw new Error('preferredPort is required');
  }

  logger.info({ preferredPort, maxPort, host, killExisting }, 'Setting up server with port fallback');

  // Check if preferred port is available
  const preferredAvailable = await isPortAvailable(preferredPort, host);

  if (preferredAvailable) {
    return new Promise((resolve, reject) => {
      httpServer.listen(preferredPort, host, () => {
        logger.info({ port: preferredPort, host }, 'Server listening on preferred port');
        resolve(preferredPort);
      });

      httpServer.on('error', reject);
    });
  }

  // Preferred port not available
  logger.warn({ port: preferredPort }, 'Preferred port is not available');

  if (killExisting) {
    logger.info({ port: preferredPort }, 'Attempting to kill existing process');
    const killed = await killProcessOnPort(preferredPort);

    if (killed) {
      const nowAvailable = await isPortAvailable(preferredPort, host);
      if (nowAvailable) {
        return new Promise((resolve, reject) => {
          httpServer.listen(preferredPort, host, () => {
            logger.info({ port: preferredPort, host }, 'Server listening on preferred port after cleanup');
            resolve(preferredPort);
          });

          httpServer.on('error', reject);
        });
      }
    }
  }

  // Find fallback port
  const fallbackPort = await findAvailablePort(preferredPort + 1, maxPort, host);

  if (!fallbackPort) {
    throw new Error(`No available ports found between ${preferredPort} and ${maxPort}`);
  }

  logger.warn({ preferredPort, fallbackPort }, 'Using fallback port');

  return new Promise((resolve, reject) => {
    httpServer.listen(fallbackPort, host, () => {
      logger.info({ port: fallbackPort, host }, 'Server listening on fallback port');
      resolve(fallbackPort);
    });

    httpServer.on('error', reject);
  });
}

// file: api/routes/pipelines.ts
/**
 * Pipeline Routes (TypeScript with Zod validation)
 *
 * API endpoints for fetching pipeline details and job history.
 * All endpoints include type validation and Sentry error tracking.
 *
 * @module api/routes/pipelines
 */

import express, { type Request, type Response, type NextFunction } from 'express';
import { validateQuery, validateRequest } from '../middleware/validation.ts';
import {
  JobQueryParamsSchema,
  ManualTriggerRequestSchema,
  type JobQueryParams,
  type JobsListResponse,
  type JobDetails,
  type ManualTriggerRequest,
  type ManualTriggerResponse
} from '../types/pipeline-requests.ts';
import { createComponentLogger } from '#sidequest/utils/logger.ts';
import * as Sentry from '@sentry/node';
import { jobRepository } from '#sidequest/core/job-repository.ts';
import { workerRegistry } from '../utils/worker-registry.ts';
import { HttpStatus } from '../../shared/constants/http-status.ts';
import { LIMITS, PAGINATION } from '#sidequest/core/constants.ts';
import { sendError, ERROR_CODES } from '../utils/api-error.ts';

const RESERVED_PARAM_KEYS = new Set(['triggeredBy', 'triggeredAt', 'retriedFrom', 'retryCount']);

const router = express.Router();
const logger = createComponentLogger('PipelineRoutes');

/**
 * GET /api/sidequest/pipeline-runners/:pipelineId/jobs
 * Fetch job history for a specific pipeline
 *
 * Query Parameters:
 * - status (optional): Filter by job status (queued, running, completed, failed)
 * - limit (optional): Max jobs to return (default: 10, max: 100)
 * - offset (optional): Pagination offset (default: 0)
 * - tab (optional): UI tab context (recent, failed, all)
 *
 * Response: JobsListResponse with jobs array
 */
router.get(
  '/:pipelineId/jobs',
  validateQuery(JobQueryParamsSchema), // Automatic Zod validation
  async (
    req: Request<{ pipelineId: string }>,
    res: Response<JobsListResponse>,
    next: NextFunction
  ) => {
    const { pipelineId } = req.params;
    // Use validatedQuery from validation middleware (typed via Express module augmentation)
    const { status, limit, offset, tab } = req.validatedQuery as JobQueryParams;

    try {
      logger.info({
        pipelineId,
        status,
        limit,
        offset,
        tab
      }, 'Fetching pipeline jobs');

      // Fetch jobs from data source (now returns {jobs, total})
      const result = await fetchJobsForPipeline(pipelineId, {
        status,
        limit,
        offset,
        tab
      });

      const response: JobsListResponse = {
        pipelineId,
        jobs: result.jobs,
        total: result.total,
        hasMore: (offset + result.jobs.length) < result.total,
        timestamp: new Date().toISOString()
      };

      logger.info({
        pipelineId,
        jobCount: result.jobs.length,
        totalCount: result.total,
        hasMore: response.hasMore
      }, 'Successfully fetched pipeline jobs');

      res.json(response);
    } catch (error) {
      logger.error({
        error,
        pipelineId,
        queryParams: { status, limit, offset, tab }
      }, 'Failed to fetch pipeline jobs');

      Sentry.captureException(error, {
        tags: {
          component: 'PipelineAPI',
          endpoint: '/api/sidequest/pipeline-runners/:id/jobs',
          pipelineId
        },
        extra: {
          queryParams: { status, limit, offset, tab }
        }
      });

      next(error);
    }
  }
);

/**
 * POST /api/sidequest/pipeline-runners/:pipelineId/trigger
 * Manually trigger a pipeline job
 *
 * Request Body:
 * - parameters (optional): Job-specific parameters
 *
 * Response: ManualTriggerResponse with new job ID
 */
router.post(
  '/:pipelineId/trigger',
  validateRequest(ManualTriggerRequestSchema), // Automatic Zod validation
  async (
    req: Request<{ pipelineId: string }, {}, ManualTriggerRequest>,
    res: Response<ManualTriggerResponse>,
    next: NextFunction
  ) => {
    const { pipelineId } = req.params;
    const { parameters = {} } = req.body;

    try {
      logger.info({
        pipelineId,
        parameters
      }, 'Manually triggering pipeline job');

      // Guard: reject trigger when queue is already deep to prevent accumulation
      const counts = jobRepository.getJobCounts(pipelineId);
      if (counts && counts.queued >= LIMITS.MAX_QUEUED_JOBS_PER_PIPELINE) {
        sendError(
          res,
          ERROR_CODES.QUEUE_FULL,
          `Pipeline ${pipelineId} has ${counts.queued} queued jobs. ` +
          `Wait for the queue to drain below ${LIMITS.MAX_QUEUED_JOBS_PER_PIPELINE} before triggering new jobs.`,
          HttpStatus.TOO_MANY_REQUESTS
        );
        return;
      }

      // Trigger the job
      const jobId = await triggerPipelineJob(pipelineId, parameters);

      const response: ManualTriggerResponse = {
        jobId,
        pipelineId,
        status: 'queued',
        timestamp: new Date().toISOString()
      };

      logger.info({
        pipelineId,
        jobId
      }, 'Successfully triggered pipeline job');

      res.status(HttpStatus.CREATED).json(response);
    } catch (error) {
      logger.error({
        error,
        pipelineId,
        parameters
      }, 'Failed to trigger pipeline job');

      Sentry.captureException(error, {
        tags: {
          component: 'PipelineAPI',
          endpoint: '/api/sidequest/pipeline-runners/:id/trigger',
          pipelineId
        },
        extra: {
          parameters
        }
      });

      next(error);
    }
  }
);

/**
 * Helper: Fetch jobs for a pipeline with total count
 *
 * @param pipelineId - Pipeline identifier
 * @param options - Query options (status, limit, offset, tab)
 * @returns Object with jobs array and total count
 */
async function fetchJobsForPipeline(
  pipelineId: string,
  options: JobQueryParams
): Promise<{ jobs: JobDetails[]; total: number }> {
  const { status, limit, offset, tab } = options;

  // Query SQLite database with total count (FIXED: Now includes actual DB count)
  const dbResult = jobRepository.getJobs(pipelineId, {
    status,
    limit: limit ?? PAGINATION.DEFAULT_QUERY_LIMIT,
    offset: offset ?? 0,
    tab,
    includeTotal: true // Request total count from database
  });

  // Extract jobs and total from database result
  const dbResult2 = dbResult as Record<string, unknown>;
  const dbJobs = (dbResult2.jobs as Record<string, unknown>[]) || [];
  const totalCount = (dbResult2.total as number) || 0;

  // Map database schema to API response schema
  // Include all fields needed by the dashboard modal
  const jobs: JobDetails[] = dbJobs.map((dbJob: Record<string, unknown>) => {
    const job: JobDetails = {
      id: dbJob.id as string,
      pipelineId: dbJob.pipelineId as string,
      status: dbJob.status as JobDetails['status'],
      startTime: (dbJob.startedAt ?? dbJob.createdAt) as string,
      createdAt: dbJob.createdAt as string | undefined, // Needed for timeline display
    };

    // Add optional fields only if they exist
    if (dbJob.data) {
      job.parameters = dbJob.data as Record<string, unknown>;
    }

    // Add endTime and duration if job is completed
    if (dbJob.completedAt) {
      job.endTime = dbJob.completedAt as string;

      // Calculate duration in milliseconds
      const start = new Date((dbJob.startedAt ?? dbJob.createdAt) as string).getTime();
      const end = new Date(dbJob.completedAt as string).getTime();
      job.duration = end - start;
    }

    // Add result data
    if (dbJob.result) {
      job.result = { ...(dbJob.result as Record<string, unknown>) };
    }

    // Add error at top level (modal checks job.error, not job.result.error)
    if (dbJob.error) {
      job.error = dbJob.error as JobDetails['error'];
    }

    // Add git info if available (needed for git workflow display in modal)
    if (dbJob.git) {
      job.git = dbJob.git as JobDetails['git'];
    }

    return job;
  });

  logger.debug({
    pipelineId,
    returned: jobs.length,
    total: totalCount,
    status,
    tab
  }, 'Job query results from database');

  return { jobs, total: totalCount };
}

/**
 * Helper: Trigger a manual job for a pipeline
 *
 * @param pipelineId - Pipeline identifier
 * @param parameters - Job parameters
 * @returns New job ID
 * @throws {Error} If pipeline is unknown or worker creation fails
 */
async function triggerPipelineJob(
  pipelineId: string,
  parameters: Record<string, unknown>
): Promise<string> {
  // Validate pipeline is supported
  if (!workerRegistry.isSupported(pipelineId)) {
    throw new Error(
      `Unknown pipeline: ${pipelineId}. ` +
      `Supported pipelines: ${workerRegistry.getSupportedPipelines().join(', ')}`
    );
  }

  logger.info({
    pipelineId,
    parameters
  }, 'Triggering pipeline job');

  // Get or create worker instance
  const worker = await workerRegistry.getWorker(pipelineId);

  // Generate job ID with pipeline prefix
  const timestamp = Date.now();
  const jobId = `${pipelineId}-manual-${timestamp}`;

  // Strip system-controlled fields from parameters before spreading
  const safeParameters: Record<string, unknown> = {};
  for (const [key, value] of Object.entries(parameters)) {
    if (!RESERVED_PARAM_KEYS.has(key)) {
      safeParameters[key] = value;
    }
  }

  // Create job with worker
  const job = worker.createJob(jobId, {
    ...safeParameters,
    triggeredBy: 'api',
    triggeredAt: new Date().toISOString()
  });

  logger.info({
    pipelineId,
    jobId,
    status: job.status
  }, 'Pipeline job created successfully');

  return job.id;
}

export default router;

