/**
 * Jobs API Routes
 * Provides access to job queue across all pipelines
 */

import express from 'express';
import { createComponentLogger, logError, logStart } from '#sidequest/utils/logger.ts';
import { timingSafeEqual } from '../utils/crypto-helpers.ts';
import { filterReservedJobKeys } from '../utils/job-helpers.ts';
import { jobRepository } from '#sidequest/core/job-repository.ts';
import { workerRegistry } from '../utils/worker-registry.ts';
import { config } from '#sidequest/core/config.ts';
import { getPipelineName } from '#sidequest/utils/pipeline-names.ts';
import { isValidJobStatus, JOB_STATUS } from '../types/job-status.ts';
import { PAGINATION, VALIDATION, RETRY } from '#sidequest/core/constants.ts';
import { sendError, sendNotFoundError, sendInternalError, ERROR_CODES } from '../utils/api-error.ts';
import { bulkImportRateLimiter } from '../middleware/rate-limit.ts';
import { HttpStatus } from '../../shared/constants/http-status.ts';

const router = express.Router();
const logger = createComponentLogger('JobsAPI');

/**
 * Validate job id.
 *
 * @param {string} jobId - The jobId
 *
 * @returns {{ valid: boolean; sanitized?: string; error?: string }} True if successful, False otherwise
 */
function validateJobId(jobId: string): { valid: boolean; sanitized?: string; error?: string } {
  if (!jobId) {
    return { valid: false, error: 'Job ID is required' };
  }

  if (!VALIDATION.JOB_ID_PATTERN.test(jobId)) {
    return {
      valid: false,
      error: 'Invalid job ID format. Must be alphanumeric with hyphens/underscores (max 100 chars)'
    };
  }

  return { valid: true, sanitized: jobId };
}

/**
 * Sanitize pagination params.
 *
 * @param {string | number} limit - The limit
 * @param {string | number} offset - The offset
 *
 * @returns {{ limit: number; offset: number }} The { limit: number; offset: number }
 */
function sanitizePaginationParams(limit: string | number, offset: string | number): { limit: number; offset: number } {
  // Convert to string to ensure parseInt works correctly
  const limitStr = String(limit);
  const offsetStr = String(offset);

  // Parse and use default if NaN (use ?? to handle 0 correctly)
  const parsedLimit = parseInt(limitStr);
  const parsedOffset = parseInt(offsetStr);

  // Sanitize limit: enforce bounds [1, MAX_LIMIT], default to DEFAULT_LIMIT if NaN
  const limitNum = Math.min(
    Math.max(1, Number.isNaN(parsedLimit) ? PAGINATION.DEFAULT_LIMIT : parsedLimit),
    PAGINATION.MAX_LIMIT
  );

  // Sanitize offset: ensure non-negative, default to 0 if NaN
  const offsetNum = Math.max(0, Number.isNaN(parsedOffset) ? 0 : parsedOffset);

  return { limit: limitNum, offset: offsetNum };
}

/**
 * GET /api/jobs
 * Get all jobs with optional status filtering
 *
 * Query params:
 * - status: Filter by job status (running, queued, completed, failed)
 * - limit: Number of jobs to return (default: 50)
 * - offset: Pagination offset (default: 0)
 */
router.get('/', (req, res) => {
  try {
    const { status, limit = PAGINATION.DEFAULT_LIMIT, offset = 0 } = req.query;

    // Validate status if provided (use explicit null check, not truthy check)
    if (status !== undefined && status !== null && !isValidJobStatus(status as string)) {
      return sendError(res, ERROR_CODES.INVALID_STATUS,
        `Invalid status '${status}'. Must be one of: ${Object.values(JOB_STATUS).join(', ')}`, HttpStatus.BAD_REQUEST);
    }

    // Sanitize pagination parameters to prevent memory issues and NaN propagation
    const { limit: limitNum, offset: offsetNum } = sanitizePaginationParams(limit as string | number, offset as string | number);

    // Get jobs from database with filtering and pagination
    const allJobs = jobRepository.getAllJobs({ status: (status as string) || undefined, limit: limitNum, offset: offsetNum });

    // Format response - getAllJobs now returns parsed camelCase objects
    const jobs = allJobs.map(job => ({
      '@type': 'https://schema.org/Action',
      id: job.id,
      pipelineId: job.pipelineId,
      pipelineName: getPipelineName(job.pipelineId),
      status: job.status,
      createdAt: job.createdAt,
      startedAt: job.startedAt,
      completedAt: job.completedAt,
      error: job.error,
      result: job.result,
      data: job.data
    }));

    // Get total count for pagination (efficient COUNT query)
    const total = jobRepository.getJobCount({ status: (status as string) || undefined });
    const page = limitNum > 0 ? Math.floor(offsetNum / limitNum) : 0;
    const hasMore = (offsetNum + limitNum) < total;

    res.json({
      success: true,
      data: {
        jobs,
        total,
        page,
        limit: limitNum,
        hasMore
      },
      timestamp: new Date().toISOString()
    });

  } catch (error) {
    logError(logger, error, 'Failed to get jobs');
    return sendInternalError(res, 'Failed to retrieve jobs');
  }
});

/**
 * POST /api/jobs/bulk-import
 * Bulk import jobs (for database migration)
 * NOTE: This route MUST be defined before /:jobId routes to avoid matching 'bulk-import' as a jobId
 * Requires MIGRATION_API_KEY environment variable for authentication
 *
 * Request body:
 * {
 *   'jobs': [{ id, pipeline_id, status, created_at, ... }],
 *   'apiKey': 'migration-key-from-env'
 * }
 */
router.post('/bulk-import', bulkImportRateLimiter, (req, res) => {
  try {
    const { jobs, apiKey } = req.body;

    // Validate API key for migration operations
    // Note: config.migrationApiKey is loaded via Doppler - never use process.env directly
    const migrationKey = config.migrationApiKey;
    if (!migrationKey) {
      return sendError(res, ERROR_CODES.MIGRATION_NOT_CONFIGURED,
        'Migration API not configured. Set MIGRATION_API_KEY environment variable.', HttpStatus.SERVICE_UNAVAILABLE);
    }

    if (!timingSafeEqual(apiKey, migrationKey)) {
      logger.warn('Bulk import attempted with invalid API key');
      return sendError(res, ERROR_CODES.UNAUTHORIZED, 'Invalid migration API key', HttpStatus.UNAUTHORIZED);
    }

    // Validate jobs array
    if (!Array.isArray(jobs) || jobs.length === 0) {
      return sendError(res, ERROR_CODES.INVALID_REQUEST,
        'Request body must contain a non-empty 'jobs' array', HttpStatus.BAD_REQUEST);
    }

    // Validate required fields
    const requiredFields = ['id', 'status'];
    for (const job of jobs) {
      for (const field of requiredFields) {
        if (!job[field]) {
          return sendError(res, ERROR_CODES.INVALID_JOB_DATA,
            `Job missing required field: ${field}`, HttpStatus.BAD_REQUEST);
        }
      }
    }

    logStart(logger, 'bulk import', { jobCount: jobs.length });

    // Perform bulk import
    const result = jobRepository.bulkImport(jobs);

    logger.info({
      imported: result.imported,
      skipped: result.skipped,
      errors: result.errors.length
    }, 'Bulk import completed');

    res.json({
      success: true,
      data: {
        imported: result.imported,
        skipped: result.skipped,
        errors: result.errors
      },
      timestamp: new Date().toISOString()
    });

  } catch (error) {
    logError(logger, error, 'Bulk import failed');
    return sendError(res, ERROR_CODES.INTERNAL_ERROR, 'Bulk import failed', HttpStatus.INTERNAL_SERVER_ERROR, { details: (error as Error).message });
  }
});

