    this.readyState = 1; // OPEN
    this.OPEN = 1;
    this.sentMessages = [];
  }

  /**
   * send.
   */
  send(data) {
    this.sentMessages.push(data);
  }

  /**
   * close.
   */
  close() {
    this.readyState = 3; // CLOSED
    this.emit('close');
  }

  /**
   * ping.
   */
  ping() {
    // Mock ping
  }
}

// Mock HTTP Server
