  after(async () => {
    if (worker) {
      worker.stop();
      for (const [jobId, job] of worker.jobs) {
        if (job.status === 'running' || job.status === 'queued') {
          worker.cancelJob(jobId);
        }
      }
    }
    if (closeDatabase) closeDatabase();
