describe('Pipeline Execution - Integration Tests', () => {
  const pipelineRunners = [
    'sidequest/pipeline-runners/duplicate-detection-pipeline.ts',
    'sidequest/pipeline-runners/git-activity-pipeline.ts',
    'sidequest/pipeline-runners/gitignore-pipeline.ts',
    'sidequest/pipeline-runners/plugin-management-pipeline.ts',
    'sidequest/pipeline-runners/claude-health-pipeline.ts'
  ];

  it('Scenario 1: Verify all pipeline runners have correct shebangs', async () => {
    for (const pipeline of pipelineRunners) {
      const pipelinePath = path.join(projectRoot, pipeline);

      // Read first line of file
      const content = await fs.readFile(pipelinePath, 'utf-8');
      const firstLine = content.split('\n')[0];

      const isTs = pipeline.endsWith('.ts');
      const validShebangs = isTs
        ? ['#!/usr/bin/env -S npx tsx', '#!/usr/bin/env -S node --strip-types']
        : ['#!/usr/bin/env node'];

      assert(
        validShebangs.includes(firstLine),
        `${pipeline} should have correct shebang, got: ${firstLine}`
      );
    }
  });

  it('Scenario 2: Verify managed pipeline runners are not executable', async () => {
    for (const pipeline of pipelineRunners) {
      const pipelinePath = path.join(projectRoot, pipeline);

      // Check file permissions
      const stats = await fs.stat(pipelinePath);
      const mode = stats.mode;

      // Check if owner has execute permission (0o100)
      const hasExecute = (mode & 0o100) !== 0;

      assert.equal(
        hasExecute,
        false,
        `${pipeline} should NOT have execute permissions (current: ${mode.toString(8)})`
      );
    }
  });

  it('Scenario 4: Execute pipeline with shebang (direct execution)', async () => {
    const pipelinePath = path.join(projectRoot, pipelineRunners[0]);

    // Verify file is executable
    const stats = await fs.stat(pipelinePath);
    const hasExecute = (stats.mode & 0o100) !== 0;

    try {
      if (!hasExecute) {
        // Temporarily make executable for direct shebang execution test
        await fs.chmod(pipelinePath, 0o755);
      }

      // Execute directly (shebang should work)
      const { stdout: _stdout, stderr } = await execAsync(
        `'${pipelinePath}' --version || true`,
        {
          cwd: projectRoot,
          timeout: TestTiming.DEFAULT_WAIT_TIMEOUT_MS,
          env: {
            ...process.env,
            RUN_ON_STARTUP: 'false'
          }
        }
      ).catch(err => {
        // Pipeline may not support --version, that's okay
        // We just want to verify shebang execution works
        return { stdout: '', stderr: err.message };
      });

      // Should not have shebang-related errors
      assert(
        !stderr.includes('bad interpreter'),
        'Shebang should be correct'
      );
      assert(
        !stderr.includes('command not found'),
        'Node should be in PATH'
      );
    } finally {
      if (!hasExecute) {
