                </div>
              )}

              {/* Empty State */}
              {activeJobs.length === 0 && queuedJobs.length === 0 && (
                <div className='empty-state'>
                  <span className='empty-icon' aria-hidden='true'>✓</span>
                  <p className='empty-message'>No active or queued jobs</p>
