              )}
            </div>
          </section>

          {/* Right Column: Activity Feed */}
          <section className='dashboard-section activity-section' aria-labelledby='activity-heading'>
            <ActivityFeed
              activities={activities}
              onClear={onActivityClear}
              onItemClick={onActivityItemClick}
            />
          </section>
        </div>
      </main>
    </div>
  );
};

